// Auto-detect when bot is added to or removed from groups
bot?.on('my_chat_member', async update => {
  try {
    const chat = update.chat
    const newStatus = update.new_chat_member?.status
    const chatType = chat?.type

    if (chatType !== 'group' && chatType !== 'supergroup') return

    if (newStatus === 'member' || newStatus === 'administrator') {
      // Bot was added to a group — register it
      if (notifyGroupsCol?.updateOne) {
        // ✅ Force String(_id) — MUST match the `on('message')` group handler at line ~3240
        // to prevent duplicates caused by MongoDB treating Number(-100...) !== "-100...".
        const groupId = String(chat.id)
        await notifyGroupsCol.updateOne(
          { _id: groupId },
          { $set: { _id: groupId, title: chat.title, addedAt: new Date().toISOString(), source: 'my_chat_member' } },
          { upsert: true }
        )
        log('Registered group for notifications: ' + chat.title + ' (' + groupId + ')')
        bot?.sendMessage(chat.id, `${CHAT_BOT_NAME} is now active in this group! You will receive live event notifications here.`)?.catch(() => {})
      }
    } else if (newStatus === 'left' || newStatus === 'kicked') {
      // Bot was removed from a group — unregister it (delete BOTH string + numeric forms
      // for legacy data safety).
      if (notifyGroupsCol?.deleteOne) {
        const groupId = String(chat.id)
        await notifyGroupsCol.deleteMany({ _id: { $in: [groupId, chat.id, Number(chat.id)] } })
        log('Unregistered group from notifications: ' + chat.title + ' (' + groupId + ')')
      }
    }
  } catch (e) {
    log('my_chat_member handler error: ' + e.message)
  }
})

// Unified coupon validator — checks static codes + daily auto-generated codes + win-back codes
async function resolveCoupon(code, chatId) {
  // Normalize: always uppercase for consistent matching
  const upperCode = (code || '').toUpperCase().trim()
  if (!upperCode) return null

  // 1. Check static coupons first
  const staticDiscount = discountOn[upperCode]
  if (!isNaN(staticDiscount)) return { discount: staticDiscount, type: 'static' }

  // 2. Check daily auto-generated coupons
  if (dailyCouponSystem) {
    const result = await dailyCouponSystem.validateDailyCoupon(upperCode, chatId)
    if (result?.error === 'already_used') return { error: 'already_used' }
    if (result?.discount) return { discount: result.discount, type: 'daily', code: upperCode }
  }

  // 3. Check win-back / monetization codes
  const moCode = await monetization.validateMonetizationCode(upperCode, chatId)
  if (moCode?.error) return { error: moCode.error }
  if (moCode?.discount) return { discount: moCode.discount, type: moCode.type || 'winback', code: upperCode }

  // 4. Check welcome offer coupons (Feature 3)
  if (userConversion) {
    const welcomeResult = await userConversion.validateWelcomeCoupon(upperCode, chatId)
    if (welcomeResult?.error === 'already_used') return { error: 'already_used' }
    if (welcomeResult?.error === 'expired') return null  // Let it show as "invalid" — expired codes shouldn't hint existence
    if (welcomeResult?.error === 'wrong_user') return null  // Don't reveal coupon belongs to another user
    if (welcomeResult?.discount) {
      return { discount: welcomeResult.discount, type: 'welcome_offer', code: welcomeResult.code }
    }
  }

  return null
}

// Returns the human-friendly label for a SIM, honoring any user-custom label
// stored in userSmsPrefs.simLabels[subId]. Falls back to carrierName/displayName.
function simLabelFor(prefs, sim) {
  if (!sim) return ''
  const subId = String(sim.subscriptionId)
  const custom = prefs?.simLabels?.[subId]
  if (custom && typeof custom === 'string' && custom.trim()) return custom.trim()
  return (sim.carrierName || sim.displayName || '').trim() || 'Unknown'
}

// Render the SIM-picker inline keyboard for a campaign created via the bot.
// Silent no-op if the user hasn't synced SIMs yet (app hasn't been opened since
// v2.7.0). Honors user prefs + custom SIM labels.
async function renderCampaignSimPicker(chatId, campaignId) {
  try {
    const _info = await state.findOne({ _id: String(chatId) })
    const lang = _info?.userLanguage || 'en'
    const prefs = await smsAppService.getUserSmsPrefs(chatId)
    const sims = Array.isArray(prefs?.sims) ? prefs.sims : []
    if (sims.length === 0) {
      // App hasn't reported SIMs yet. Hint user so they know the option exists.
      return bot?.sendMessage(chatId,
        ({
          en: `📶 <b>Tip:</b> Open the Nomadly SMS app once, then come back — you'll be able to pick which SIM (or auto-rotate across all SIMs) for each campaign.`,
          fr: `📶 <b>Astuce :</b> Ouvrez l'application Nomadly SMS une fois, puis revenez — vous pourrez choisir la SIM (ou rotation automatique entre toutes les SIM) pour chaque campagne.`,
          zh: `📶 <b>提示：</b>打开 Nomadly SMS 应用一次，然后返回 — 您将能够为每个活动选择 SIM（或在所有 SIM 之间自动轮换）。`,
          hi: `📶 <b>सुझाव:</b> Nomadly SMS ऐप एक बार खोलें, फिर वापस आएँ — आप प्रत्येक अभियान के लिए SIM चुन सकेंगे (या सभी SIMs में स्वतः-घुमाव)।`,
        }[lang]) || `📶 <b>Tip:</b> Open the Nomadly SMS app once, then come back — you'll be able to pick which SIM (or auto-rotate across all SIMs) for each campaign.`,
        { parse_mode: 'HTML' }
      )
    }
    const rows = []
    const _useDefault = ({en:'Use default',fr:'Utiliser par défaut',zh:'使用默认',hi:'डिफ़ॉल्ट उपयोग'}[lang]) || 'Use default'
    const _autoRotate = ({en:'🔁 Auto-rotate',fr:'🔁 Rotation auto',zh:'🔁 自动轮换',hi:'🔁 स्वतः-घुमाव'}[lang]) || '🔁 Auto-rotate'
    const perCampaignBtns = [
      { text: _useDefault, callback_data: `campsim:${campaignId}:default` }
    ]
    if (sims.length > 1) perCampaignBtns.push({ text: _autoRotate, callback_data: `campsim:${campaignId}:rotate` })
    sims.forEach((s, i) => perCampaignBtns.push({
      text: `SIM ${i + 1} — ${simLabelFor(prefs, s).slice(0, 14)}`,
      callback_data: `campsim:${campaignId}:${s.subscriptionId}`
    }))
    for (let i = 0; i < perCampaignBtns.length; i += 2) rows.push(perCampaignBtns.slice(i, i + 2))
    return bot?.sendMessage(chatId,
      ({
        en: `📶 <b>Which SIM should send this campaign?</b>\nDefault keeps your existing preference. Tap <b>Auto-rotate</b> to spread load across all SIMs.`,
        fr: `📶 <b>Quelle SIM doit envoyer cette campagne ?</b>\nPar défaut conserve votre préférence existante. Tapez <b>Rotation auto</b> pour répartir la charge sur toutes les SIM.`,
        zh: `📶 <b>哪张 SIM 卡应发送此活动？</b>\n默认保留您的现有偏好。点击<b>自动轮换</b>将负载分散到所有 SIM 卡。`,
        hi: `📶 <b>यह अभियान कौन सा SIM भेजे?</b>\nडिफ़ॉल्ट आपकी मौजूदा प्राथमिकता रखता है। सभी SIMs पर लोड वितरित करने के लिए <b>स्वतः-घुमाव</b> टैप करें।`,
      }[lang]) || `📶 <b>Which SIM should send this campaign?</b>\nDefault keeps your existing preference. Tap <b>Auto-rotate</b> to spread load across all SIMs.`,
      { parse_mode: 'HTML', reply_markup: { inline_keyboard: rows } }
    )
  } catch (e) {
    console.log('[renderCampaignSimPicker] error:', e.message)
  }
}

/**
 * Build a localized "unfilled placeholders" error message.
 * Used by the IVR / Bulk-call flows to BLOCK the call from being sent if the
 * script contains literal placeholder tokens like [Bank], [Name], [Amount]
 * that were never filled with actual values. Without this guard, the literal
 * brackets ended up in the call recipient's audio (we saw 2 such launches in
 * production logs on 2026-04-30).
 *
 * @param {string[]} unfilled - The placeholder names still in the text
 * @param {string} lang       - User language ('en'|'fr'|'zh'|'hi')
 * @returns {string} HTML-formatted error message
 */
function formatUnfilledPlaceholderError(unfilled, lang) {
  const list = unfilled.map(p => `<code>[${p}]</code>`).join(', ')
  const messages = {
    en: `❌ <b>Cannot place this call yet</b>\n\nYour script still contains unfilled placeholder${unfilled.length > 1 ? 's' : ''}: ${list}\n\n<i>If left as-is, the recipient would hear "left bracket ${unfilled[0]} right bracket" in the audio.</i>\n\nTap <b>✍️ Custom Script</b> to rewrite the script with the actual value${unfilled.length > 1 ? 's' : ''}, then try again.`,
    fr: `❌ <b>Impossible de passer cet appel</b>\n\nVotre script contient encore ${unfilled.length > 1 ? 'des' : 'un'} placeholder${unfilled.length > 1 ? 's' : ''} non rempli${unfilled.length > 1 ? 's' : ''} : ${list}\n\n<i>Tel quel, le destinataire entendrait littéralement "crochet ouvrant ${unfilled[0]} crochet fermant".</i>\n\nTouchez <b>✍️ Custom Script</b> pour réécrire le script avec la valeur réelle, puis réessayez.`,
    zh: `❌ <b>暂时无法发起此通话</b>\n\n您的脚本仍包含未填写的占位符：${list}\n\n<i>如果保持原样，接收方将在音频中听到字面的"左方括号 ${unfilled[0]} 右方括号"。</i>\n\n点击 <b>✍️ Custom Script</b> 用实际值重写脚本后再试。`,
    hi: `❌ <b>अभी यह कॉल नहीं की जा सकती</b>\n\nआपकी स्क्रिप्ट में अभी भी अधूरे प्लेसहोल्डर हैं: ${list}\n\n<i>ऐसे ही छोड़ने पर, प्राप्तकर्ता ऑडियो में "ब्रैकेट ${unfilled[0]} ब्रैकेट" शब्दशः सुनेगा।</i>\n\n<b>✍️ Custom Script</b> टैप करें, स्क्रिप्ट को वास्तविक मान से दोबारा लिखें, फिर पुनः प्रयास करें।`,
  }
  return messages[lang] || messages.en
}

/**
 * Build a localized "your request is being processed in the background" message
 * for existing-user mutation flows (take-offline / bring-online / unlink-addon /
 * cancel-plan) when the WHM control plane is unreachable.
 *
 * Same calm tone as the post-payment provisioning flow — user is NOT told that
 * the hosting server is down. They see an in-progress message + know they will
 * be notified when it completes (via the cpanel-job-queue worker DMing
 * "✅ <label> completed").
 */
function formatMutationQueuedMessage(label, lang) {
  const messages = {
    en: `⏳ <b>Your request is being processed</b>\n\n${label} for your hosting plan is queued and will complete in the background — usually within a few minutes. We'll notify you here as soon as it's done.\n\n<i>You don't need to do anything — keep this chat open.</i>`,
    fr: `⏳ <b>Votre demande est en cours de traitement</b>\n\n${label} pour votre plan d'hébergement est en file d'attente et sera terminé en arrière-plan — généralement en quelques minutes. Nous vous notifierons ici dès que ce sera fait.\n\n<i>Vous n'avez rien à faire — gardez ce chat ouvert.</i>`,
    zh: `⏳ <b>您的请求正在处理中</b>\n\n您主机方案的 ${label} 已加入队列，将在后台完成 — 通常几分钟内。完成后我们会立即在此通知您。\n\n<i>您无需任何操作 — 保持此聊天窗口打开即可。</i>`,
    hi: `⏳ <b>आपका अनुरोध संसाधित किया जा रहा है</b>\n\nआपके होस्टिंग प्लान के लिए ${label} कतार में है और पृष्ठभूमि में पूरा होगा — आमतौर पर कुछ मिनटों में। पूर्ण होते ही हम आपको यहीं सूचित करेंगे।\n\n<i>आपको कुछ नहीं करना — बस इस चैट को खुला रखें।</i>`,
  }
  return messages[lang] || messages.en
}

/**
 * Try-then-queue a cPanel mutation. Returns `true` if WHM is reachable so the
 * caller should proceed with the existing direct call, or `false` if the
 * action was queued instead (caller should return without further work).
 *
 * Centralises the pre-flight WHM probe + mutation enqueue + user notification
 * so each of the 4 mutation call-sites in _index.js can wrap its action in 3
 * lines instead of repeating the boilerplate.
 *
 * @param {object} args
 * @param {string|number} args.chatId  - Telegram chat
 * @param {string} args.lang           - 'en' | 'fr' | 'zh' | 'hi'
 * @param {string} args.kind           - mutation kind handled by cpanel-job-handlers
 *                                       ('suspend'|'unsuspend'|'enableMaintenance'|
 *                                        'disableMaintenance'|'unlinkAddon'|'cancelPlan'|
 *                                        'saveFile')
 * @param {string} args.label          - Human-readable description for the
 *                                       "processing" message + completion DM
 * @param {object} args.params         - Mutation-specific params (forwarded to handler)
 * @param {string} args.domain         - Primary domain (for queue introspection)
 * @param {string} [args.dedupeKey]    - Optional dedupe key; if a job with this
 *                                       key is already pending/running, no new
 *                                       job is created.
 * @param {boolean} [args.silent=false] - If true, do NOT send the "processing"
 *                                       message (used by automated flows like
 *                                       post-renewal auto-unsuspend).
 * @returns {Promise<boolean>} true → caller should proceed with direct call.
 *                              false → action queued, caller should return.
 */
async function tryWhmOrQueue(args) {
  try {
    const cpHealth = require('./cpanel-health')
    const reachable = await cpHealth.isWhmReachable()
    if (reachable) return true
  } catch (e) {
    log(`[mutation-queue] health probe error (proceed direct): ${e.message}`)
    return true
  }
  // WHM is down — enqueue + (optionally) notify user
  try {
    const cpQueue = require('./cpanel-job-queue')
    await cpQueue.enqueue({
      type: 'mutation',
      chatId: args.chatId,
      lang: args.lang,
      domain: args.domain,
      params: { kind: args.kind, label: args.label, args: args.params || {} },
      dedupeKey: args.dedupeKey || `${args.kind}:${args.domain}:${args.chatId}`,
    })
    if (!args.silent) {
      send(args.chatId, formatMutationQueuedMessage(args.label, args.lang))
    }
    log(`[mutation-queue] queued ${args.kind} for chat=${args.chatId} domain=${args.domain || '-'}`)
  } catch (e) {
    log(`[mutation-queue] enqueue failed (falling through to direct call): ${e.message}`)
    return true
  }
  return false
}

/**
 * Robust "is this message a Back-button press?" detector.
 *
 * Background: across the bot, Back buttons are sometimes rendered as plain
 * locale text (`Back` / `Retour` / `返回` / `वापस`) and sometimes with an emoji
 * prefix (`↩️ Back`, `🔙 Back`, `🔙 Retour`, `🔙 返回`, `🔙 वापस`). The IVR-OB
 * Custom-Script flow used `isBackPress(message)` which only matched the plain
 * locale text — a French user tapping the visible `↩️ Back` button would have
 * the click silently ignored, the literal string treated as their script
 * content, and would loop pressing Back trying to escape (production rage-tap
 * incident: user `fuckthisapp` hit Back 16× in 8 s).
 *
 * This helper accepts ALL plausible Back-button strings across all 4 locales,
 * so handlers don't have to enumerate variants.
 */
function isBackPress(message) {
  if (!message || typeof message !== 'string') return false
  const m = message.trim()
  // Fast path: emoji-prefixed English (most common UI button)
  if (m === '↩️ Back' || m === '🔙 Back' || m === '⬅️ Back') return true
  // Plain locale words (any language) — trim emojis if any
  const stripped = m.replace(/^[\p{Extended_Pictographic}\u200d\ufe0f\s↩🔙]+/u, '').trim()
  // Match against the 'back' translation in any of the 4 locales
  const knownBacks = new Set([
    'Back',     // en  (t.back)
    'Retour',   // fr
    '返回',     // zh
    'वापस',    // hi
  ])
  return knownBacks.has(stripped)
}

/**
 * Robust Cancel-button matcher — same approach as isBackPress.
 * Accepts plain locale words (`Cancel` / `Annuler` / `取消` / `रद्द करें`) and
 * any emoji-prefixed variant (`❌ Cancel`, `❎ Cancel`, `🚫 Cancel`, etc.).
 *
 * Used to make handlers robust to deploy-window stale-keyboard scenarios
 * where a user might have an old (pre-emoji) Cancel button on their screen
 * while we've shipped emoji-prefixed renders.
 */
function isCancelPress(message) {
  if (!message || typeof message !== 'string') return false
  const m = message.trim()
  const stripped = m.replace(/^[\p{Extended_Pictographic}\u200d\ufe0f\s❌❎🚫]+/u, '').trim()
  const knownCancels = new Set(['Cancel', 'Annuler', '取消', 'रद्द करें'])
  return knownCancels.has(stripped)
}

/**
 * Robust Yes-button matcher — accepts plain locale (`Yes` / `Oui` / `是` /
 * `हाँ`), emoji-prefixed (`✅ Yes`, `✔️ Yes`, `✅ Confirm`, etc.).
 * Also accepts "Confirm" variants since they're commonly rendered as Yes-style.
 */
function isYesPress(message) {
  if (!message || typeof message !== 'string') return false
  const m = message.trim()
  const stripped = m.replace(/^[\p{Extended_Pictographic}\u200d\ufe0f\s✅✔]+/u, '').trim()
  const knownYes = new Set(['Yes', 'Oui', '是', 'हाँ', 'Confirm', 'Confirmer', '确认', 'पुष्टि करें'])
  return knownYes.has(stripped)
}

/**
 * Robust No-button matcher — accepts plain locale (`No` / `Non` / `否` /
 * `नहीं`) and emoji-prefixed (`❌ No`, etc.).
 */
function isNoPress(message) {
  if (!message || typeof message !== 'string') return false
  const m = message.trim()
  const stripped = m.replace(/^[\p{Extended_Pictographic}\u200d\ufe0f\s❌❎🚫]+/u, '').trim()
  const knownNo = new Set(['No', 'Non', '否', 'नहीं'])
  return knownNo.has(stripped)
}

const send = (chatId, message, options) => {
  // Auto-detect HTML in message and add parse_mode if not already set
  const opts = options || {}
  if (typeof message === 'string' && !opts.parse_mode && /<\/?(?:b|i|u|s|code|pre|a)\b/.test(message)) {
    opts.parse_mode = 'HTML'
  }
  // Cross-device: auto-inject resize_keyboard for all custom keyboards
  if (opts?.reply_markup?.keyboard && !opts.reply_markup.resize_keyboard) {
    opts.reply_markup.resize_keyboard = true
  }
  log('reply: ' + message + ' ' + (opts?.reply_markup?.keyboard?.map(i => i) || '') + '\tto: ' + chatId + '\n')
  bot?.sendMessage(chatId, message, opts)?.catch(e => log(e.message + ': ' + chatId))
}

// ── Support SLA nudge ──
// If the user opens a support session and the admin does not reply within 10 min
// (admin replying flips `supportSessions[chatId]` to `adminTakeover: true` via /reply),
// ping admin again so support requests aren't forgotten. Self-cancels if:
//   • admin has since replied (adminTakeover=true)
//   • the session was closed (timestamp reset to 0)
//   • the session timestamp changed (user re-opened / re-triggered — newer nudge wins)
const _slaNudgeTimers = new Map() // chatId → timeout handle (dedup)
function scheduleSupportSlaNudge(chatId, displayName, openedTs, delayMs = 10 * 60 * 1000) {
  try {
    // Cancel any prior nudge for this chatId — newest session-open wins
    const prev = _slaNudgeTimers.get(String(chatId))
    if (prev) { try { clearTimeout(prev) } catch {} }

    const t = setTimeout(async () => {
      _slaNudgeTimers.delete(String(chatId))
      try {
        const currentTs = await get(supportSessions, chatId)
        if (!currentTs || currentTs !== openedTs) return // closed or re-opened — skip
        const st = await get(state, chatId)
        if (st?.adminTakeover === true) return // admin already replied — skip
        const waitedMin = Math.floor((Date.now() - openedTs) / 60000)
        send(TELEGRAM_ADMIN_CHAT_ID,
          `⏰ <b>Support SLA breach</b>\n` +
          `👤 <b>${displayName}</b> (${chatId}) has been waiting <b>${waitedMin} min</b> for a human reply.\n\n` +
          `↩️ /reply ${chatId} <i>your message</i>\n` +
          `✖️ /close ${chatId}`,
          adminMsgOpts({ chatId, supportSession: true }))
        log(`[Support] SLA nudge sent — ${chatId} waited ${waitedMin}min`)
      } catch (e) { log('[Support] SLA nudge error: ' + e.message) }
    }, delayMs)
    _slaNudgeTimers.set(String(chatId), t)
  } catch (e) { log('[Support] scheduleSupportSlaNudge error: ' + e.message) }
}

// ─── IVR campaign wallet hint prefix ─────────────────────────
// Returns a short localized wallet-balance / minimum-required line that is
// prepended to script-entry prompts in the outbound IVR builder. This is the
// second visibility hook (after the Quick IVR entry menu) for fix B: users
// should see the cost/balance picture BEFORE typing a ~15-minute custom
// script. Non-fatal if the wallet lookup errors — returns ''.
//
// When `ivrObData` is supplied (post-target-selection) the banner also shows
// a per-campaign cost estimate: `📞 Est: $X.XX (N targets × $Y.YY)`. The
// estimate uses IVR_CALL_RATE × 1 minute × target count (matches the billing
// floor of 1-minute-minimum per call). If balance < estimate the whole
// banner turns red regardless of the min-wallet check, because the user
// genuinely cannot complete THIS campaign with their current balance.
const ivrWalletHintPrefix = async (chatId, lang = 'en', ivrObData = null) => {
  try {
    const voiceService = require('./voice-service.js')
    const IVR_MIN_WALLET = parseFloat(process.env.BULK_CALL_MIN_WALLET || '50')
    const IVR_RATE = voiceService.IVR_CALL_RATE || 0.15
    const wc = await smartWalletCheck(walletOf, chatId, IVR_MIN_WALLET)
    const bal = wc.usdBal.toFixed(2)
    const min = IVR_MIN_WALLET.toFixed(2)

    // Per-campaign cost estimate (only if we have target info).
    const targetCount = Array.isArray(ivrObData?.batchTargets) && ivrObData.batchTargets.length
      ? ivrObData.batchTargets.length
      : (ivrObData?.targetNumber ? 1 : 0)
    const estCost = targetCount * IVR_RATE // 1-minute minimum per call
    const canCoverCampaign = targetCount === 0 || wc.usdBal >= estCost
    const estLine = targetCount > 0 ? ({
      en: `📞 <b>Est:</b> $${estCost.toFixed(2)} (${targetCount} target${targetCount === 1 ? '' : 's'} × $${IVR_RATE.toFixed(2)})\n\n`,
      fr: `📞 <b>Estimation :</b> ${estCost.toFixed(2)} $ (${targetCount} cible${targetCount === 1 ? '' : 's'} × ${IVR_RATE.toFixed(2)} $)\n\n`,
      zh: `📞 <b>预估费用:</b> $${estCost.toFixed(2)} (${targetCount} 个目标 × $${IVR_RATE.toFixed(2)})\n\n`,
      hi: `📞 <b>अनुमानित:</b> $${estCost.toFixed(2)} (${targetCount} लक्ष्य × $${IVR_RATE.toFixed(2)})\n\n`,
    }[lang] || `📞 <b>Est:</b> $${estCost.toFixed(2)} (${targetCount} targets × $${IVR_RATE.toFixed(2)})\n\n`) : ''

    if (wc.sufficient && canCoverCampaign) {
      const walletLine = ({
        en: `💰 <b>Wallet:</b> $${bal} · <b>Min:</b> $${min} ✅\n`,
        fr: `💰 <b>Portefeuille :</b> ${bal} $ · <b>Min :</b> ${min} $ ✅\n`,
        zh: `💰 <b>钱包:</b> $${bal} · <b>最低:</b> $${min} ✅\n`,
        hi: `💰 <b>वॉलेट:</b> $${bal} · <b>न्यूनतम:</b> $${min} ✅\n`,
      }[lang] || `💰 <b>Wallet:</b> $${bal} · <b>Min:</b> $${min} ✅\n`)
      return walletLine + estLine + (estLine ? '' : '\n')
    }

    // Short of either the min-wallet floor OR the per-campaign estimate —
    // both are blockers, so show the more specific shortfall. Campaign
    // shortfall takes precedence because it gives the user an exact number.
    const gap = !canCoverCampaign ? (estCost - wc.usdBal) : (IVR_MIN_WALLET - wc.usdBal)
    const reasonEn = !canCoverCampaign ? 'for this campaign' : 'to meet the minimum'
    const reasonFr = !canCoverCampaign ? 'pour cette campagne' : 'pour atteindre le minimum'
    const reasonZh = !canCoverCampaign ? '用于本次任务' : '以达到最低额'
    const reasonHi = !canCoverCampaign ? 'इस कैंपेन के लिए' : 'न्यूनतम पूरा करने के लिए'
    const walletLine = ({
      en: `⚠️ <b>Wallet:</b> $${bal} · <b>Min:</b> $${min} · Top up <b>$${gap.toFixed(2)}</b> ${reasonEn}.\n`,
      fr: `⚠️ <b>Portefeuille :</b> ${bal} $ · <b>Min :</b> ${min} $ · Déposez <b>${gap.toFixed(2)} $</b> ${reasonFr}.\n`,
      zh: `⚠️ <b>钱包:</b> $${bal} · <b>最低:</b> $${min} · 需充值 <b>$${gap.toFixed(2)}</b> ${reasonZh}。\n`,
      hi: `⚠️ <b>वॉलेट:</b> $${bal} · <b>न्यूनतम:</b> $${min} · <b>$${gap.toFixed(2)}</b> ${reasonHi} जमा करें।\n`,
    }[lang] || `⚠️ <b>Wallet:</b> $${bal} · <b>Min:</b> $${min} · Top up <b>$${gap.toFixed(2)}</b> ${reasonEn}.\n`)
    return walletLine + estLine + (estLine ? '' : '\n')
  } catch (e) {
    return ''
  }
}


// After a Cloud IVR number is activated (any payment path), users historically
// had to drill 4 levels (Cloud IVR + SIP → My Plans → [number] → 🔑 SIP
// Credentials → 👁️ Reveal Password) to see their SIP password. Support log
// analysis for @LBHAND23 (May 2026) showed this caused repeated confusion and
// two support tickets per user on average.
//
// This helper is called immediately AFTER the activation confirmation message
// to:
//   1. Pre-seed session state with `cpActiveNumber` + `action = cpManageNumber`
//      so the keyboard-based 🔑 SIP Credentials handler (in the main action
//      dispatcher) works on first tap with zero additional navigation.
//   2. Surface 🔑 SIP Credentials as the PRIMARY call-to-action via a reply
//      keyboard on a short localized "next step" message.
//
// Resilient to partial state: if the user's number doc isn't yet persisted in
// `phoneNumbersOf[chatId].numbers`, we still set the nudge based on the
// phoneNumber string — when the 🔑 SIP Credentials handler resolves `num` from
// state it'll hit `cpActiveNumber.phoneNumber` and look it up live.
const postActivationNudge = async (chatId, phoneNumber, planName) => {
  try {
    const userData = await get(phoneNumbersOf, chatId)
    const numberDoc =
      userData?.numbers?.find(n => n?.phoneNumber === phoneNumber)
      || { phoneNumber } // fall-back shim; SIP cred handler re-hydrates from DB

    // Write state atomically so the next message arrives in the right context.
    await setFields(state, chatId, {
      cpActiveNumber: numberDoc,
      action: 'cpManageNumber',
    })

    const info = await get(state, chatId)
    const lang = info?.userLanguage || 'en'
    const pc = phoneConfig.getBtn(lang)

    // Localized "next step" copy — concise, actionable, one tap to SIP creds.
    const body = ({
      en: `🎯 <b>Next step — grab your SIP credentials</b>\n\nTap <b>${pc.sipCredentials}</b> below to reveal your SIP username / password and get your softphone or browser calling page up and running in under a minute.`,
      fr: `🎯 <b>Prochaine étape — récupérez vos identifiants SIP</b>\n\nAppuyez sur <b>${pc.sipCredentials}</b> ci-dessous pour afficher votre nom d'utilisateur et mot de passe SIP et démarrer votre softphone ou page d'appel en moins d'une minute.`,
      hi: `🎯 <b>अगला कदम — अपने SIP क्रेडेंशियल्स प्राप्त करें</b>\n\nअपना SIP उपयोगकर्ता नाम / पासवर्ड दिखाने और एक मिनट में सॉफ्टफोन या ब्राउज़र कॉलिंग शुरू करने के लिए नीचे <b>${pc.sipCredentials}</b> पर टैप करें।`,
      zh: `🎯 <b>下一步 — 获取您的 SIP 凭据</b>\n\n点击下方的 <b>${pc.sipCredentials}</b> 查看您的 SIP 用户名 / 密码，几秒内即可在软电话或浏览器通话页面上线。`,
    })[lang] || ({
      en: `🎯 <b>Next step — grab your SIP credentials</b>\n\nTap <b>${pc.sipCredentials}</b> below to reveal your SIP username / password.`,
    }).en

    // Reply keyboard puts SIP Credentials as the top button — one tap away.
    // Include Test My Number and Back so the user has the common quick actions.
    return sendMessage(chatId, body, k.of([
      [pc.sipCredentials],
      [pc.testMyNumber, pc.callForwarding],
      [pc.back],
    ]))
  } catch (err) {
    // Non-fatal — failure here must never break the activation flow itself.
    log(`[postActivationNudge] failed for ${chatId}/${phoneNumber}: ${err.message}`)
  }
}



// Mask username: show first 2 chars + ***
const maskName = name => {
  if (!name || typeof name !== 'string') return 'User***'
  return name.length <= 2 ? name + '***' : name.slice(0, 2) + '***'
}

// Admin-only helpers: never used in public-group messages.
// Returns "@username (chatId)" or "User <chatId>" if username missing.
const adminUserTag = (name, chatId) => {
  const cid = chatId != null ? String(chatId) : ''
  if (name && typeof name === 'string') return `@${name}${cid ? ' (' + cid + ')' : ''}`
  return cid ? `User ${cid}` : 'User'
}
// Returns the domain unmasked (admin-only context).
const adminDomainTag = domain => (domain && typeof domain === 'string') ? domain : '***'

// Mask domain for group notifications — show first 3 chars of name + *** + full TLD
const maskDomain = domain => {
  if (!domain || typeof domain !== 'string') return '***.*'
  const dotIdx = domain.indexOf('.')
  if (dotIdx < 0) return domain.slice(0, 3) + '***'
  const name = domain.slice(0, dotIdx)
  const tld = domain.slice(dotIdx) // includes the dot
  const visible = Math.min(3, name.length)
  return name.slice(0, visible) + '***' + tld
}

// Reusable post-domain-registration upsell — keep parity across wallet/bank/crypto/dynopay paths.
// Sends "What's next with {domain}?" message + keyboard offering valid domain pairings
// (URL Shortener + Anti-Red Hosting). Used by Express route handlers where
// the inner-scope `send`/`trans`/`k`/`t` helpers aren't available.
const sendDomainUpsell = (chatId, lang, domain, delayMs = 2000) => {
  setTimeout(() => {
    try {
      const backLabel = (translation && translation('t.back', lang)) || 'Back'
      sendMessage(chatId, translation('t.dom_4', lang, domain, domain), {
        reply_markup: {
          keyboard: [
            ['🔗 Activate Domain for Shortener'],
            ['🛡️🔥 Anti-Red Hosting'],
            [backLabel]
          ],
          resize_keyboard: true,
        }
      })
    } catch (e) { log(`[Upsell] sendDomainUpsell error: ${e.message}`) }
  }, delayMs)
}


// Send event notification to all registered groups + configured fallback targets.
//
// 3-arg form: `notifyGroup(groupMsg, adminMsg, adminButtons)`
//   • Public groups (configured + auto-registered) receive `groupMsg` (masked).
//   • Admin chat (TELEGRAM_ADMIN_CHAT_ID) receives `adminMsg` (unmasked) + optional
//     inline keyboard `adminButtons` (array of rows, each row an array of buttons).
//
// 2-arg form: `notifyGroup(groupMsg, adminMsg)` — admin gets unmasked, no buttons.
// 1-arg form: `notifyGroup(message)` — legacy/back-compat (both groups + admin same msg).
const TELEGRAM_NOTIFY_GROUP_ID = process.env.TELEGRAM_NOTIFY_GROUP_ID
const notifyGroup = async (message, adminMessage = null, adminButtons = null) => {
  try {
    const taggedMessage = message + `\n— <b>${CHAT_BOT_NAME}</b>`
    const taggedAdminMessage = adminMessage != null
      ? adminMessage + `\n— <b>${CHAT_BOT_NAME}</b>`
      : taggedMessage
    const sentTo = new Set()

    // 1. Always send to configured notification group (if set) — masked, no buttons
    if (TELEGRAM_NOTIFY_GROUP_ID) {
      const gid = Number(TELEGRAM_NOTIFY_GROUP_ID)
      sentTo.add(String(gid)) // normalize to String for consistent dedup
      bot?.sendMessage(gid, taggedMessage, { parse_mode: 'HTML' })?.then(() => {
        log('[NotifyGroup] ✅ Sent to configured group ' + gid)
      })?.catch(e => {
        log('Configured notify group error (' + gid + '): ' + e.message)
      })
    }

    // 2. Always send to admin chat — UNMASKED if `adminMessage` provided,
    //    with optional inline keyboard for one-tap actions.
    if (TELEGRAM_ADMIN_CHAT_ID && !sentTo.has(String(TELEGRAM_ADMIN_CHAT_ID))) {
      sentTo.add(String(TELEGRAM_ADMIN_CHAT_ID))
      const adminOpts = { parse_mode: 'HTML' }
      if (adminButtons && Array.isArray(adminButtons) && adminButtons.length && adminMessage != null) {
        adminOpts.reply_markup = { inline_keyboard: adminButtons }
      }
      bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID, taggedAdminMessage, adminOpts)?.then(() => {
        log('[NotifyGroup] ✅ Sent to admin ' + TELEGRAM_ADMIN_CHAT_ID + (adminMessage != null ? ' (unmasked)' : '') + (adminOpts.reply_markup ? ' [+buttons]' : ''))
      })?.catch(e => {
        log('Admin notify error: ' + e.message)
      })
    }

    // 3. Send to all auto-registered groups from notifyGroups collection — masked, no buttons
    if (notifyGroupsCol?.find) {
      const groups = await notifyGroupsCol.find({}).toArray()
      log('[NotifyGroup] Auto-registered groups found: ' + groups.length + (groups.length ? ' → ' + groups.map(g => g.title || g._id).join(', ') : ''))
      for (const group of groups) {
        // ✅ Normalize to String for dedup — handles legacy docs where _id was stored
        // as Number (float) vs String (current). Prevents duplicate notifications.
        const gidKey = String(group._id)
        if (sentTo.has(gidKey)) { log('[NotifyGroup] ⏭ Skipping duplicate group ' + (group.title || gidKey)); continue }
        sentTo.add(gidKey)
        bot?.sendMessage(group._id, taggedMessage, { parse_mode: 'HTML' })?.then(() => {
          log('[NotifyGroup] ✅ Sent to group ' + (group.title || group._id))
        })?.catch(e => {
          log('Group notify error for ' + group._id + ': ' + e.message)
          if (e.message?.includes('bot was kicked') || e.message?.includes('chat not found') || e.message?.includes('bot is not a member')) {
            notifyGroupsCol.deleteOne({ _id: group._id })
            log('Removed group ' + group._id + ' from notifyGroups')
          }
        })
      }
    } else {
      log('[NotifyGroup] ⚠️ notifyGroupsCol not ready — skipped group query')
    }

    log('[NotifyGroup] Dispatched to ' + sentTo.size + ' target(s)')
  } catch (e) {
    log('notifyGroup error: ' + e.message)
  }
}

// ─── Admin one-tap action buttons (inline_keyboard rows) ───
// Used as the 3rd arg of `notifyGroup`. Callback handler lives in the existing
// `bot.on('callback_query')` block; awaiting-state hand-off lives in the early
// admin-message interceptor in the main on('message') handler.
//   • aR:<chatId>          → 💬 Reply (prompts admin, then runs /reply)
//   • aCS:<chatId>         → ✖️ Close Session (one-tap /close for support chats)
//   • aD:<orderId>         → 📩 Deliver (prompts admin, then runs /deliver)
//   • aRO:<orderId>        → ❌ Refund Order (confirm dialog, then refund)
//   • aRC:<chatId>:<usd>   → 💵 Refund $X.XX (confirm dialog, then refund)
//   • aCONF:<encoded>      → confirmation for a destructive action
//   • aCANCEL              → cancel a pending confirmation
const buildAdminButtons = ({ chatId, orderId, refundUsd, supportSession } = {}) => {
  const rows = []
  if (orderId) {
    rows.push([
      { text: '📩 Deliver', callback_data: `aD:${orderId}` },
      { text: '❌ Refund Order', callback_data: `aRO:${orderId}` },
    ])
  }
  if (refundUsd && chatId) {
    rows.push([{ text: `💵 Refund $${Number(refundUsd).toFixed(2)}`, callback_data: `aRC:${chatId}:${Number(refundUsd).toFixed(2)}` }])
  }
  if (chatId) {
    // Support-session notifications get both Reply + Close on the same row so
    // admins can end a spam/drive-by chat with one tap instead of typing /close.
    if (supportSession) {
      rows.push([
        { text: '💬 Reply User', callback_data: `aR:${chatId}` },
        { text: '✖️ Close Session', callback_data: `aCS:${chatId}` },
      ])
    } else {
      rows.push([{ text: '💬 Reply User', callback_data: `aR:${chatId}` }])
    }
  }
  return rows.length ? rows : null
}

// Convenience: full sendMessage `opts` including HTML + admin action buttons.
const adminMsgOpts = (args = {}) => {
  const opts = { parse_mode: 'HTML' }
  const rows = buildAdminButtons(args)
  if (rows) opts.reply_markup = { inline_keyboard: rows }
  return opts
}

// Send admin-only notification (private, not to groups)
const notifyAdmin = (message) => {
  try {
    if (TELEGRAM_ADMIN_CHAT_ID) {
      // Auto-resolve chatId references to include usernames
      const resolveAndSend = async () => {
        let enrichedMsg = message
        // Match patterns: "chatId: 123456", "User: 123456", "from: 123456", "(123456)"
        const patterns = [
          /chatId:\s*(\d{6,12})/g,
          /User:\s*(\d{6,12})/g,
          /from:\s*(\d{6,12})/g,
          /\((\d{6,12})\)/g,
        ]
        const resolvedIds = new Set()
        if (nameOf?.findOne) {
          for (const pattern of patterns) {
            const matches = message.matchAll(pattern)
            for (const match of matches) {
              const cid = match[1]
              if (resolvedIds.has(cid)) continue
              resolvedIds.add(cid)
              try {
                const user = await nameOf.findOne({ _id: String(cid) })
                if (user?.val) {
                  // Replace all occurrences of this chatId with @username (chatId)
                  const tag = `@${user.val}`
                  // Only replace bare chatId (not already tagged)
                  enrichedMsg = enrichedMsg.replace(new RegExp(`User:\\s*${cid}`, 'g'), `User: ${tag} (${cid})`)
                  enrichedMsg = enrichedMsg.replace(new RegExp(`chatId:\\s*${cid}`, 'g'), `chatId: ${tag} (${cid})`)
                  enrichedMsg = enrichedMsg.replace(new RegExp(`from:\\s*${cid}`, 'g'), `from: ${tag} (${cid})`)
                }
              } catch {}
            }
          }
        }
        bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID, enrichedMsg + `\n— <b>${CHAT_BOT_NAME}</b>`, { parse_mode: 'HTML' })?.catch(e => {
          log('notifyAdmin error: ' + e.message)
        })
      }
      resolveAndSend().catch(() => {
        // Fallback: send without enrichment
        bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID, message + `\n— <b>${CHAT_BOT_NAME}</b>`, { parse_mode: 'HTML' })?.catch(() => {})
      })
    }
  } catch (e) {
    log('notifyAdmin error: ' + e.message)
  }
}


