// ── Module-level resolveUserTag — accessible from callback_query handler ──
// FIX: Moved from inside loadData() to module scope so marketplace callback_query can use it
// Previously caused "resolveUserTag is not defined" error
async function resolveUserTag(chatId) {
  try {
    const name = await get(nameOf, chatId)
    if (name && typeof name === 'string') return `@${name} (${chatId})`
    if (name?.val) return `@${name.val} (${chatId})`
    return String(chatId)
  } catch { return String(chatId) }
}
function resolveUserTagSync(chatId, cachedName) {
  if (cachedName) return `@${cachedName} (${chatId})`
  return String(chatId)
}

let autoPromo = null
let cartRecovery = null
let userConversion = null

// Telnyx resources (set during init)
let telnyxResources = { sipConnectionId: null, messagingProfileId: null, callControlAppId: null }
let twilioResources = { sipDomainSid: null, sipDomainName: null, credentialListSid: null, accountSid: null }

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// Shared Twilio Purchase Helper — used by wallet, bank, crypto flows
// MUST be at module scope so bot.on('message') handler can access it
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
async function executeTwilioPurchase(chatId, selectedNumber, planKey, price, countryCode, countryName, numType, paymentMethod, addressSid, subOpts, bundleSid) {
  const plan = phoneConfig.plans[planKey]
  const name = await get(nameOf, chatId)
  const surcharge = getNumberSurcharge(countryCode, numType)

  // 1. Get or create sub-account (auto-replace if suspended)
  let userData = await get(phoneNumbersOf, chatId)
  let subSid = userData?.twilioSubAccountSid
  let subToken = userData?.twilioSubAccountToken

  // Check if existing sub-account is suspended/closed — if so, create a new one
  if (subSid) {
    try {
      const subAcctInfo = await twilioService.getSubAccount(subSid)
      if (subAcctInfo && !subAcctInfo.error && subAcctInfo.status && subAcctInfo.status !== 'active') {
        log(`[CloudPhone] Sub-account ${subSid} is "${subAcctInfo.status}" for chatId=${chatId} — creating new sub-account`)
        subSid = null
        subToken = null
      }
    } catch (checkErr) {
      log(`[CloudPhone] Sub-account check failed for ${subSid}: ${checkErr.message} — creating new sub-account`)
      subSid = null
      subToken = null
    }
  }

  if (!subSid) {
    const subAccount = await twilioService.createSubAccount(`Nomadly-${chatId}-${name || 'user'}`)
    if (subAccount.error) return { error: `Could not create phone account: ${subAccount.error}` }
    subSid = subAccount.accountSid
    subToken = subAccount.authToken
    if (userData) {
      userData.twilioSubAccountSid = subSid
      userData.twilioSubAccountToken = subToken
      // Atomic field-level $set — never rewrite the whole `val` (would race with feature edits)
      await phoneNumbersOf.updateOne(
        { _id: chatId },
        { $set: { 'val.twilioSubAccountSid': subSid, 'val.twilioSubAccountToken': subToken } },
        { upsert: true }
      )
    } else {
      // First-time setup: safe to create the full doc
      await set(phoneNumbersOf, chatId, { numbers: [], twilioSubAccountSid: subSid, twilioSubAccountToken: subToken })
    }
    log(`[CloudPhone] New sub-account created for chatId=${chatId}: ${subSid}`)
  }

  // 2. Buy number on main account with optional address + bundle
  // ━━━ SECURITY: Number is bought on main account then IMMEDIATELY transferred to sub-account ━━━
  // The number never stays on the main account — transfer is mandatory
  const buyResult = await twilioService.buyNumber(selectedNumber, null, null, SELF_URL, addressSid || null, bundleSid || null)
  if (buyResult.error) return { error: buyResult.error }

  // 3. Transfer to sub-account — MANDATORY, number must not stay on main account
  if (!subSid) {
    log(`[CloudPhone] CRITICAL: No sub-account SID for transfer after purchase — this should never happen`)
    return { error: 'Internal error: no sub-account for number transfer.' }
  }
  if (buyResult.sid) {
    const transferResult = await twilioService.transferNumberToSubAccount(buyResult.sid, subSid)
    if (transferResult.success) {
      log(`[CloudPhone] Number ${selectedNumber} transferred to sub-account ${subSid}`)
      await twilioService.updateSubAccountNumberWebhooks(subSid, buyResult.sid, SELF_URL)
    } else {
      log(`[CloudPhone] CRITICAL: Transfer failed for ${selectedNumber} to ${subSid}: ${transferResult.error}`)
      // Try to release the number from main account to avoid orphan
      try { const _mc = twilioService.getClient(); if (_mc) await _mc.incomingPhoneNumbers(buyResult.sid).remove() } catch (_) {}
      return { error: `Number purchased but transfer to your account failed: ${transferResult.error}` }
    }
  }

  // 4. SIP credentials (Twilio + Telnyx)
  // Telnyx is the primary SIP provider (sip.speechcue.com), so the Telnyx username
  // is used as the main sipUsername shown to users. Twilio seed is kept separately.
  const seedUser = phoneConfig.generateSipUsername()
  const seedPass = phoneConfig.generateSipPassword()
  let sipUsername = seedUser
  let sipPassword = seedPass
  let telnyxSipUsername = null
  let telnyxSipPassword = null
  let telnyxCredentialId = null
  let twilioSeedUsername = seedUser  // Keep original seed for Twilio credential list
  if (telnyxResources?.sipConnectionId) {
    const telnyxCred = await telnyxApi.createSIPCredential(telnyxResources.sipConnectionId, seedUser, seedPass)
    if (telnyxCred?.sip_username) {
      telnyxSipUsername = telnyxCred.sip_username
      telnyxSipPassword = telnyxCred.sip_password || seedPass
      telnyxCredentialId = telnyxCred.id || null
      // Use Telnyx username as the primary sipUsername since domain is sip.speechcue.com
      sipUsername = telnyxSipUsername
      sipPassword = telnyxSipPassword
      log(`[CloudPhone] Telnyx SIP credential created: ${telnyxSipUsername} (ID: ${telnyxCredentialId})`)
    }
  }
  if (twilioResources?.credentialListSid) {
    await twilioService.addSipCredential(twilioResources.credentialListSid, twilioSeedUsername, seedPass)
  }

  // 5. Save to DB
  const expiresAt = new Date()
  expiresAt.setMonth(expiresAt.getMonth() + 1)
  const numberDoc = {
    phoneNumber: selectedNumber,
    telnyxOrderId: null,
    twilioNumberSid: buyResult.sid,
    twilioSubAccountSid: (await get(phoneNumbersOf, chatId))?.twilioSubAccountSid || null,
    provider: 'twilio',
    country: countryCode,
    countryName: countryName,
    type: numType || 'local',
    plan: planKey,
    planPrice: price,
    purchaseDate: new Date().toISOString(),
    expiresAt: expiresAt.toISOString(),
    autoRenew: true,
    status: 'active',
    sipUsername,
    sipPassword,
    telnyxSipUsername,
    telnyxSipPassword,
    telnyxCredentialId,
    sipDomain: phoneConfig.SIP_DOMAIN,
    messagingProfileId: null,
    connectionId: null,
    addressSid: addressSid || null,
    numberSurcharge: surcharge,
    smsUsed: 0,
    minutesUsed: 0,
    capabilities: { voice: true, sms: true, fax: false },
    features: {
      sms: true,
      callForwarding: { enabled: false, mode: 'disabled', forwardTo: null, ringTimeout: 25 },
      voicemail: { enabled: false, greetingType: 'default', customGreetingUrl: null, forwardToTelegram: true, forwardToEmail: null, ringTimeout: 25 },
      smsForwarding: { toTelegram: true, toEmail: null, webhookUrl: null },
      recording: false,
    }
  }

  // Add sub-number fields if this is a sub-number purchase
  if (subOpts?.isSubNumber && subOpts?.parentNumber) {
    numberDoc.isSubNumber = true
    numberDoc.parentNumber = subOpts.parentNumber
  }

  userData = await get(phoneNumbersOf, chatId)
  // Atomic $push — never rewrite the whole val (would race with concurrent feature edits)
  await phoneNumbersOf.updateOne(
    { _id: chatId },
    { $push: { 'val.numbers': numberDoc } },
    { upsert: true }
  )
  if (userData?.numbers) { userData.numbers.push(numberDoc) }
  else { userData = userData || {}; userData.numbers = [numberDoc] }

  await phoneTransactions.insertOne({ chatId, phoneNumber: selectedNumber, action: subOpts?.isSubNumber ? 'sub-number-purchase' : 'purchase', plan: planKey, amount: price, paymentMethod, timestamp: new Date().toISOString() })

  // 6. Verify caller ID on main account for SIP bridge support
  // This allows the main account's SIP domain to use this sub-account number as callerId
  try {
    const subSid = numberDoc.twilioSubAccountSid || userData?.twilioSubAccountSid
    const subToken = userData?.twilioSubAccountToken
    if (subSid && subToken && buyResult?.sid) {
      log(`[CloudPhone] Verifying caller ID ${selectedNumber} on main account for SIP bridge...`)
      twilioService.verifyCallerIdOnMainAccount(selectedNumber, subSid, subToken, SELF_URL, buyResult.sid)
        .then(verified => log(`[CloudPhone] Caller ID verification for ${selectedNumber}: ${verified ? '✅' : '⚠️ failed'}`))
        .catch(e => log(`[CloudPhone] Caller ID verification error: ${e.message}`))
    }
  } catch (e) {
    log(`[CloudPhone] Non-critical: Caller ID verification setup error: ${e.message}`)
  }

  // Use phoneConfig.getTxt directly (module-scope safe) — cpTxt is only available inside loadData
  const _adminTxt = phoneConfig.getTxt('en')
  if (subOpts?.isSubNumber) {
    notifyGroup(_adminTxt.adminSubPurchase(maskName(name), selectedNumber, subOpts.parentNumber, price, paymentMethod), _adminTxt.adminSubPurchasePrivate(adminUserTag(name, chatId), selectedNumber, subOpts.parentNumber, price, paymentMethod))
  } else {
    notifyGroup(_adminTxt.adminPurchase(maskName(name), selectedNumber, plan?.name || planKey, price, paymentMethod), _adminTxt.adminPurchasePrivate(adminUserTag(name, chatId), selectedNumber, plan?.name || planKey, price, paymentMethod))
  }

  return { success: true, sipUsername, sipPassword, expiresAt, plan }
}

// Get or create cached Twilio address for a country
async function getCachedTwilioAddress(chatId, countryCode) {
  const userData = await get(phoneNumbersOf, chatId)
  return userData?.twilioAddresses?.[countryCode] || null
}

async function cacheTwilioAddress(chatId, countryCode, addressSid) {
  // Atomic field-level $set — never rewrite the whole val (would race with concurrent feature edits)
  await phoneNumbersOf.updateOne(
    { _id: chatId },
    { $set: { [`val.twilioAddresses.${countryCode}`]: addressSid } },
    { upsert: true }
  )
}

