  // startup isn't blocked by a Cloudflare round-trip.
  try {
    const { syncDiscoveryWorker } = require('./cloudflare-discovery-sync.js')
    setTimeout(() => { syncDiscoveryWorker().catch(e => console.log('[CF-Sync] failed:', e.message)) }, 3000)
  } catch (e) {
    console.log('[CF-Sync] module load failed:', e.message)
  }

  // SMS App APK download route
  const apkPath = require('path').join(__dirname, '..', 'static', 'nomadly-sms.apk')
  app.get('/sms-app/download', (req, res) => {
    const fs = require('fs')
    if (fs.existsSync(apkPath)) {
      // Prevent caching so users always get the latest APK
      res.setHeader('Content-Disposition', 'attachment; filename=NomadlySMS.apk')
      res.setHeader('Content-Type', 'application/vnd.android.package-archive')
      res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, max-age=0')
      res.setHeader('Pragma', 'no-cache')
      res.setHeader('Expires', '0')
      const stat = fs.statSync(apkPath)
      res.setHeader('ETag', `"${stat.size}-${stat.mtimeMs}"`)
      res.sendFile(apkPath)
    } else {
      res.status(404).json({ error: 'APK not available' })
    }
  })
  app.get('/sms-app/download/info', (req, res) => {
    const fs = require('fs')
    const exists = fs.existsSync(apkPath)
    const size = exists ? fs.statSync(apkPath).size : 0
    res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, max-age=0')
    res.json({ version: '2.7.5', name: 'Nomadly SMS', size, available: exists })
  })

  // Initialize Email Blast Service
  emailBlastService.initEmailBlast(db, bot)
  log('[EmailBlast] Service initialized with queue processor')

  // Initialize Email Validation Service
  emailValidationService.initEmailValidationService(db, bot)

  // Initialize Provider Balance Monitor (Telnyx + Twilio)
  const { initBalanceMonitor } = require('./balance-monitor.js')
  initBalanceMonitor(bot)

