    'select-dns-record-id-to-delete': async () => {
      const records = info?.dnsRecords || []
      // Filter out NS records — nameservers can only be updated, not deleted
      const deletableRecords = records.map((r, i) => ({ ...r, originalIndex: i })).filter(r => r.recordType !== 'NS')
      if (deletableRecords.length === 0) {
          send(chatId, ({ en: 'No deletable records found. Nameserver records can only be updated.', fr: 'Aucun enregistrement supprimable trouvé. Les enregistrements NS ne peuvent être que mis à jour.', zh: '没有找到可删除的记录。域名服务器记录只能更新。', hi: 'कोई हटाने योग्य रिकॉर्ड नहीं मिला। नेमसर्वर रिकॉर्ड केवल अपडेट किए जा सकते हैं।' }[lang] || 'No deletable records found. Nameserver records can only be updated.'), { parse_mode: 'HTML' })
        return
      }
      const recordBtns = deletableRecords.map((r) => {
        const label = r.recordContent || '—'
        const short = label.length > 30 ? label.substring(0, 28) + '..' : label
        // Show record name (hostname) to help distinguish records with same content
        const domainToManage = info?.domainToManage || ''
        const nameLabel = r.recordName === domainToManage ? '@' : (r.recordName || '@').replace('.' + domainToManage, '')
        return [`${r.originalIndex + 1}. ${r.recordType} ${nameLabel} → ${short}`]
      })
      const keyboard = { parse_mode: 'HTML', reply_markup: { keyboard: [...recordBtns, ['↩️ Back', t.cancel]] } }
      send(chatId, t.deleteDnsTxt, keyboard)
      await set(state, chatId, 'action', 'select-dns-record-id-to-delete')
    },

    'confirm-dns-record-id-to-delete': async () => {
      const records = info?.dnsRecords || []
      const delId = info?.delId
      const rec = records[delId]
      const label = rec ? `<b>${rec.recordType}</b> → ${rec.recordContent || '—'}` : 'this record'
      send(chatId, trans('t.wlt_7', label), k.of([[t.yes, t.no], ['↩️ Back']]))
      await set(state, chatId, 'action', 'confirm-dns-record-id-to-delete')
    },

    'choose-dns-action': async () => {
      const domain = info?.domainToManage

      // Use unified domain service to route DNS to correct provider
      const dnsResult = await domainService.viewDNSRecords(domain, db)
      const source = dnsResult?.source || 'connectreseller'
      const records = dnsResult?.records || []
      const domainNameId = dnsResult?.domainNameId || null
      const cfZoneId = dnsResult?.cfZoneId || null

      // Get domain metadata for nameserverType
      const domainMeta = await domainService.getDomainMeta(domain, db)
      const nameserverType = domainMeta?.nameserverType || (source === 'cloudflare' ? 'cloudflare' : 'provider')

      const toSave = records?.map((r) => ({
        dnszoneID: r.dnszoneID || null,
        dnszoneRecordID: r.dnszoneRecordID || null,
        cfRecordId: r.cfRecordId || null,
        recordType: r.recordType,
        nsId: r.nsId || null,
        recordContent: r.recordContent,
        recordName: r.recordName || null,
        isNameserver: r.isNameserver || false,
        priority: r.priority ?? null,
      }))

      const categorizeRecords = (records) => {
        return records.reduce((acc, record, index) => {
          const type = record.recordType;
          if (!acc[type]) {
            acc[type] = [];
          }
          acc[type].push({ index: index+1, ...record });
          return acc;
        }, {});
      };
      const categorizedRecords = categorizeRecords(records);

      // Detect if shortener is active (CNAME pointing to railway)
      const shortenerActive = records.some(r =>
        r.recordType === 'CNAME' && r.recordContent && r.recordContent.includes('.up.railway.app')
      )
      set(state, chatId, 'shortenerActive', shortenerActive)

      set(state, chatId, 'dnsRecords', toSave)
      set(state, chatId, 'dnsSource', source)
      // NOTE: `cfZoneId` is intentionally NOT stamped on session state.
      // It used to be set here as `set(state, chatId, 'cfZoneId', cfZoneId)`,
      // but that polluted user state with the most recently MANAGED domain's
      // zone ID, which then leaked into hosting provisioning and caused records
      // to be created in the wrong CF zone (see WRONG_ZONE_CFZONEID_BUG.md).
      // `cfZoneId` MUST be looked up per-domain from `registeredDomains` DB
      // or via `cfService.getZoneByName(domain)` at the point of use.
      set(state, chatId, 'domainNameId', domainNameId)
      set(state, chatId, 'nameserverType', nameserverType)
      await set(state, chatId, 'action', 'choose-dns-action')

      // Dynamic keyboard — custom NS domains only get Manage NS
      const shortenerBtn = shortenerActive ? t.deactivateShortener : t.activateShortener
      const _bc = ['↩️ Back']
      let kbRows
      if (nameserverType === 'custom') {
        // Custom nameservers: DNS is managed externally — surface NS management prominently
        kbRows = [[t.manageNameservers]]
        kbRows.push(_bc)
      } else {
        // Cloudflare or provider_default: full DNS management with NS management at top
        kbRows = [[t.manageNameservers], [t.quickActions, t.checkDns], [t.addDns, t.updateDns, t.deleteDns]]
        kbRows.push([shortenerBtn], _bc)
      }
      const dnsKeyboard = {
        parse_mode: 'HTML',
        reply_markup: { keyboard: kbRows },
        disable_web_page_preview: true,
      }
      send(chatId, t.viewDnsRecords(categorizedRecords, domain, nameserverType), dnsKeyboard)
    },

