async function buyDomain(chatId, domain, registrar, nsChoice, customNS) {
  // ref https://www.mongodb.com/docs/manual/core/dot-dollar-considerations
  const domainSanitizedForDb = domain.replaceAll('.', '@')

  // Use unified domain service for registration
  registrar = registrar || 'ConnectReseller'
  nsChoice = nsChoice || 'provider_default'

  const result = await domainService.registerDomain(domain, registrar, nsChoice, db, chatId, customNS)
  if (result.success) {
    set(domainsOf, chatId, domainSanitizedForDb, true)
  }

  return result
}

const formatLinks = links => {
  return links.map(d => `${d.clicks} ${d.clicks === 1 ? 'click' : 'clicks'} → ${d.shorter} → ${d.url}`)
}

const buyDomainFullProcess = async (chatId, lang, domain) => {
  let domainRegistered = false // track so catch-block knows not to refund
  try {
    sendMessage(chatId, translation('t.paymentSuccessFul', lang), rem)
    let info = await get(state, chatId)
    let registrar = info?.registrar || 'ConnectReseller'
    const nsChoice = info?.nsChoice || 'provider_default'
    const customNS = info?.customNS || null
    const buyResult = await buyDomain(chatId, domain, registrar, nsChoice, customNS)
    if (buyResult.error) {
      // Send detailed error to admin/dev only — user gets generic message
      const adminMsg = `❌ Domain purchase failed: ${domain} | user: ${chatId} | error: ${buyResult.error}`
      log(adminMsg)
      sendMessage(TELEGRAM_DEV_CHAT_ID, adminMsg)
      // User-facing message — no provider names, no raw errors
      const userMsg = translation('t.domainPurchasedFailed', lang, domain)
      sendMessage(chatId, userMsg)
      return userMsg
    }
    // ✅ At this point the domain is registered — no exception below should trigger refund
    domainRegistered = true
    // Track actual registrar — may differ from original if CR→OP fallback occurred
    registrar = buyResult.registrar || registrar

    // Save registration outcome to state for pricing in payment handler
    if (buyResult.registrarChanged) {
      // Fallback occurred (e.g., CR→OP) — no savings, charge shown price
      log(`[buyDomainFullProcess] Registrar fallback for ${domain}: registered via ${buyResult.registrar} (actual price: $${buyResult.actualPrice || 'unknown'})`)
      await set(state, chatId, 'registrarFallback', true)
      if (buyResult.actualPrice) {
        await set(state, chatId, 'actualPrice', buyResult.actualPrice)
      }
      await set(state, chatId, 'actualRegistrar', buyResult.registrar)
    } else {
      // Cheaper registrar succeeded — savings may apply
      log(`[buyDomainFullProcess] ${domain} registered via primary registrar ${buyResult.registrar} — potential savings`)
      await set(state, chatId, 'registrarFallback', false)
      await set(state, chatId, 'actualRegistrar', buyResult.registrar)
    }

    // Generate transaction ID for domain purchase
    const txnId = generateTransactionId()
    try {
      await logTransaction(db, {
        transactionId: txnId,
        chatId,
        type: 'domain',
        amount: buyResult.actualPrice || info?.price || 0,
        currency: 'USD',
        status: 'completed',
        metadata: { domain, registrar: buyResult.registrar, nameservers: buyResult.nameservers }
      })
    } catch (txErr) {
      log('[Domain] Failed to log transaction (non-blocking):', txErr.message)
    }

    const domainSuccessMsg = translation('t.domainBoughtSuccess', lang, domain) + 
      `\n\n<b>Transaction ID:</b> <code>${txnId}</code>\n<i>Quote this ID when contacting support</i>`
    send(chatId, domainSuccessMsg, translation('o', lang))
    
    // Show smart recommendations after domain purchase (unless user explicitly skipped shortener integration)
    if (info?.askDomainToUseWithShortener !== false) {
      try {
        const recommendations = getRecommendationsAfterDomain(domain, lang)
        send(chatId, recommendations.message, k.of(recommendations.keyboard))
      } catch (recErr) {
        log('[Domain] Failed to show recommendations (non-blocking):', recErr.message)
      }
    }

    // NS was set at registration time (passed to registrar API directly) — no post-reg update needed
    if (nsChoice !== 'provider_default' && buyResult.nameservers && buyResult.nameservers.length >= 2) {
      const nsLabel = nsChoice === 'cloudflare' ? 'Cloudflare' : 'Custom'
      log(`[buyDomainFullProcess] ${domain} registered with ${nsLabel} NS: ${buyResult.nameservers.join(', ')} (registrar: ${registrar})`)
    }

    if (info?.askDomainToUseWithShortener === false) return

    // ── Persist shortener activation intent ──
    await createActivationTask(chatId, domain, lang)

    // Link domain to Railway/Render for URL shortener
    const { server, error, recordType, txtHost, txtValue } =
      process.env.HOSTED_ON === 'render'
        ? await saveDomainInServerRender(domain)
        : await saveDomainInServerRailway(domain)

    if (error) {
      // NOTE: Domain is ALREADY registered & transaction logged at this point.
      // Post-registration shortener setup failure must NOT trigger refund in the caller.
      // We mark the activation "skipped" (not "failed") so it's not auto-retried.
      // Required DNS metadata (registrar, cfZoneId, opDomainId, nameserverType) is
      // already persisted by domainService.registerDomain → user can manage DNS via bot menu.
      sendMessage(chatId, translation('t.domainRegisteredManualDns', lang, domain) ||
        `✅ <b>${domain}</b> registered successfully.\n\n` +
        `⚠️ URL-shortener couldn't be activated automatically right now, but your domain is yours. ` +
        `You can manage DNS (A, CNAME, TXT, MX) anytime from the <b>My Domains</b> menu.`)
      await markSkipped(domain, `shortener-server-link: ${error}`).catch(() => {})
      sendMessage(TELEGRAM_DEV_CHAT_ID, `⚠️ Shortener server link failed (no refund, no retry) for ${domain} | user ${chatId}: ${error}`)
      log(`[buyDomainFullProcess] Shortener server link failed for ${domain} — domain already registered with DNS metadata; marked skipped, NOT refunding: ${error}`)
      return false // domain already succeeded — do not refund
    }

    // ── Persist Railway link complete ──
    await markRailwayLinked(domain, server, recordType)

    sendMessage(chatId, translation('t.domainLinking', lang, domain))

    // Add shortener DNS via unified service — auto-resolves A/CNAME conflicts,
    // routes to Cloudflare when domain metadata has nameserverType='cloudflare' + cfZoneId.
    await sleep(5000) // Brief delay for DB metadata propagation
    const addResult = await domainService.addShortenerCNAME(domain, server, db, txtHost, txtValue)
    if (addResult.error || !addResult.success) {
      log(`[buyDomainFullProcess] DNS record add failed via domainService for ${domain}: ${addResult.error || 'unknown'}`)
      // Fallback: try direct CR DNS add for ConnectReseller domains
      if (registrar === 'ConnectReseller') {
        log(`[buyDomainFullProcess] Falling back to direct CR DNS add for ${domain}`)
        await sleep(60000) // CR needs propagation time
        const { error: saveServerInDomainError } = await saveServerInDomain(domain, server, recordType)
        if (saveServerInDomainError) {
          // NOTE: Domain is ALREADY registered & transaction logged — NO refund, NO retry.
          // DNS metadata already saved by domainService.registerDomain.
          sendMessage(chatId, translation('t.domainRegisteredManualDns', lang, domain) ||
            `✅ <b>${domain}</b> registered successfully.\n\n` +
            `⚠️ URL-shortener couldn't be activated automatically right now, but your domain is yours. ` +
            `You can manage DNS (A, CNAME, TXT, MX) anytime from the <b>My Domains</b> menu.`)
          await markSkipped(domain, `cname-cr-fallback: ${saveServerInDomainError}`).catch(() => {})
          sendMessage(TELEGRAM_DEV_CHAT_ID, `⚠️ Shortener CNAME (CR fallback) failed (no refund, no retry) for ${domain} | user ${chatId}: ${saveServerInDomainError}`)
          log(`[buyDomainFullProcess] Shortener CNAME CR-fallback failed for ${domain} — domain already registered with DNS metadata; marked skipped, NOT refunding: ${saveServerInDomainError}`)
          return false // domain already succeeded — do not refund
        }
      } else {
        // NOTE: Domain is ALREADY registered & transaction logged — NO refund, NO retry.
        // DNS metadata already saved by domainService.registerDomain.
        sendMessage(chatId, translation('t.domainRegisteredManualDns', lang, domain) ||
          `✅ <b>${domain}</b> registered successfully.\n\n` +
          `⚠️ URL-shortener couldn't be activated automatically right now, but your domain is yours. ` +
          `You can manage DNS (A, CNAME, TXT, MX) anytime from the <b>My Domains</b> menu.`)
        await markSkipped(domain, `cname-addRecord: ${addResult.error || 'unknown'}`).catch(() => {})
        sendMessage(TELEGRAM_DEV_CHAT_ID, `⚠️ Shortener CNAME failed (no refund, no retry) for ${domain} | user ${chatId}: ${addResult.error || 'unknown'}`)
        log(`[buyDomainFullProcess] Shortener CNAME failed for ${domain} — domain already registered with DNS metadata; marked skipped, NOT refunding: ${addResult.error || 'unknown'}`)
        return false // domain already succeeded — do not refund
      }
    }

    // ── Persist DNS complete ──
    await markDnsAdded(domain)

    sendMessage(chatId, translation('t.domainBought', lang).replaceAll('{{domain}}', domain))
    regularCheckDns(bot, chatId, domain, lang)

    // ── Persist fully completed ──
    await markCompleted(domain)

    return false // error = false
  } catch (error) {
    const errorMessage = `err buyDomainFullProcess ${error?.message} ${safeStringify(error?.response?.data)}`
    sendMessage(TELEGRAM_DEV_CHAT_ID, errorMessage)
    console.error(errorMessage)
    // If the domain was already registered before the exception, DO NOT signal an error to the caller — the payment should not be refunded.
    if (domainRegistered) {
      log(`[buyDomainFullProcess] Exception AFTER successful domain registration (${domain}) — suppressing refund. Error: ${error?.message}`)
      sendMessage(TELEGRAM_DEV_CHAT_ID, `⚠️ Post-registration exception (no refund) for ${domain}: ${error?.message}`)
      return false
    }
    return errorMessage
  }
}

schedule.scheduleJob('*/5 * * * *', function() {
  checkVPSPlansExpiryandPayment()
})

// ─── Weekly Contabo ↔ MongoDB orphan reconciliation ─────────────────────
// Every Monday at 09:00 UTC. Detects Contabo instances not linked to any
// customer record in MongoDB. Alerts admin so leaks like the €30+ surprise
// (test-probe, never-paid pending_payment ghosts) are caught within a week.
// Infrastructure instances (those whose IPs are referenced by env vars such
// as EV_WORKER_URL, WHM_HOST, PANEL_DOMAIN, etc.) are whitelisted.
schedule.scheduleJob('0 9 * * 1', function() {
  reconcileContaboOrphans()
})

// ─── Self-heal: VPS renewed-after-cancel guard ──────────────────────────
// Every 30 minutes. Detects the failure mode that caused the @davion419 €30
// leak: DB plan is CANCELLED/DELETED but the matching Contabo instance is
// STILL RUNNING (either because Contabo auto-renewed before our cancel
// landed, leaving a future cancelDate beyond our end_time, or because the
// cancel never propagated and cancelDate is null on a pending_payment
// instance). In both cases the bot user retains access they didn't pay for.
// Action: shutdown instance → rotate Administrator password → archive +
// delete the vpsPlansOf doc → alert admin. Idempotent via vpsPlansOf_revoked.
schedule.scheduleJob('*/30 * * * *', function() {
  selfHealRenewedAfterCancelVPS()
})

// ─── Daily Contabo state drift check ────────────────────────────────────
// Once per day, walks all vpsPlansOf records and reconciles DB intent vs
// Contabo state. Catches anything that slips through the per-event paths:
//   • autoRenewable=false but Contabo cancelDate missing → call cancel
//   • _uncancelPending=true (user re-enabled / paid manually) → nag admin
//     until they hit "Resume Subscription" on the Contabo dashboard
// Runs at 08:00 UTC daily — admin gets a single morning digest.
schedule.scheduleJob('0 8 * * *', function() {
  reconcileContaboBillingDrift()
})

async function reconcileContaboOrphans() {
  if (!vpsPlansOf || typeof vpsPlansOf.find !== 'function') {
    console.log('[Orphan Recon] Database not ready — skipping')
    return
  }
  try {
    const contabo = require('./contabo-service.js')
    const fs = require('fs')
    let envContent = ''
    try { envContent = fs.readFileSync('.env', 'utf8') } catch {}

    const instances = await contabo.listInstances()
    const allPlans = await vpsPlansOf.find({}).toArray()
    const dbByInstanceId = new Map()
    for (const p of allPlans) {
      const id = p.contaboInstanceId ?? p.vpsId
      if (id != null) dbByInstanceId.set(String(id), p)
    }

    const orphans = []
    for (const inst of instances) {
      // Skip instances already queued for cancellation on Contabo
      if (inst.cancelDate || inst.status === 'cancelled') continue
      const ip = inst.ipConfig?.v4?.ip
      // Whitelist infrastructure IPs (referenced by env vars)
      if (ip && envContent.includes(ip)) continue
      if (!dbByInstanceId.has(String(inst.instanceId))) {
        orphans.push({ id: inst.instanceId, name: inst.name, product: inst.productId, region: inst.region, status: inst.status, ip: ip || 'pending', created: inst.createdDate })
      }
    }

    if (orphans.length === 0) {
      log('[Orphan Recon] ✅ No orphans detected')
      return
    }

    const list = orphans.map(o => `• <code>${o.id}</code> ${o.name} | ${o.product} @ ${o.region} | ${o.status} | ${o.ip} | since ${new Date(o.created).toISOString().slice(0,10)}`).join('\n')
    const msg = `🧹 <b>Contabo Orphan Report — ${orphans.length} instance(s) not linked to any customer</b>\n\n${list}\n\n⚠️ Potential billing leak. Review & cancel via Contabo panel if no longer needed.`
    if (typeof bot?.sendMessage === 'function' && TELEGRAM_ADMIN_CHAT_ID) {
      bot.sendMessage(TELEGRAM_ADMIN_CHAT_ID, msg, { parse_mode: 'HTML' }).catch(e => log('[Orphan Recon] notify fail: ' + e.message))
    }
    log(`[Orphan Recon] ⚠️ ${orphans.length} orphan(s) detected`)
  } catch (err) {
    log('[Orphan Recon] error: ' + (err.message || err))
  }
}

// ─── Self-heal: VPS renewed-after-cancel ────────────────────────────────────
// Detects the failure mode that caused @davion419's leak (2026-05-10):
//   • DB plan.status ∈ {CANCELLED, DELETED}
//   • Contabo instance still RUNNING (consuming the seat we already paid for)
//   • Either:
//     (a) Contabo cancelDate is in the future AND > planEnd + grace → Contabo
//         auto-renewed before our cancel landed (this is the @davion419 case),
//         OR
//     (b) Contabo cancelDate is null → our cancel never propagated (e.g.
//         pending_payment instances that Contabo refuses to /cancel).
// Action: shutdown + rotate password + archive+delete the vpsPlansOf doc.
// The archive into vpsPlansOf_revoked acts as the idempotency marker — once a
// plan is moved there, the main vpsPlansOf collection no longer contains it
// so this sweep stops touching it.
const SELF_HEAL_GRACE_DAYS = 2  // tolerance: Contabo cancelDate vs DB end_time
async function selfHealRenewedAfterCancelVPS() {
  if (!vpsPlansOf || typeof vpsPlansOf.find !== 'function') {
    console.log('[VPS Self-heal] Database not ready — skipping')
    return
  }
  let healed = 0
  let alerted = 0
  try {
    const contabo = require('./contabo-service.js')
    // Bucket A: DB cancelled/deleted (renewed-after-cancel + cancel-never-propagated)
    const cancelled = await vpsPlansOf.find({
      status: { $in: ['CANCELLED', 'DELETED'] },
      $or: [
        { _selfHealAttemptedAt: { $exists: false } },
        { _selfHealAttemptedAt: { $lt: new Date(Date.now() - 6 * 60 * 60 * 1000) } } // retry after 6h
      ]
    }).toArray()

    // Bucket B: auto-renew turned OFF by user but Contabo cancel never propagated.
    // Catches the pre-Bug-B-fix records where user disabled auto-renew before the
    // cancel-on-toggle code shipped. Without this, Contabo's pre-renewal billing
    // (~4 days before end_time) fires before our T-24h Phase 1 cancel call, and
    // we eat the next month's invoice — the @davion419 V93 €7.26 leak (May 8).
    const autoRenewOffNoCancel = await vpsPlansOf.find({
      autoRenewable: false,
      status: { $in: ['RUNNING', 'running', 'INSTALLING', 'installing', 'provisioning'] },
      _contaboCancelledEarly: { $ne: true },
      $or: [
        { _selfHealAttemptedAt: { $exists: false } },
        { _selfHealAttemptedAt: { $lt: new Date(Date.now() - 6 * 60 * 60 * 1000) } }
      ]
    }).toArray()

    if (cancelled.length + autoRenewOffNoCancel.length === 0) return

    const revoked = db.collection('vpsPlansOf_revoked')
    const graceMs = SELF_HEAL_GRACE_DAYS * 24 * 60 * 60 * 1000

    // First handle Bucket B: just call Contabo cancel (instance keeps running for
    // the customer until end_time — they paid for the current month). Stamp the
    // DB so future cycles don't repeat.
    for (const plan of autoRenewOffNoCancel) {
      const cid = plan.contaboInstanceId ?? plan.vpsId
      if (!cid) continue
      try {
        const live = await contabo.getInstance(cid)
        if (live.cancelDate || live.status === 'cancelled' || live.status === 'stopped') {
          // already cancelled or stopped; just stamp DB so we stop checking
          await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _contaboCancelledEarly: true, contaboCancelDate: live.cancelDate, _selfHealAttemptedAt: new Date(), _selfHealReason: 'autoRenewOff_already_cancelled_on_contabo' } })
          continue
        }
        // Refuse if Contabo can't accept cancel (pending_payment)
        if (live.status === 'pending_payment') {
          await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _selfHealAttemptedAt: new Date(), _selfHealReason: 'pending_payment_manual_required' } })
          continue
        }
        log(`[VPS Self-heal] BACKFILL-CANCEL ${cid} (chatId=${plan.chatId}) — autoRenew=false but Contabo had no cancelDate`)
        await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _selfHealAttemptedAt: new Date(), _selfHealReason: 'autoRenewOff_backfill_cancel' } })
        try {
          await contabo.cancelInstance(cid)
          await new Promise(r => setTimeout(r, 5000))
          const v = await contabo.getInstance(cid)
          if (v.cancelDate) {
            await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _contaboCancelledEarly: true, contaboCancelDate: v.cancelDate, cancelReason: 'autoRenew_backfill' } })
            log(`[VPS Self-heal] BACKFILL-CANCEL ${cid} ✓ cancelDate=${v.cancelDate}`)
            healed++
            try {
              const userTag = adminUserTag(await get(nameOf, plan.chatId), plan.chatId)
              if (typeof bot?.sendMessage === 'function' && TELEGRAM_ADMIN_CHAT_ID) {
                bot.sendMessage(TELEGRAM_ADMIN_CHAT_ID, `🛠️ <b>VPS Self-heal — Backfill cancel</b>\nUser: ${userTag}\nVPS: ${plan.label || plan.name || '-'}\nContabo ID: <code>${cid}</code>\nReason: autoRenew=off but Contabo cancel never propagated.\n✅ Contabo cancelDate = ${v.cancelDate}`, { parse_mode: 'HTML' }).catch(() => {})
              }
              alerted++
            } catch {}
          } else {
            log(`[VPS Self-heal] BACKFILL-CANCEL ${cid} ⚠️ soft-success (no cancelDate)`)
          }
        } catch (err) {
          log(`[VPS Self-heal] BACKFILL-CANCEL ${cid} failed: ${err.message || err}`)
        }
      } catch (err) {
        if (err?.status === 404) {
          // gone from Contabo — clear stamps
          await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _contaboCancelledEarly: true, _selfHealAttemptedAt: new Date(), _selfHealReason: 'contabo_404_on_lookup' } })
          continue
        }
        log(`[VPS Self-heal] BACKFILL fetch ${cid} failed: ${err.message || err}`)
      }
    }

    if (cancelled.length === 0) {
      if (healed || alerted) log(`[VPS Self-heal] cycle complete — healed=${healed}, alerted=${alerted}`)
      return
    }
    for (const plan of cancelled) {
      const cid = plan.contaboInstanceId ?? plan.vpsId
      if (!cid) continue

      let live
      try {
        live = await contabo.getInstance(cid)
      } catch (err) {
        // 404 = already gone from Contabo; safe to skip
        if (err?.status === 404) continue
        log(`[VPS Self-heal] Could not fetch ${cid}: ${err.message || err}`)
        continue
      }

      // Skip if Contabo already stopped/cancelled it — nothing to heal
      if (live.status === 'stopped' || live.status === 'shutdown' || live.status === 'cancelled') {
        continue
      }

      // pending_payment leak: Contabo refuses /cancel API on this state, so we
      // can only alert the admin once to take manual action via my.contabo.com.
      if (live.status === 'pending_payment' && !live.cancelDate) {
        await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _selfHealAttemptedAt: new Date(), _selfHealReason: 'pending_payment_manual_required' } })
        try {
          const userTag = adminUserTag(await get(nameOf, plan.chatId), plan.chatId)
          const msg = `⚠️ <b>VPS Self-heal — Manual action required</b>\n` +
            `User: ${userTag}\nVPS: ${plan.label || plan.name || '-'}\nContabo ID: <code>${cid}</code>\n` +
            `Status: <code>pending_payment</code> (Contabo API refuses /cancel for this state)\n` +
            `Plan end_time: ${plan.end_time ? new Date(plan.end_time).toISOString() : '-'}\n\n` +
            `🛠️ Please cancel manually via my.contabo.com → Unpaid Orders.`
          if (typeof bot?.sendMessage === 'function' && TELEGRAM_ADMIN_CHAT_ID) {
            bot.sendMessage(TELEGRAM_ADMIN_CHAT_ID, msg, { parse_mode: 'HTML' }).catch(() => {})
          }
          alerted++
          log(`[VPS Self-heal] ALERT-ONLY ${cid} — pending_payment manual action required`)
        } catch (err) { log(`[VPS Self-heal] alert fail: ${err.message}`) }
        continue
      }

      if (live.status !== 'running' && live.status !== 'installing' && live.status !== 'provisioning') {
        continue
      }

      const planEnd = plan.end_time ? new Date(plan.end_time).getTime() : null
      const contaboCancelDate = live.cancelDate ? new Date(live.cancelDate).getTime() : null
      const renewedAfterCancel = contaboCancelDate && planEnd && (contaboCancelDate - planEnd > graceMs)
      const cancelNeverPropagated = !contaboCancelDate

      if (!renewedAfterCancel && !cancelNeverPropagated) {
        // CancelDate is set and reasonably close to end_time — normal cancellation in flight
        continue
      }

      const reason = renewedAfterCancel ? 'renewed_after_cancel_bug' : 'cancel_never_propagated'
      log(`[VPS Self-heal] DETECTED ${cid} (chatId=${plan.chatId}) — reason=${reason} cancelDate=${live.cancelDate || 'null'} planEnd=${plan.end_time}`)

      // mark attempt early so concurrent runs don't double-act
      await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _selfHealAttemptedAt: new Date(), _selfHealReason: reason } })

      // Step 1: rotate password (locks user out even if VPS reboots)
      let pwdSecretId = null
      try {
        const r = await contabo.resetPassword(cid, {
          osType: live.osType,
          isRDP: live.osType === 'Windows',
          defaultUser: live.defaultUser
        })
        pwdSecretId = r.secretId
        log(`[VPS Self-heal] ${cid} password rotated, secretId=${pwdSecretId}`)
      } catch (err) {
        log(`[VPS Self-heal] ${cid} resetPassword failed: ${err.message || err}`)
      }

      // Step 2: shutdown (give the reset reboot 45s to settle first)
      let stopped = false
      await new Promise(r => setTimeout(r, 45000))
      for (let attempt = 1; attempt <= 3; attempt++) {
        try {
          await contabo.shutdownInstance(cid)
          await new Promise(r => setTimeout(r, 10000))
          const v = await contabo.getInstance(cid)
          if (v.status === 'stopped' || v.status === 'shutdown') { stopped = true; break }
        } catch (err) {
          // 400 "Instance is already stopped" means it IS stopped — count as success
          const msg = err?.message || ''
          if (msg.includes('already stopped')) { stopped = true; break }
          log(`[VPS Self-heal] ${cid} shutdown attempt ${attempt} failed: ${msg}`)
          await new Promise(r => setTimeout(r, 15000))
        }
      }

      // Step 3: archive then delete the DB doc
      try {
        await revoked.insertOne({
          ...plan,
          _archivedAt: new Date(),
          _archivedReason: reason,
          _archivedBy: 'selfHealRenewedAfterCancelVPS',
          _contaboFinalStatus: stopped ? 'stopped' : live.status,
          _passwordRotatedSecretId: pwdSecretId,
          _originalId: plan._id,
          _id: undefined
        })
        await vpsPlansOf.deleteOne({ _id: plan._id })
        healed++
        log(`[VPS Self-heal] HEALED ${cid} — archived + deleted from vpsPlansOf (stopped=${stopped})`)
      } catch (err) {
        log(`[VPS Self-heal] ${cid} archive/delete failed: ${err.message}`)
      }

      // Step 4: admin alert
      try {
        const userTag = adminUserTag(await get(nameOf, plan.chatId), plan.chatId)
        const planEndStr = plan.end_time ? new Date(plan.end_time).toISOString() : '-'
        const cancelDateStr = live.cancelDate || '-'
        const msg = `🛠️ <b>VPS Self-heal — ${reason === 'renewed_after_cancel_bug' ? 'Renewed-after-cancel' : 'Cancel-never-propagated'}</b>\n` +
          `User: ${userTag}\nVPS: ${plan.label || plan.name || '-'}\nContabo ID: <code>${cid}</code>\n` +
          `Plan end_time: ${planEndStr}\nContabo cancelDate: ${cancelDateStr}\n` +
          `${pwdSecretId ? '🔑 Password rotated (admin password file stored on Contabo as secretId ' + pwdSecretId + ')\n' : '⚠️ Password rotation FAILED\n'}` +
          `${stopped ? '⏹️ Instance shutdown verified\n' : '⚠️ Shutdown could not be verified within 60s — may still be settling\n'}` +
          `🗑️ DB record moved to <code>vpsPlansOf_revoked</code>` +
          `${reason === 'cancel_never_propagated' ? '\n\n⚠️ <b>Cancel API never accepted</b> — please cancel manually via my.contabo.com to stop billing.' : ''}`
        if (typeof bot?.sendMessage === 'function' && TELEGRAM_ADMIN_CHAT_ID) {
          bot.sendMessage(TELEGRAM_ADMIN_CHAT_ID, msg, { parse_mode: 'HTML' }).catch(() => {})
        }
        alerted++
      } catch (err) {
        log(`[VPS Self-heal] admin notify fail: ${err.message}`)
      }
    }

    if (healed || alerted) log(`[VPS Self-heal] cycle complete — healed=${healed}, alerted=${alerted}`)
  } catch (err) {
    log('[VPS Self-heal] cycle error: ' + (err.message || err))
  }
}

// ─── Daily Contabo state drift check ────────────────────────────────────
async function reconcileContaboBillingDrift() {
  if (!vpsPlansOf || typeof vpsPlansOf.find !== 'function') {
    console.log('[VPS Drift] Database not ready — skipping')
    return
  }
  try {
    const contabo = require('./contabo-service.js')

    // Bucket 1: autoRenewable=false but Contabo cancelDate not yet set → cancel now
    const candidatesA = await vpsPlansOf.find({
      autoRenewable: false,
      status: { $in: ['RUNNING', 'running', 'INSTALLING', 'installing', 'provisioning'] },
      _contaboCancelledEarly: { $ne: true }
    }).toArray()

    let cancelled = 0
    for (const plan of candidatesA) {
      const cid = plan.contaboInstanceId ?? plan.vpsId
      if (!cid) continue
      try {
        const live = await contabo.getInstance(cid)
        if (live.cancelDate) {
          await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _contaboCancelledEarly: true, contaboCancelDate: live.cancelDate } })
          continue
        }
        if (live.status === 'pending_payment' || live.status === 'cancelled' || live.status === 'stopped') continue
        await contabo.cancelInstance(cid)
        await new Promise(r => setTimeout(r, 4000))
        const v = await contabo.getInstance(cid)
        if (v.cancelDate) {
          await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _contaboCancelledEarly: true, contaboCancelDate: v.cancelDate, cancelReason: 'daily_drift_backfill' } })
          cancelled++
          log(`[VPS Drift] backfill-cancelled ${cid} chat=${plan.chatId} → cancelDate=${v.cancelDate}`)
        }
      } catch (err) {
        if (err?.status === 404) {
          await vpsPlansOf.updateOne({ _id: plan._id }, { $set: { _contaboCancelledEarly: true } })
          continue
        }
        log(`[VPS Drift] ${cid} cancel attempt failed: ${err.message || err}`)
      }
    }

    // Bucket 2: _uncancelPending=true → nag admin until Contabo cancelDate cleared
    const candidatesB = await vpsPlansOf.find({ _uncancelPending: true }).toArray()
    const stillPending = []
    for (const plan of candidatesB) {
      const cid = plan.contaboInstanceId ?? plan.vpsId
      if (!cid) continue
      try {
        const live = await contabo.getInstance(cid)
        if (!live.cancelDate) {
          // Admin already hit "Resume Subscription" — clear our flag
          await vpsPlansOf.updateOne({ _id: plan._id }, { $unset: { _uncancelPending: '', _uncancelPendingSince: '' } })
          log(`[VPS Drift] _uncancelPending cleared for ${cid} (Contabo cancelDate gone)`)
          continue
        }
        stillPending.push({ cid, chatId: plan.chatId, label: plan.label || plan.name, since: plan._uncancelPendingSince, cancelDate: live.cancelDate })
      } catch (err) {
        if (err?.status === 404) {
          await vpsPlansOf.updateOne({ _id: plan._id }, { $unset: { _uncancelPending: '', _uncancelPendingSince: '' } })
          continue
        }
        log(`[VPS Drift] _uncancelPending fetch ${cid} failed: ${err.message || err}`)
      }
    }

    if (stillPending.length && typeof bot?.sendMessage === 'function' && TELEGRAM_ADMIN_CHAT_ID) {
      const list = stillPending.map(p => `• <code>${p.cid}</code> | chat=${p.chatId} | ${p.label || '-'} | cancelDate=${p.cancelDate} | pending since ${p.since ? new Date(p.since).toISOString().slice(0,10) : '?'}`).join('\n')
      const msg = `🔄 <b>Contabo dashboard action — Resume Subscription needed</b>\n\nThese plans were re-enabled by users or paid manually after an early cancel. Please open each in <a href="https://my.contabo.com">my.contabo.com</a> and tap <b>Resume Subscription</b> so next renewal can fire:\n\n${list}`
      bot.sendMessage(TELEGRAM_ADMIN_CHAT_ID, msg, { parse_mode: 'HTML', disable_web_page_preview: true }).catch(() => {})
    }

    if (cancelled || stillPending.length) log(`[VPS Drift] daily reconcile — backfill_cancelled=${cancelled}, uncancel_pending=${stillPending.length}`)
  } catch (err) {
    log('[VPS Drift] error: ' + (err.message || err))
  }
}

async function checkVPSPlansExpiryandPayment() {
  // Guard: Ensure database is initialized before proceeding
  if (!vpsPlansOf || typeof vpsPlansOf.find !== 'function') {
    console.log('[VPS Scheduler] Database not ready yet, skipping check')
    return
  }

  const now = new Date()
  const oneDayFromNow = new Date(now.getTime() + 1 * 24 * 60 * 60 * 1000)
  const threeDaysFromNow = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000)

  try {
    // ═══════════════════════════════════════════════════════════════
    // Phase 1: AUTO-RENEW — 1 day before expiry (end_time within next 24h)
    // Uses smartWalletDeduct (USD → NGN fallback, atomic)
    // ═══════════════════════════════════════════════════════════════
    const dueForRenewal = await vpsPlansOf.find({
      'end_time': { $lte: oneDayFromNow, $gt: now },
      'status': { $in: ['RUNNING', 'running'] },
      '_autoRenewAttempted': { $ne: true }
    }).toArray()

    for (const vpsPlan of dueForRenewal) {
      const { chatId, _id, planPrice, vpsId, label, autoRenewable, contaboInstanceId } = vpsPlan
      const info = await state.findOne({ _id: String(chatId) })
      const lang = info?.userLanguage || 'en'
      const displayName = label || vpsPlan.name || 'VPS'
      const expiryDate = new Date(vpsPlan.end_time).toLocaleDateString()

      if (!autoRenewable) {
        // Auto-renew disabled — mark as pending cancellation, warn user
        await vpsPlansOf.updateOne({ _id }, { $set: { status: 'PENDING_CANCELLATION', _autoRenewAttempted: true } })
        try { send(chatId, translation('t.util_1', lang, displayName, expiryDate)) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
        log(`[VPS Scheduler] ${displayName} marked PENDING_CANCELLATION for ${chatId} — auto-renew disabled`)
        // ── BUG-B FIX: cancel on Contabo IMMEDIATELY (24h before expiry) ──
        // Contabo bills monthly contracts in advance; waiting until the 5h
        // pre-emptive cancel (Phase 1.5) was too late and caused €30+ leak
        // charges (cancelDate landed one period later instead of at end_time).
        if (!vpsPlan._contaboCancelledEarly) {
          try {
            const cancelResult = await deleteVPSinstance(chatId, vpsId)
            if (cancelResult && cancelResult.success) {
              await vpsPlansOf.updateOne({ _id }, { $set: { _contaboCancelledEarly: true, status: 'CANCELLED', cancelledAt: new Date(), cancelReason: 'auto_renew_disabled', contaboCancelDate: cancelResult.cancelDate } })
              log(`[VPS Scheduler] EARLY CANCEL on Contabo for ${displayName} (auto-renew off) — cancelDate=${cancelResult.cancelDate}`)
            } else {
              log(`[VPS Scheduler] EARLY CANCEL non-success for ${displayName}: ${(cancelResult && cancelResult.error) || 'unknown'}`)
            }
          } catch (cancelErr) {
            log(`[VPS Scheduler] EARLY CANCEL crash for ${displayName}: ${cancelErr.message}`)
          }
        }
        continue
      }

      // Try to charge wallet: USD first, then NGN
      const deductResult = await smartWalletDeduct(walletOf, chatId, Number(planPrice))

      if (deductResult.success) {
        // Renew: extend by 1 month
        const newEnd = new Date(vpsPlan.end_time)
        newEnd.setMonth(newEnd.getMonth() + 1)

        await vpsPlansOf.updateOne({ _id }, {
          $set: { end_time: newEnd, status: 'RUNNING', _autoRenewAttempted: true, _reminder3DaySent: false, _reminder1DaySent: false }
        })
        const currSymbol = deductResult.currency === 'ngn' ? '₦' : '$'
        const chargedDisplay = deductResult.currency === 'ngn'
          ? `₦${Number(deductResult.chargedNgn).toFixed(2)} (≈ $${planPrice})`
          : `$${planPrice}`
        set(payments, nanoid(), `Wallet,VPSAutoRenew,Monthly,$${planPrice},${chatId},${new Date()},${deductResult.currency}`)

        const { usdBal: usd } = await getBalance(walletOf, chatId)
        try { send(chatId, translation('t.util_2', lang, displayName, chargedDisplay, deductResult.currency.toUpperCase(), newEnd.toLocaleDateString(), usd.toFixed(2), '0.00')) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
        log(`[VPS Scheduler] Auto-renewed ${displayName} for ${chatId}, charged ${deductResult.currency} $${planPrice}`)
      } else {
        // Both USD and NGN failed — mark pending cancellation
        await vpsPlansOf.updateOne({ _id }, { $set: { status: 'PENDING_CANCELLATION', _autoRenewAttempted: true } })
        const { usdBal } = deductResult
        try { send(chatId, translation('t.util_3', lang, displayName, (usdBal || 0).toFixed(2), planPrice, expiryDate)) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
        send(TELEGRAM_ADMIN_CHAT_ID, `⚠️ <b>VPS Renewal Failed</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName}\nPrice: $${planPrice}\nBalance: $${(usdBal || 0).toFixed(2)}`, adminMsgOpts({ chatId }))
        log(`[VPS Scheduler] ${displayName} PENDING_CANCELLATION for ${chatId} — balance insufficient ($${usdBal || 0} < $${planPrice})`)
        // ── BUG-B FIX (extended): cancel on Contabo IMMEDIATELY at wallet-fail.
        // Contabo pre-bills the next period ~4 days BEFORE end_time, which is
        // earlier than the old Phase 1.5 trigger (T-5h) — so without this we
        // get charged for the next month before the safety net fires.
        // Phase 1.5 is kept as a redundant retry for any record this misses.
        if (!vpsPlan._contaboCancelledEarly) {
          try {
            const cancelResult = await deleteVPSinstance(chatId, vpsId)
            if (cancelResult && cancelResult.success) {
              await vpsPlansOf.updateOne({ _id }, { $set: { _contaboCancelledEarly: true, status: 'CANCELLED', cancelledAt: new Date(), cancelReason: 'wallet_deduct_failed', contaboCancelDate: cancelResult.cancelDate } })
              log(`[VPS Scheduler] EARLY CANCEL on Contabo for ${displayName} (wallet fail) — cancelDate=${cancelResult.cancelDate}`)
            } else {
              log(`[VPS Scheduler] EARLY CANCEL (wallet fail) non-success for ${displayName}: ${(cancelResult && cancelResult.error) || 'unknown'} — Phase 1.5 will retry`)
            }
          } catch (cancelErr) {
            log(`[VPS Scheduler] EARLY CANCEL (wallet fail) crash for ${displayName}: ${cancelErr.message} — Phase 1.5 will retry`)
          }
        }
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 1.5: PRE-EMPTIVE CONTABO CANCELLATION — 5 hours before expiry
    // If auto-renew failed (PENDING_CANCELLATION) and expiry is within 5 hours,
    // cancel on Contabo NOW to prevent their auto-billing/renewal
    // ═══════════════════════════════════════════════════════════════
    const fiveHoursFromNow = new Date(now.getTime() + 5 * 60 * 60 * 1000)
    const urgentCancellations = await vpsPlansOf.find({
      'end_time': { $lte: fiveHoursFromNow, $gt: now },
      'status': 'PENDING_CANCELLATION',
      '_contaboCancelledEarly': { $ne: true }
    }).toArray()

    for (const vpsPlan of urgentCancellations) {
      const { chatId, _id, vpsId, label, contaboInstanceId, planPrice } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const hoursLeft = ((new Date(vpsPlan.end_time).getTime() - now.getTime()) / (1000 * 60 * 60)).toFixed(1)
      const _info = await state.findOne({ _id: String(chatId) })
      const lang = _info?.userLanguage || 'en'

      try {
        // Cancel on Contabo early to prevent their auto-renewal billing
        const cancelResult = await deleteVPSinstance(chatId, vpsId)
        if (cancelResult.success) {
          await vpsPlansOf.updateOne({ _id }, { $set: { _contaboCancelledEarly: true, status: 'CANCELLED', cancelledAt: new Date(), cancelReason: 'pre_emptive_no_payment' } })
          try { send(chatId, translation('t.util_4', lang, displayName)) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
          bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID, `🛑 <b>VPS Pre-emptive Cancel</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName}\nContabo ID: ${contaboInstanceId || vpsId}\nHours before expiry: ${hoursLeft}h\nPrice: $${planPrice}/mo\n\n✅ Cancelled on Contabo to prevent their billing.`, adminMsgOpts({ chatId })).catch(() => {})
          log(`[VPS Scheduler] PRE-EMPTIVE CANCEL: ${displayName} for ${chatId} — ${hoursLeft}h before expiry`)
        } else {
          // Cancel failed — alert admin urgently
          bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID,
            `🚨🚨 <b>URGENT: VPS Cancel FAILED — ${hoursLeft}h to Contabo billing!</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName}\nContabo ID: ${contaboInstanceId || vpsId}\nError: ${cancelResult.error}\n\n⚠️ <b>MANUAL ACTION REQUIRED on Contabo dashboard to prevent billing!</b>`,
            adminMsgOpts({ chatId })
          ).catch(err => {
            log(`[VPS] CRITICAL: Failed to notify admin about VPS cancel failure for ${chatId}: ${err.message}`)
          })
          log(`[VPS Scheduler] PRE-EMPTIVE CANCEL FAILED: ${displayName} — ${cancelResult.error}`)
        }
      } catch (err) {
        bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID,
          `🚨🚨 <b>URGENT: VPS Cancel CRASH — ${hoursLeft}h to Contabo billing!</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName}\nContabo ID: ${contaboInstanceId || vpsId}\nError: ${err.message}\n\n⚠️ <b>MANUAL ACTION REQUIRED!</b>`,
          adminMsgOpts({ chatId })
        ).catch(notifyErr => {
          log(`[VPS] CRITICAL: Failed to notify admin about VPS cancel crash for ${chatId}: ${notifyErr.message}`)
        })
        log(`[VPS Scheduler] PRE-EMPTIVE CANCEL CRASH: ${displayName} — ${err.message}`)
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 1.6: ESCALATING ADMIN NOTIFICATIONS — 24h countdown for unpaid VPS
    // Notify admin at 24h, 12h, 6h, 3h, 1h before expiry for PENDING_CANCELLATION
    // ═══════════════════════════════════════════════════════════════
    const pendingVps = await vpsPlansOf.find({
      'end_time': { $lte: oneDayFromNow, $gt: fiveHoursFromNow },
      'status': 'PENDING_CANCELLATION'
    }).toArray()

    for (const vpsPlan of pendingVps) {
      const { chatId, _id, label, contaboInstanceId, planPrice, end_time } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const hoursLeft = (new Date(end_time).getTime() - now.getTime()) / (1000 * 60 * 60)
      const notifySent = vpsPlan._adminNotifyHistory || []

      // Determine which notification tier to send
      const tiers = [
        { hours: 24, key: '24h', emoji: '⏰' },
        { hours: 12, key: '12h', emoji: '⚠️' },
        { hours: 6,  key: '6h',  emoji: '🚨' },
      ]

      for (const tier of tiers) {
        if (hoursLeft <= tier.hours && !notifySent.includes(tier.key)) {
          const { usdBal } = await getBalance(walletOf, chatId)
          const shortfall = (planPrice - usdBal).toFixed(2)
          bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID,
            `${tier.emoji} <b>VPS Renewal Alert — ${tier.key} remaining</b>\n` +
            `\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName}\nContabo ID: ${contaboInstanceId || vpsPlan.vpsId}\n` +
            `Price: $${planPrice}/mo\nUser balance: $${usdBal.toFixed(2)} (short: $${shortfall})\n` +
            `Expires: ${new Date(end_time).toLocaleString()}\n` +
            `\n${hoursLeft <= 6 ? '🛑 <b>Will be auto-cancelled on Contabo at 5h mark if unpaid!</b>' : '💡 User has been notified. No action needed yet.'}`,
            adminMsgOpts({ chatId })
          ).catch(() => {})
          await vpsPlansOf.updateOne({ _id }, { $push: { _adminNotifyHistory: tier.key } })
          log(`[VPS Scheduler] Admin ${tier.key} notification for ${displayName} (${chatId}) — ${hoursLeft.toFixed(1)}h left`)
          break // only send one notification per cycle
        }
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 2: DELETE on Contabo — VPS past deadline with failed renewal
    // PENDING_CANCELLATION + end_time <= now → cancel on Contabo + mark CANCELLED
    // ═══════════════════════════════════════════════════════════════
    const pastDeadline = await vpsPlansOf.find({
      'end_time': { $lte: now },
      'status': 'PENDING_CANCELLATION'
    }).toArray()

    for (const vpsPlan of pastDeadline) {
      const { chatId, _id, vpsId, label, contaboInstanceId, planPrice } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const info = await state.findOne({ _id: String(chatId) })
      const lang = info?.userLanguage || 'en'

      try {
        // Delete from Contabo to prevent their billing
        const deleteResult = await deleteVPSinstance(chatId, vpsId)
        if (deleteResult.success) {
          await vpsPlansOf.updateOne({ _id }, { $set: { status: 'CANCELLED', cancelledAt: new Date(), cancelReason: 'auto_renewal_failed' } })
          try { send(chatId, translation('t.util_5', lang, displayName)) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
          send(TELEGRAM_ADMIN_CHAT_ID, `🗑️ <b>VPS Auto-Deleted</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName}\nReason: Renewal failed, deadline passed\nPrice was: $${planPrice}/mo`, adminMsgOpts({ chatId }))
          log(`[VPS Scheduler] DELETED ${displayName} on Contabo for ${chatId} — deadline passed`)
        } else {
          // Delete failed — retry next cycle, alert admin
          log(`[VPS Scheduler] ERROR: Failed to delete ${displayName} on Contabo: ${deleteResult.error}`)
          send(TELEGRAM_ADMIN_CHAT_ID, `🚨 <b>VPS DELETE FAILED</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName} (vpsId: ${vpsId})\nInstance ID: ${contaboInstanceId}\nError: ${deleteResult.error}\n\n⚠️ Manual deletion required to prevent provider billing!`, adminMsgOpts({ chatId }))
        }
      } catch (err) {
        log(`[VPS Scheduler] CRASH deleting ${displayName}: ${err.message}`)
        send(TELEGRAM_ADMIN_CHAT_ID, `🚨 <b>VPS Delete Crash</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nVPS: ${displayName}\nError: ${err.message}`, adminMsgOpts({ chatId }))
      }
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 3: Also handle any VPS that are RUNNING but past expiry
    // (edge case: old records before this update, or missed scheduler runs)
    // ═══════════════════════════════════════════════════════════════
    const staleExpired = await vpsPlansOf.find({
      'end_time': { $lte: now },
      'status': { $in: ['RUNNING', 'running'] },
      '_autoRenewAttempted': { $ne: true }
    }).toArray()

    for (const vpsPlan of staleExpired) {
      const { chatId, _id, planPrice, vpsId, label, autoRenewable } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const info = await state.findOne({ _id: String(chatId) })
      const lang = info?.userLanguage || 'en'

      // Try one last renewal attempt
      if (autoRenewable) {
        const deductResult = await smartWalletDeduct(walletOf, chatId, Number(planPrice))
        if (deductResult.success) {
          const newEnd = new Date(now)
          newEnd.setMonth(newEnd.getMonth() + 1)
          await vpsPlansOf.updateOne({ _id }, {
            $set: { end_time: newEnd, status: 'RUNNING', _autoRenewAttempted: true, _reminder3DaySent: false, _reminder1DaySent: false }
          })
          const chargedDisplay = deductResult.currency === 'ngn'
            ? `₦${Number(deductResult.chargedNgn).toFixed(2)} (≈ $${planPrice})`
            : `$${planPrice}`
          set(payments, nanoid(), `Wallet,VPSAutoRenew,Monthly,$${planPrice},${chatId},${new Date()},${deductResult.currency}`)
          const { usdBal: usd } = await getBalance(walletOf, chatId)
          try { send(chatId, translation('t.util_6', lang, displayName, chargedDisplay, newEnd.toLocaleDateString(), usd.toFixed(2), '0.00')) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
          log(`[VPS Scheduler] Late auto-renewed ${displayName} for ${chatId}`)
          continue
        }
      }
      // Failed or auto-renew off — mark pending cancellation (will be deleted next cycle)
      await vpsPlansOf.updateOne({ _id }, { $set: { status: 'PENDING_CANCELLATION', _autoRenewAttempted: true } })
      const { usdBal } = await getBalance(walletOf, chatId)
      try { send(chatId, translation('t.util_7', lang, displayName, (usdBal).toFixed(2))) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
      log(`[VPS Scheduler] ${displayName} marked PENDING_CANCELLATION (stale) for ${chatId}`)
    }

    // ═══════════════════════════════════════════════════════════════
    // Phase 4: Pre-expiry reminders with wallet balance info
    // ═══════════════════════════════════════════════════════════════
    const soonExpiring = await vpsPlansOf.find({
      'end_time': { $lte: threeDaysFromNow, $gt: oneDayFromNow },
      'status': { $in: ['RUNNING', 'running'] }
    }).toArray()

    for (const vpsPlan of soonExpiring) {
      const { chatId, _id, label, end_time, planPrice } = vpsPlan
      const displayName = label || vpsPlan.name || 'VPS'
      const msLeft = new Date(end_time).getTime() - now.getTime()
      const daysLeft = msLeft / (1000 * 60 * 60 * 24)
      const expiryDate = new Date(end_time).toLocaleDateString()
      const _info = await state.findOne({ _id: String(chatId) })
      const lang = _info?.userLanguage || 'en'

      // 3-day reminder
      if (daysLeft > 2.5 && daysLeft <= 3.1 && !vpsPlan._reminder3DaySent) {
        const { usdBal } = await getBalance(walletOf, chatId)
        const sufficient = usdBal >= planPrice
        const statusIcon = sufficient ? '✅' : '⚠️'
        try { send(chatId, translation('t.util_8', lang, displayName, expiryDate, planPrice, usdBal.toFixed(2), statusIcon, sufficient ? 'Auto-renewal will be attempted 1 day before expiry.' : 'Insufficient balance — top up or renew manually to keep your server!')) } catch (notifErr) { log(`[VPS Scheduler] notify failed: ${notifErr.message}`) }
        await vpsPlansOf.updateOne({ _id }, { $set: { _reminder3DaySent: true } })
        log(`[VPS Scheduler] 3-day reminder sent to ${chatId} for ${displayName}`)
      }
    }
  } catch (error) {
    console.error('[VPS Scheduler] Error:', error.message || error)
  }
}

const buyVPSPlanFullProcess = async (chatId, lang, vpsDetails) => {
  try {
    // Create progress tracker for VPS provisioning
    const progress = createProgressTracker(bot, chatId,
      { en: 'VPS Setup', fr: 'Configuration VPS', zh: 'VPS 设置', hi: 'VPS सेटअप' }[lang] || 'VPS Setup',
      [
        { en: 'Creating instance', fr: 'Création instance', zh: '创建实例', hi: 'इंस्टेंस बना रहे हैं' }[lang] || 'Creating instance',
        { en: 'Assigning IP address', fr: 'Attribution IP', zh: '分配 IP 地址', hi: 'IP पता आवंटित कर रहे हैं' }[lang] || 'Assigning IP address',
        { en: 'Installing OS', fr: 'Installation OS', zh: '安装操作系统', hi: 'OS इंस्टॉल कर रहे हैं' }[lang] || 'Installing OS',
        { en: 'Configuring access', fr: 'Configuration accès', zh: '配置访问', hi: 'एक्सेस कॉन्फ़िगर कर रहे हैं' }[lang] || 'Configuring access',
        { en: 'Finalizing setup', fr: 'Finalisation', zh: '完成设置', hi: 'सेटअप समाप्त कर रहे हैं' }[lang] || 'Finalizing setup'
      ]
    )
    
    await progress.startStep(1)
    const vmInstance = await createVPSInstance(chatId, vpsDetails)
    if (!vmInstance.success) {
      const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.plan)
      log(m)
      sendMessage(TELEGRAM_DEV_CHAT_ID, m)
      sendMessage(chatId, m)
      return false
    }
    await progress.completeStep(1)
    
    const { data: vpsData } = vmInstance
    let info = await get(state, chatId)

    // NOTE: vm-instance-setup.js already inserts into vpsPlansOf during createVPSInstance.
    // No duplicate insert needed here.

    // For Contabo, SSH keys are attached at creation time (no separate step needed).
    // Just wait for the instance to provision and get an IP.
    await progress.startStep(2)

    // Poll for the real IP address (Contabo takes ~30-60s to assign one)
    let resolvedIp = vpsData.host
    if (!resolvedIp || resolvedIp === 'provisioning...' || resolvedIp === 'pending') {
      const contaboService = require('./contabo-service.js')
      const maxAttempts = 6
      for (let attempt = 1; attempt <= maxAttempts; attempt++) {
        await sleep(15000) // wait 15s between each poll
        try {
          const details = await contaboService.getInstance(vpsData.contaboInstanceId || vpsData._id)
          const ip = details?.ipConfig?.v4?.ip || details?.ipv4 || null
          if (ip && ip !== 'provisioning...' && ip !== 'pending' && ip !== '0.0.0.0') {
            resolvedIp = ip
            console.log(`[VPS] IP resolved after ${attempt} attempts: ${ip}`)
            // Update stored record with the real IP
            if (typeof _vpsPlansOf !== 'undefined' && _vpsPlansOf) {
              await _vpsPlansOf.updateOne(
                { contaboInstanceId: parseInt(vpsData.contaboInstanceId || vpsData._id) },
                { $set: { host: ip } }
              )
            }
            break
          }
          console.log(`[VPS] IP poll attempt ${attempt}/${maxAttempts} — still provisioning...`)
        } catch (err) {
          console.log(`[VPS] IP poll attempt ${attempt} error: ${err.message}`)
        }
      }
      vpsData.host = resolvedIp
      await progress.completeStep(2)
    } else {
      await sleep(15000)
      await progress.completeStep(2)
    }

    // Step 3: OS Installation (already happening in background)
    await progress.startStep(3)
    await sleep(10000) // Simulated OS install time
    await progress.completeStep(3)
    
    // Step 4: Configuring access
    await progress.startStep(4)

    // Credentials are returned directly from createVPSInstance for Contabo
    const credentials = vpsData.credentials || { username: vpsData.isRDP ? 'Administrator' : 'root', password: 'Check email' }

    // Generate transaction ID for VPS purchase
    const txnId = generateTransactionId()
    try {
      await logTransaction(db, {
        transactionId: txnId,
        chatId,
        type: 'vps',
        amount: vpsDetails.totalPrice || 0,
        currency: 'USD',
        status: 'completed',
        metadata: { plan: vpsDetails.plan, host: vpsData.host, region: vpsDetails.region }
      })
    } catch (txErr) {
      log('[VPS] Failed to log transaction (non-blocking):', txErr.message)
    }
    await progress.completeStep(4)

    // Step 5: Finalizing
    await progress.startStep(5)
    set(state, info._id, 'action', 'none')
    const vpsSuccessMsg = translation('vp.vpsBoughtSuccess', lang, vpsDetails, vpsData, credentials) + 
      `\n\n<b>Transaction ID:</b> <code>${txnId}</code>\n<i>Quote this ID when contacting support</i>`
    send(chatId, vpsSuccessMsg, translation('o', lang))
    await progress.complete({ en: '🎉 VPS ready!', fr: '🎉 VPS prêt !', zh: '🎉 VPS 就绪！', hi: '🎉 VPS तैयार!' }[lang] || '🎉 VPS ready!')
    try {
      await sendVPSCredentialsEmail(info, vpsData, vpsDetails, credentials)
    } catch (error) {
      log('Error sending email:', error)
      send(TELEGRAM_DEV_CHAT_ID, 'Error sending email', translation('o'))
    }

    // ── Phase 6: Notify admin group about VPS purchase ──
    try {
      const name = await get(nameOf, chatId)
      const isRDP = vpsData.isRDP || vpsDetails.isRDP || false
      const planType = isRDP ? 'RDP' : 'VPS'
      const regionStr = vpsDetails.region ? ` in <b>${vpsDetails.region}</b>` : ''
      notifyGroup(
        `🖥 <b>New ${planType} Deployed!</b>\nUser ${maskName(name)} just deployed a <b>${vpsDetails.plan || 'Cloud VPS'}</b> server${regionStr}.\nGet yours — /start`,
        `🖥 <b>VPS Purchase</b>\n👤 ${adminUserTag(name, chatId)}\n📦 ${vpsDetails.plan || 'Cloud VPS'}${regionStr}\n💰 $${vpsDetails.totalPrice}\n🖥 IP: ${vpsData.host || 'pending'}`
      )
    } catch (e) {
      log('[VPS] notifyGroup error: ' + e.message)
    }

    return true
  } catch (error) {
    const errorMessage = `err buyVPSPlanFullProcess ${error?.message} ${safeStringify(error?.response?.data)}`
    const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.plan)
    sendMessage(chatId, m)
    sendMessage(TELEGRAM_DEV_CHAT_ID, errorMessage)
    console.error(errorMessage)
    return false
  }
}

const upgradeVPSDetails = async (chatId, lang, vpsDetails) => {
  try {
    log(vpsDetails)
    const vmInstanceDetails = await fetchVPSDetails(chatId, vpsDetails._id)
    if (!vmInstanceDetails) {
      const m = translation('vp.errorUpgradingVPS', lang, vpsDetails.name)
      log(m)
      sendMessage(TELEGRAM_DEV_CHAT_ID, m)
      sendMessage(chatId, m)
      return false
    }
    let vmInstanceUpgrade;
    let message = ''
    switch (vpsDetails.upgradeType) {
      case 'plan':
        vmInstanceUpgrade = await upgradeVPSPlanType(chatId, vpsDetails)
        if (vmInstanceUpgrade.success) {
          await vpsPlansOf.updateOne(
            { vpsId: vpsDetails._id },
            { $set: { 'planPrice': vmInstanceUpgrade.data.price } },
          )
        }
        message = translation('vp.vpsUpgradePlanTypeSuccess', lang, vpsDetails)
        break;
      case 'disk':
        vmInstanceUpgrade = await upgradeVPSDiskType(chatId, vpsDetails)
        if (vmInstanceUpgrade.success) {
          await vpsPlansOf.updateOne(
            { vpsId: vpsDetails._id },
            { $set: { 'planPrice': vmInstanceUpgrade.data.subscription.price } },
          )
        }
        message = translation('vp.vpsUpgradeDiskTypeSuccess', lang, vpsDetails)
        break;
      case 'vps-renew':
        vmInstanceUpgrade = await renewVPSPlan(chatId, vmInstanceDetails.subscription_id)
        if (vmInstanceUpgrade.success) {
          await vpsPlansOf.updateOne(
            { vpsId: vpsDetails._id },
            { $set: { 
              'end_time': new Date(vmInstanceUpgrade.data.subscriptionEnd), 
              'status': 'RUNNING'
            }},
          )
          const expiryDate = date(vmInstanceUpgrade.data.subscriptionEnd)
          message = translation('vp.vpsRenewPlanSuccess', lang, vmInstanceDetails, expiryDate)
          // Background admin alert when the renewal was for a plan that had
          // already been cancelled early on Contabo. The customer's UX is
          // unchanged (they see the new expiry date); admin needs to click
          // "Resume Subscription" on my.contabo.com so the next cycle bills.
          if (vmInstanceUpgrade.needsContaboUncancel) {
            try {
              const userTag = adminUserTag(await get(nameOf, chatId), chatId)
              bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID,
                `🔄 <b>Contabo Resume Subscription needed</b>\nUser: ${userTag}\nInstance: <code>${vmInstanceUpgrade.contaboInstanceId}</code>\nAction: manual renewal received on an early-cancelled VPS.\n\nPlease open my.contabo.com → instance ${vmInstanceUpgrade.contaboInstanceId} → Resume Subscription so the next renewal can fire.`,
                adminMsgOpts({ chatId })
              ).catch(() => {})
            } catch (_) {}
          }
        }
        break;
      case 'vps-cPanel-renew':
        // cPanel not available with Contabo
        vmInstanceUpgrade = { success: false, error: 'cPanel not available with current VPS provider' }
        break;
      default:
        break;
    }
    if (!vmInstanceUpgrade?.success) {
      const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.name)
      log(m)
      sendMessage(TELEGRAM_DEV_CHAT_ID, m)
      sendMessage(chatId, m)
      return false
    }

    await set(state, chatId, 'action', 'none')
    send(chatId, message, translation('o', lang))

    // ── Phase 6: Notify admin group about VPS upgrade/renewal ──
    try {
      const name = await get(nameOf, chatId)
      const upgradeLabel = vpsDetails.upgradeType === 'plan' ? 'Plan Upgrade' : vpsDetails.upgradeType === 'disk' ? 'Disk Upgrade' : vpsDetails.upgradeType === 'vps-renew' ? 'Renewal' : 'Update'
      notifyGroup(
        `⬆️ <b>VPS ${upgradeLabel}!</b>\nUser ${maskName(name)} just ${vpsDetails.upgradeType === 'vps-renew' ? 'renewed' : 'upgraded'} their VPS.\nManage yours — /start`,
        `⬆️ <b>VPS ${upgradeLabel}</b>\n👤 ${adminUserTag(name, chatId)}\n📦 ${vpsDetails.name || 'VPS'}\n💰 $${vpsDetails.totalPrice}`
      )
    } catch (e) {
      log('[VPS] upgrade notifyGroup error: ' + e.message)
    }

    return true
  } catch (error) {
    const errorMessage = `err buyUPgradingVPSProcess ${error?.message} ${safeStringify(error?.response?.data)}`
    const m = translation('vp.errorPurchasingVPS', lang, vpsDetails.name)
    sendMessage(chatId, m)
    sendMessage(TELEGRAM_DEV_CHAT_ID, errorMessage)
    console.error(errorMessage)
    return false
  }
}

// ── Cloud IVR DB helpers ──

// Audit-trail helper for crypto PSP webhook callbacks (BlockBee + DynoPay).
// Writes a row to the universal `transactions` ledger so every crypto-paid
// product purchase can be reconciled alongside wallet-paid flows that
// already call logTransaction() inline. Designed to be non-blocking — a
// DB failure here must never strand a user who has already paid + been
// provisioned. See the Apr-30-2026 audit-trail sweep for context.
async function auditCryptoTx(chatId, type, amount, metadata, psp) {
  try {
    await logTransaction(db, {
      transactionId: generateTransactionId(),
      chatId,
      type,
      amount,
      currency: 'USD',
      status: 'completed',
      metadata: { ...(metadata || {}), psp },
    })
  } catch (txErr) {
    log(`[Audit] Failed to log ${psp} ${type} transaction (non-blocking): ${txErr.message}`)
  }
}

// Shared function to apply a phone plan upgrade — used by wallet, crypto, and bank payment paths
async function applyPhonePlanUpgrade(chatId, num, newPlan, newPrice, lang, paymentMethod, upgradeData) {
  const oldPlan = num.plan
  const oldPrice = num.planPrice
  await updatePhoneNumberField(phoneNumbersOf, chatId, num.phoneNumber, 'plan', newPlan)
  await updatePhoneNumberField(phoneNumbersOf, chatId, num.phoneNumber, 'planPrice', newPrice)
  num.plan = newPlan
  num.planPrice = newPrice

  // Re-enable SIP if upgrading to a plan that supports it
  if (phoneConfig.canAccessFeature(newPlan, 'sipCredentials') && num.sipDisabled) {
    await updatePhoneNumberField(phoneNumbersOf, chatId, num.phoneNumber, 'sipDisabled', false)
    num.sipDisabled = false
  }

  const info = await state.findOne({ _id: String(chatId) })
  await set(state, chatId, 'cpActiveNumber', num)
  await set(state, chatId, 'cpPendingPlan', null)
  await set(state, chatId, 'cpUpgradeData', null)

  // ── Audit-trail: log the upgrade to phoneTransactions ──
  // Fixes the Apr-30-2026 gap where crypto/wallet/bank upgrades left no record
  // in phoneTransactions (reconciliation hole discovered when @fuckthisapp's
  // $62.50 Pro upgrade had zero row in the collection). We capture the actual
  // charge + credit breakdown so reconciliation can distinguish credited
  // upgrades from full-price ones.
  const chargeAmount = Number.isFinite(upgradeData?.chargeAmount) ? upgradeData.chargeAmount : newPrice
  const credit = Number.isFinite(upgradeData?.credit) ? upgradeData.credit : 0
  const eligibleForCredit = upgradeData?.eligibleForCredit === true
  try {
    await phoneTransactions.insertOne({
      chatId,
      phoneNumber: num.phoneNumber,
      action: 'upgrade',
      oldPlan,
      newPlan,
      oldPrice,
      newPrice,
      amount: chargeAmount.toFixed(2),
      credit: credit.toFixed(2),
      eligibleForCredit,
      paymentMethod,
      timestamp: new Date().toISOString(),
    })
  } catch (e) {
    log(`[CloudPhone] phoneTransactions.insertOne failed for upgrade ${chatId}/${num.phoneNumber}: ${e.message}`)
  }

  const m = phoneConfig.getMsg(lang)
  const confirmMsg = `✅ <b>Plan Upgraded!</b>\n\n📦 New plan: <b>${newPlan.charAt(0).toUpperCase() + newPlan.slice(1)}</b> ($${newPrice}/mo)\n💳 Paid via: ${paymentMethod}\n\nYour new features are now active!`
  sendMessage(chatId, confirmMsg, { parse_mode: 'HTML' })
  const name = await get(nameOf, chatId)
  notifyGroup(
    `⬆️ <b>Plan Upgrade!</b>\nUser ${maskName(name)} upgraded to <b>${newPlan.charAt(0).toUpperCase() + newPlan.slice(1)}</b> — /start`,
    `⬆️ <b>Phone Plan Upgrade</b>\n👤 ${adminUserTag(name, chatId)}\n📞 Number: ${num.phoneNumber}\n📦 ${oldPlan.charAt(0).toUpperCase() + oldPlan.slice(1)} → <b>${newPlan.charAt(0).toUpperCase() + newPlan.slice(1)}</b>\n💵 Charged: <b>$${chargeAmount.toFixed(2)}</b>${credit > 0 ? ` (credit -$${credit.toFixed(2)})` : ''}\n📅 New renewal: $${newPrice}/mo\n💳 Payment: ${paymentMethod}`
  )

  await set(state, chatId, 'action', 'none')
  // Log the ACTUAL charge (what the user paid) rather than the plan's sticker
  // price — avoids the Apr-30 ambiguity where the log line read "$75" for an
  // upgrade that was actually billed at $62.50 (25% credit).
  log(`[CloudPhone] Plan upgraded for ${chatId}: ${num.phoneNumber} ${oldPlan}→${newPlan} charged $${chargeAmount.toFixed(2)}${credit > 0 ? ` (credit -$${credit.toFixed(2)})` : ''} via ${paymentMethod}`)
}

async function updatePhoneNumberFeature(col, chatId, phoneNumber, featureKey, value) {
  // Fully atomic positional $set — never rewrite the whole numbers array
  // (prior read-modify-write pattern could race with concurrent feature edits
  // and wipe IVR/voicemail/forwarding settings saved moments earlier).
  // MongoDB auto-creates nested paths, so `features.<key>` works even if features is missing.
  // Stamp updatedAt so the Manage screen can show "Last changed: X ago".
  await col.updateOne(
    { _id: chatId, 'val.numbers.phoneNumber': phoneNumber },
    { $set: {
      [`val.numbers.$.features.${featureKey}`]: value,
      'val.numbers.$.updatedAt': new Date().toISOString(),
    } }
  )
}

async function updatePhoneNumberField(col, chatId, phoneNumber, fieldKey, value) {
  // Fully atomic positional $set — see updatePhoneNumberFeature for context.
  // Skip updatedAt stamp for purely-internal bookkeeping fields that auto-tick every call/SMS
  // (otherwise every inbound SMS would reset the "Last changed" timestamp).
  const INTERNAL_FIELDS = new Set(['smsUsed', 'minutesUsed', '_smsLimitNotified', '_minLimitNotified', 'lastCallAt', 'lastSmsAt'])
  const setObj = { [`val.numbers.$.${fieldKey}`]: value }
  if (!INTERNAL_FIELDS.has(fieldKey)) {
    setObj['val.numbers.$.updatedAt'] = new Date().toISOString()
  }
  await col.updateOne(
    { _id: chatId, 'val.numbers.phoneNumber': phoneNumber },
    { $set: setObj }
  )
}

const auth = async (req, res, next) => {
  log(req.hostname + req.originalUrl)
  // Fincra webhooks: merchantReference = our nanoid ref; reference = Fincra's own fcr-p-xxx
  // Crypto callbacks: ref is in query string
  const ref = req?.query?.ref || req?.body?.data?.merchantReference || req?.body?.data?.reference
  log('[auth] Resolved ref:', ref, '| merchantRef:', req?.body?.data?.merchantReference, '| fincraRef:', req?.body?.data?.reference, '| queryRef:', req?.query?.ref)
  const pay = await get(chatIdOfPayment, ref)
  if (!pay) {
    // Check if this ref was already processed (stale/duplicate webhook)
    const existingPayment = ref ? await get(payments, ref) : null
    if (existingPayment) {
      log(`[auth] ℹ️ Payment ref ${ref} already processed (stale/duplicate webhook) — ignoring safely`)
    } else {
      log(`[auth] ⚠️ Payment session NOT FOUND for ref: ${ref} — no matching active session or historical record`)
      // B4 fix: Log unmatched Fincra webhooks to DB for later investigation
      // This helps identify real missed payments vs stale webhooks
      try {
        if (isDbHealthy() && db) {
          const unmatchedWebhooks = db.collection('unmatchedFincraWebhooks')
          await unmatchedWebhooks.insertOne({
            ref,
            merchantReference: req?.body?.data?.merchantReference,
            fincraReference: req?.body?.data?.reference,
            amount: req?.body?.data?.amountReceived || req?.body?.data?.amount,
            currency: req?.body?.data?.currencyReceived || req?.body?.data?.currency,
            status: req?.body?.data?.status,
            receivedAt: new Date(),
            webhookBody: JSON.stringify(req?.body || {}).substring(0, 2000),
          })
          log(`[auth] B4: Logged unmatched Fincra webhook ref=${ref} to DB for investigation`)
        }
      } catch (dbErr) {
        log(`[auth] B4: Failed to log unmatched webhook: ${dbErr.message}`)
      }
    }
    return res.send(html(translation('t.payError', 'en')))
  }
  req.pay = { ...pay, ref }
  next()
}

// Track processed DynoPay payment IDs to prevent duplicate processing
const processedDynopayPayments = new Set()

// Track processed Fincra webhook refs to prevent duplicate processing
const processedFincraRefs = new Set()

// Map payment_id → refId from pending events, so confirmed/failed events (which lack meta_data) can find the session
const dynopayPaymentIdToRef = new Map()

const authDyno = async (req, res, next) => {
  log('=== DYNOPAY WEBHOOK RECEIVED ===')
  log('URL:', req.hostname + req.originalUrl)
  // Security: Only log non-sensitive fields from webhook payload
  const safeFields = { event: req.body?.event, status: req.body?.status, payment_id: req.body?.payment_id, currency: req.body?.currency }
  log('Webhook summary:', JSON.stringify(safeFields))
  
  const paymentId = req.body?.payment_id
  const event = req.body?.event || req.body?.status

  // ── PENDING events: Extract and store payment_id → refId mapping, then skip ──
  // DynoPay only sends meta_data.refId on pending events; confirmed/failed events lack it.
  // We store the mapping here so later confirmed events can look up the correct session.
  if (event === 'payment.pending' || req.body?.status === 'pending') {
    const pendingRef = req.body?.meta_data?.refId
    if (paymentId && pendingRef) {
      dynopayPaymentIdToRef.set(paymentId, pendingRef)
      log(`[DynoPay] Stored payment_id → refId mapping: ${paymentId} → ${pendingRef}`)
      // Auto-cleanup after 24 hours (some confirmed events arrive very late)
      setTimeout(() => dynopayPaymentIdToRef.delete(paymentId), 86400000)
    }
    log('Skipping pending payment event (stored mapping for future confirmed event)')
    return res.send(html('OK'))
  }

  // ── Skip failed events — only process confirmed payments ──
  if (event === 'payment.failed') {
    log(`[DynoPay] Skipping failed payment event (payment_id: ${paymentId})`)
    return res.send(html('OK'))
  }

  // ── UNDERPAID events: Store mapping + skip — wait for confirmed/settled with full amount ──
  // Processing underpaid events causes handlers to receive partial amounts, which often
  // leads to "sent less money" → wallet credit → no product delivered. Then the confirmed
  // event (with the full amount) is rejected as duplicate.
  if (event === 'payment.underpaid' || req.body?.status === 'underpaid') {
    const underpaidRef = req.body?.meta_data?.refId
    if (paymentId && underpaidRef && !dynopayPaymentIdToRef.has(paymentId)) {
      dynopayPaymentIdToRef.set(paymentId, underpaidRef)
      log(`[DynoPay] Stored underpaid mapping: ${paymentId} → ${underpaidRef}`)
      setTimeout(() => dynopayPaymentIdToRef.delete(paymentId), 86400000)
    }
    log(`[DynoPay] Skipping underpaid event — waiting for confirmed/settled (payment_id: ${paymentId})`)
    return res.send(html('OK'))
  }

  // Deduplicate by payment_id — DynoPay sends multiple webhooks per payment
  if (paymentId && processedDynopayPayments.has(paymentId)) {
    log(`[DynoPay] Duplicate webhook ignored for payment_id: ${paymentId}`)
    return res.send(html('OK'))
  }

  // ── Extract refId — try meta_data first, then fall back to stored mapping from pending event ──
  const { meta_data } = req.body
  let ref = meta_data?.refId
  
  if (!ref && paymentId) {
    ref = dynopayPaymentIdToRef.get(paymentId)
    if (ref) {
      log(`[DynoPay] Recovered refId from pending mapping: payment_id ${paymentId} → refId ${ref}`)
    }
  }
  
  log('Extracted refId:', ref)
  
  const pay = await get(chatIdOfDynopayPayment, ref)
  log('Payment data found for ref:', ref, '=', pay ? 'YES' : 'NO')
  
  if (!pay) {
    log(`[DynoPay] ⚠️ Payment session not found for ref: ${ref}, payment_id: ${paymentId} (event: ${event})`)
    // Alert admin about missed payment
    if (event === 'payment.confirmed' && bot && process.env.TELEGRAM_ADMIN_CHAT_ID) {
      const amount = req.body?.base_amount || req.body?.amount || '?'
      bot.sendMessage(process.env.TELEGRAM_ADMIN_CHAT_ID, 
        `⚠️ <b>Missed Payment Alert</b>\n\n💰 Confirmed payment of <b>$${amount}</b> could not be credited!\n🆔 payment_id: <code>${paymentId}</code>\n📝 refId: <code>${ref || 'missing'}</code>\n\nManual credit may be required.`, 
        { parse_mode: 'HTML' }
      ).catch(() => {})
    }
    return res.send(html('OK'))
  }

  // Mark as processed to block future duplicates
  if (paymentId) {
    processedDynopayPayments.add(paymentId)
    // Auto-cleanup after 1 hour to prevent memory leak
    setTimeout(() => processedDynopayPayments.delete(paymentId), 3600000)
    // Clean up the pending mapping as well
    dynopayPaymentIdToRef.delete(paymentId)
  }
  
  log('Payment session authenticated successfully:', pay)
  req.pay = { ...pay, ref }
  next()
}

