app.get('/crypto-pay-plan', auth, async (req, res) => {
  // Validate
  const { ref, chatId, price, plan } = req.pay
  const coin = req?.query?.coin
  const value = req?.query?.value_coin

  console.log({ method: '/crypto-pay-plan', ref, chatId, plan, price, coin, value })

  if (!ref || !chatId || !plan || !price || !coin || !value) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))

  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)

  // Logs
  del(chatIdOfPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,Plan,${plan},$${price},${chatId},${name},${new Date()},${value} ${coin}`)

  // Update Wallet
  const usdIn = await convert(value, coin, 'usd')
  const usdNeed = usdIn
  console.log(`usdIn ${usdIn}, usdNeed ${usdNeed}, Crypto, Plan, ${chatId}, ${name}`)
  if (usdNeed < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  console.log(`usdIn > price = ${usdIn > price}`)
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', usdIn - price, lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }

  // Subscribe Plan
  subscribePlan(planEndingTime, freeDomainNamesAvailableFor, planOf, chatId, plan, bot, lang, freeValidationsAvailableFor)

  // ── Universal-ledger audit (Apr-30-2026 sweep) ──
  // Previously the BlockBee bot-plan subscription webhook wrote NO row to
  // `transactions`, leaving ~$15-75/mo recurring revenue off the audit ledger
  // until the DynoPay equivalent (different PSP) was rolled out.
  try {
    await logTransaction(db, {
      transactionId: generateTransactionId(),
      chatId,
      type: 'plan-subscription',
      amount: price,
      currency: 'USD',
      status: 'completed',
      metadata: { plan, coin, value, ref, psp: 'blockbee' },
    })
  } catch (txErr) {
    log('[Plan] Failed to log BlockBee subscription transaction (non-blocking): ' + txErr.message)
  }

  notifyGroup(
    `💎 <b>New Subscription!</b>\nUser ${maskName(name)} just upgraded to the <b>${plan} Plan</b> — unlocking unlimited URL shortening + ${(freeValidationsOf[plan] || 0).toLocaleString()} phone validations.\nDon't miss out — /start`,
    `💎 <b>New Subscription (Crypto BlockBee)</b>\n👤 User: ${adminUserTag(name, chatId)}\n📦 Plan: <b>${plan}</b>\n💵 Paid: <b>$${usdIn}</b> (${value} ${coin})\n💳 Payment: Crypto BlockBee`
  )
  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  res.send(html())
})
app.get('/crypto-pay-domain', auth, async (req, res) => {
  // Validate
  const { ref, chatId, price, domain } = req.pay
  const coin = req?.query?.coin
  const value = req?.query?.value_coin
  if (!ref || !chatId || !domain || !price || !coin || !value) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)
  // Logs
  del(chatIdOfPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,Domain,${domain},$${price},${chatId},${name},${new Date()},${value} ${coin}`)

  // Update Wallet
  const usdIn = await convert(value, coin, 'usd')
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', usdIn - price, lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }

  // Buy Domain
  const error = await buyDomainFullProcess(chatId, lang, domain)
  if (error) {
    // Domain purchase failed after crypto payment received — credit wallet as refund
    try {
      addFundsTo(walletOf, chatId, 'usd', price, lang)
      sendMessage(chatId, trans('t.wh_2', domain, price))
      sendMessage(TELEGRAM_ADMIN_CHAT_ID, `🔄 <b>Auto-Refund (BlockBee Crypto→Domain)</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nDomain: ${domain}\nAmount: $${price}\nReason: buyDomainFullProcess failed`, adminMsgOpts({ chatId }))
      log(`[Domain] BlockBee crypto refund issued: ${chatId} | ${domain} | $${price}`)
    } catch (refundErr) {
      log(`[Domain] CRITICAL: BlockBee crypto refund failed for ${chatId}: ${refundErr.message}`)
      sendMessage(TELEGRAM_ADMIN_CHAT_ID, `🚨 CRITICAL: BlockBee crypto domain refund FAILED\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nDomain: ${domain}\nAmount: $${price}\nError: ${refundErr.message}`, adminMsgOpts({ chatId }))
    }
    return res.send(html('error'))
  }

  // Check for savings — cheaper registrar succeeded → credit difference to wallet
  const updatedInfo = await state.findOne({ _id: String(chatId) })
  const cheaperPrice = info?.cheaperPrice
  const fallbackOccurred = updatedInfo?.registrarFallback === true
  if (!fallbackOccurred && cheaperPrice && cheaperPrice < price) {
    const savingsUsd = price - cheaperPrice
    addFundsTo(walletOf, chatId, 'usd', savingsUsd, lang)
    sendMessage(chatId, trans('t.wh_3', savingsUsd, domain, cheaperPrice, price, savingsUsd), { parse_mode: 'HTML' })
    sendMessage(TELEGRAM_ADMIN_CHAT_ID, `💰 <b>Domain savings (BlockBee Crypto)</b>\nUser: ${adminUserTag(await get(nameOf, chatId), chatId)}\nDomain: ${domain}\nShown: $${price} | Actual: $${cheaperPrice} | Saved: $${savingsUsd}\nRegistrar: ${updatedInfo?.actualRegistrar || 'unknown'}`, adminMsgOpts({ chatId }))
  }

  // Clean up pricing state
  await set(state, chatId, 'actualPrice', null)
  await set(state, chatId, 'actualRegistrar', null)
  await set(state, chatId, 'registrarFallback', null)

  // ── Universal-ledger audit (Apr-30-2026 sweep) ──
  try {
    await logTransaction(db, {
      transactionId: generateTransactionId(),
      chatId,
      type: 'domain',
      amount: updatedInfo?.actualPrice || cheaperPrice || price,
      currency: 'USD',
      status: 'completed',
      metadata: { domain, registrar: updatedInfo?.actualRegistrar, coin, value, ref, psp: 'blockbee' },
    })
  } catch (txErr) {
    log('[Domain] Failed to log BlockBee domain transaction (non-blocking): ' + txErr.message)
  }

  notifyGroup(
    `🌐 <b>Domain Registered!</b>\nUser ${maskName(name)} just claimed <b>${maskDomain(domain)}</b> — your dream domain could be next.\nGrab yours before it's taken — /start`,
    `🌐 <b>Domain Registered (Crypto BlockBee)</b>\n👤 User: ${adminUserTag(name, chatId)}\n🌍 Domain: <b>${adminDomainTag(domain)}</b>\n💵 Charged: <b>$${price}</b> (${value} ${coin})\n💳 Payment: Crypto BlockBee`
  )
  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  sendDomainUpsell(chatId, lang, domain) // Post-purchase upsell (parity with wallet path)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  res.send(html())
})

// Hosting
app.get('/crypto-pay-hosting', auth, async (req, res) => {
  // Validate
  const { ref, chatId, price } = req.pay
  const coin = req?.query?.coin
  const value = req?.query?.value_coin
  const response = req?.query

  if (!ref || !chatId || !price || !coin || !value) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)

    // Logs
  del(chatIdOfPayment, ref)

  // Capture business context before hosting creation
  const txDomain = info?.domain || info?.website_name
  const txPlan = info?.plan || null
  const txHostingType = info?.hostingType || null
  const txCouponApplied = !!info?.couponApplied
  const txCouponDiscount = info?.couponDiscount || null
  const txExistingDomain = !!info?.existingDomain || !!info?.connectExternalDomain
  const txBase = { domain: txDomain, plan: txPlan, priceUsd: price, paymentMethod: 'blockbee', currency: coin || 'crypto', hostingType: txHostingType, couponApplied: txCouponApplied, couponDiscount: txCouponDiscount, existingDomain: txExistingDomain, gatewayData: response }

  // Update Wallet
  const usdIn = await convert(value, coin, 'usd')
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    recordHostingTransaction(chatId, { ...txBase, outcome: 'failed' })
    return res.send(html(translation('t.lowPrice')))
  }
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', usdIn - price, lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }

  const hostingResult = await registerDomainAndCreateCpanel(send, info, translation('o', lang), state)
  if (hostingResult?.duplicate) {
    log(`[Hosting] Duplicate provisioning blocked for crypto BlockBee path — chatId ${chatId} domain ${info?.website_name}. Skipping refund.`)
    return res.send(html('ok'))
  }
  if (!hostingResult?.success) {
    // If new domain was registered, refund only hosting portion (domain is consumed)
    if (!info?.existingDomain && !info?.connectExternalDomain && (info?.domainPrice || info?.price || 0) > 0) {
      const domainPrice = info?.domainPrice || info?.price || 0
      // FIX: Use hostingPrice directly instead of usdIn - domainPrice to avoid over-refund when overpaid
      const hostingRefund = info?.hostingPrice || (price - domainPrice)
      if (hostingRefund > 0) addFundsTo(walletOf, chatId, 'usd', hostingRefund, lang)
      sendMessage(chatId, trans('t.wh_4', info?.website_name, domainPrice, hostingRefund.toFixed(2), process.env.APP_SUPPORT_LINK))
      recordHostingTransaction(chatId, { ...txBase, outcome: 'domain_only', refundAmount: hostingRefund, refundCurrency: 'USD' })
    } else {
      addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
      sendMessage(chatId, hostingResult?.error || 'Hosting creation failed. Full payment refunded to your USD wallet.')
      recordHostingTransaction(chatId, { ...txBase, outcome: 'full_refund', refundAmount: usdIn, refundCurrency: 'USD' })
    }
    return res.send(html(hostingResult?.error || 'Hosting creation failed'))
  }

  // Record successful hosting transaction
  recordHostingTransaction(chatId, { ...txBase, outcome: 'success' })
  await auditCryptoTx(chatId, 'hosting', price, { domain: txDomain, plan: txPlan, hostingType: txHostingType, coin, value, ref }, 'blockbee')


  // ── Hosting purchase group notification (was missing — Fix #1) ──
  try {
    const name = await get(nameOf, chatId)
    const domain = info?.domain || info?.website_name
    notifyGroup(
      `🏠 <b>Hosting Activated!</b>\nUser ${maskName(name)} just set up hosting for <b>${maskDomain(domain)}</b> — ready for launch.\nBuild yours — /start`,
      `🏠 <b>Hosting Purchase (Crypto BlockBee)</b>\n🆔 User: ${adminUserTag(name, chatId)}\n🌐 Domain: ${adminDomainTag(domain)}\n📋 Plan: ${info?.plan || 'N/A'}\n💵 Price: <b>$${price}</b>\n💳 Payment: Crypto BlockBee`
    )
  } catch (e) { log('[Hosting] notifyGroup error: ' + e.message) }

  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  set(state, chatId, 'processingPayment', false) // Clear hosting payment lock
  res.send(html())
})

// Cloud IVR — BlockBee callback
app.get('/crypto-pay-phone', auth, async (req, res) => {
  const { ref, chatId, price, cpData } = req.pay
  const coin = req?.query?.coin
  const value = req?.query?.value_coin
  if (!ref || !chatId || !price || !coin || !value || !cpData) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const cpTxt = phoneConfig.getTxt(lang)
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)
  del(chatIdOfPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,CloudPhone,${cpData.selectedNumber},$${price},${chatId},${name},${new Date()},${value} ${coin}`)
  const usdIn = await convert(value, coin, 'usd')
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  // ━━━ FIX: Defer excess credit until AFTER purchase result is known ━━━
  // Previously excess was credited before buyNumber, creating a race condition
  // where concurrent wallet purchases could use the pre-credited excess.
  const excessUsd = usdIn > price ? (usdIn - price) : 0

  let selectedNumber = cpData.selectedNumber
  const planKey = cpData.planKey
  const plan = phoneConfig.plans[planKey]
  const provider = cpData.provider || 'telnyx'
  const countryCode = cpData.countryCode || info?.cpCountryCode || 'US'
  const countryName = cpData.countryName || info?.cpCountryName || 'US'

  if (provider === 'twilio') {
    try {
    if (needsTwilioAddress(countryCode, provider)) {
      // ── Tier 2+ doc upload check for Fincra/crypto path ──
      const numType_fincra = cpData.numType || info?.cpNumberType || 'local'
      if (needsDocUpload(countryCode, numType_fincra)) {
        const approvedBundle_fincra = await pendingBundles.findOne({ chatId, countryCode, status: 'twilio-approved' })
        if (!approvedBundle_fincra) {
          sendMessage(chatId, trans('t.wh_5'))
          const started = await regulatoryFlow.startDocCollection(chatId, {
            countryCode, numType: numType_fincra, countryName, selectedNumber, planKey, price,
            priceUsd: price, priceNgn: 0, paymentMethod: 'crypto_' + coin,
          }, lang)
          if (started) return res.send(html())
        }
      }
      const cachedAddr = await getCachedTwilioAddress(chatId, countryCode)
      if (cachedAddr) {
        // ── Bundle-required countries (e.g. ZA) with cached address ──
        if (twilioService.needsBundle(countryCode)) {
          const approvedBundle = await pendingBundles.findOne({ chatId, countryCode, status: 'twilio-approved' })
          if (approvedBundle) {
            sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
            const result = await executeTwilioPurchase(chatId, selectedNumber, planKey, price, countryCode, countryName, info?.cpNumberType || 'local', 'crypto_' + coin, cachedAddr, null, approvedBundle.bundleSid)
            if (result.error) { addFundsTo(walletOf, chatId, 'usd', Number(price), lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
            sendMessage(chatId, cpTxt.activated(selectedNumber, result.plan?.name || planKey, price, result.sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(result.expiresAt.toISOString())))
          postActivationNudge(chatId, selectedNumber, result.plan?.name || planKey)
            return res.send(html())
          } else {
            // No approved bundle — redirect to address/bundle flow
            await state.updateOne({ _id: String(chatId) }, { $set: {
              action: 'cpEnterAddress', cpPendingCoin: 'crypto_' + coin, cpPendingPriceUsd: price, cpPendingPriceNgn: 0, cpPaymentMethod: 'crypto_' + coin,
            }}, { upsert: true })
            sendMessage(chatId, trans('t.wh_6', countryName), { parse_mode: 'HTML' })
            return res.send(html())
          }
        }
        // Non-bundle: proceed with cached address
        sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
        const result = await executeTwilioPurchase(chatId, selectedNumber, planKey, price, countryCode, countryName, info?.cpNumberType || 'local', 'crypto_' + coin, cachedAddr)
        if (result.error) { addFundsTo(walletOf, chatId, 'usd', Number(price), lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
        sendMessage(chatId, cpTxt.activated(selectedNumber, result.plan?.name || planKey, price, result.sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(result.expiresAt.toISOString())))
          postActivationNudge(chatId, selectedNumber, result.plan?.name || planKey)
        return res.send(html())
      } else {
        await state.updateOne({ _id: String(chatId) }, { $set: {
          action: 'cpEnterAddress', cpPendingCoin: 'crypto_' + coin, cpPendingPriceUsd: price, cpPendingPriceNgn: 0, cpPaymentMethod: 'crypto_' + coin,
        }}, { upsert: true })
        const addrLoc = getAddressLocationText(countryCode)
        sendMessage(chatId, trans('t.wh_7', countryName, addrLoc?.text || 'required'), { parse_mode: 'HTML' })
        return res.send(html())
      }
    }
    sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
    const result = await executeTwilioPurchase(chatId, selectedNumber, planKey, price, countryCode, countryName, info?.cpNumberType || 'local', 'crypto_' + coin, null)
    if (result.error) { addFundsTo(walletOf, chatId, 'usd', Number(price), lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
    sendMessage(chatId, cpTxt.activated(selectedNumber, result.plan?.name || planKey, price, result.sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(result.expiresAt.toISOString())))
          postActivationNudge(chatId, selectedNumber, result.plan?.name || planKey)
    return res.send(html())
    } catch (purchaseErr) {
      log(`[CloudPhone] ❌ BlockBee/Twilio purchase crashed for ${chatId}: ${purchaseErr?.message || purchaseErr}`)
      try { addFundsTo(walletOf, chatId, 'usd', Number(price), lang) } catch (e) { log(`[CloudPhone] ❌ CRITICAL: BlockBee refund failed for ${chatId}: ${e?.message}`) }
      sendMessage(chatId, phoneConfig.getMsg(lang).purchaseFailed + '\n' + sanitizeProviderError(purchaseErr?.message || 'Unexpected error', 'voice'))
      return res.send(html(phoneConfig.getMsg(lang).purchaseFailed))
    }
  }

  // ── TELNYX (BlockBee crypto path) ──
  sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
  const orderResult = await telnyxApi.buyNumber(selectedNumber, telnyxResources.sipConnectionId, telnyxResources.messagingProfileId, { countryCode, numberType: info?.cpNumberType || 'local', areaCode: info?.cpAreaCode || null })
  if (orderResult?._retriedNumber) selectedNumber = orderResult._retriedNumber
  if (!orderResult) { addFundsTo(walletOf, chatId, 'usd', Number(price) + excessUsd, lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
  // Credit excess to wallet only after successful purchase
  if (excessUsd > 0) { addFundsTo(walletOf, chatId, 'usd', excessUsd, lang); sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`)) }
  // Assign to Call Control App for inbound webhook routing
  if (telnyxResources.callControlAppId) await telnyxApi.assignNumberToCallControlApp(selectedNumber, telnyxResources.callControlAppId)
  let sipUsername = phoneConfig.generateSipUsername()
  let sipPassword = phoneConfig.generateSipPassword()
  if (telnyxResources.sipConnectionId) { const tc = await telnyxApi.createSIPCredential(telnyxResources.sipConnectionId, sipUsername, sipPassword); if (tc?.sip_username) { sipUsername = tc.sip_username; sipPassword = tc.sip_password } }
  const expiresAt = new Date(); expiresAt.setMonth(expiresAt.getMonth() + 1)
  const numberDoc = {
    phoneNumber: selectedNumber, telnyxOrderId: orderResult.id, country: countryCode, countryName,
    type: info?.cpNumberType || 'local', plan: planKey, planPrice: price,
    purchaseDate: new Date().toISOString(), expiresAt: expiresAt.toISOString(),
    autoRenew: true, status: 'active', sipUsername, sipPassword,
    sipDomain: phoneConfig.SIP_DOMAIN, provider: 'telnyx',
    messagingProfileId: telnyxResources.messagingProfileId, connectionId: telnyxResources.sipConnectionId,
    smsUsed: 0, minutesUsed: 0,
    features: { sms: true, callForwarding: { enabled: false, mode: 'disabled', forwardTo: null, ringTimeout: 25 },
      voicemail: { enabled: false, greetingType: 'default', customGreetingUrl: null, forwardToTelegram: true, forwardToEmail: null, ringTimeout: 25 },
      smsForwarding: { toTelegram: true, toEmail: null, webhookUrl: null }, recording: false }
  }
  // Atomic $push — never rewrite the whole val (would race with concurrent feature edits)
  await phoneNumbersOf.updateOne(
    { _id: chatId },
    { $push: { 'val.numbers': numberDoc } },
    { upsert: true }
  )
  const existing = await get(phoneNumbersOf, chatId)
  await phoneTransactions.insertOne({ chatId, phoneNumber: selectedNumber, action: 'purchase', plan: planKey, amount: price, paymentMethod: 'crypto_' + coin, timestamp: new Date().toISOString() })
  await auditCryptoTx(chatId, 'phone-number', price, { phoneNumber: selectedNumber, plan: planKey, countryCode, provider: 'telnyx', coin, value, ref }, 'blockbee')
  sendMessage(chatId, cpTxt.activated(selectedNumber, plan.name, price, sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(expiresAt.toISOString())))
  postActivationNudge(chatId, selectedNumber, plan.name)
  notifyGroup(cpTxt.adminPurchase(maskName(name), selectedNumber, plan.name, price, 'Crypto ' + coin), cpTxt.adminPurchasePrivate(adminUserTag(name, chatId), selectedNumber, plan.name, price, 'Crypto ' + coin))
  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  // NOTE: do NOT reset action to 'none' here — postActivationNudge() already
  // set it to 'cpManageNumber' so the 🔑 SIP Credentials tap works on first
  // press. Wiping it back to 'none' reintroduces the 4-level drill-down bug.
  res.send(html())
})

