// Dynopay Domain
app.post('/dynopay/crypto-pay-domain', authDyno, async (req, res) => {
  // Validate
  const { ref, chatId, price, domain } = req.pay
  const { amount:value , currency:coin, payment_id:id } = req.body

  log({ method: 'dynopay/crypto-pay-domain', ref, chatId, domain, price, coin, value })

  if (!ref || !chatId || !domain || !price || !coin || !value) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))

  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)

  // Logs
  del(chatIdOfDynopayPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,Domain,${domain},$${price},${chatId},${name},${new Date()},${value} ${coin},transaction,${id}`)

  // Update Wallet
  const ticker = tickerViewOfDyno[coin]
  const baseAmount = req.body.base_amount
  const feePayer = req.body.fee_payer
  let usdIn
  if (baseAmount && feePayer === 'company') {
    usdIn = parseFloat(baseAmount)
  } else {
    usdIn = await convert(value, ticker , 'usd')
  }
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', usdIn - price, lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }

  // Buy Domain
  const error = await buyDomainFullProcess(chatId, lang, domain)
  if (error) {
    // Domain purchase failed after DynoPay crypto payment received — credit wallet as refund
    try {
      await addFundsTo(walletOf, chatId, 'usd', price, lang)
      sendMessage(chatId, translation('t.wh_14', lang, domain, price))
      sendMessage(TELEGRAM_ADMIN_CHAT_ID, `🔄 <b>Auto-Refund (DynoPay Crypto→Domain)</b>\nUser: ${chatId}\nDomain: ${domain}\nAmount: $${price}\nReason: buyDomainFullProcess failed`, { parse_mode: 'HTML' })
      log(`[Domain] DynoPay crypto refund issued: ${chatId} | ${domain} | $${price}`)
    } catch (refundErr) {
      log(`[Domain] CRITICAL: DynoPay crypto refund failed for ${chatId}: ${refundErr.message}`)
      sendMessage(TELEGRAM_ADMIN_CHAT_ID, `🚨 CRITICAL: DynoPay crypto domain refund FAILED\nUser: ${chatId}\nDomain: ${domain}\nAmount: $${price}\nError: ${refundErr.message}`, { parse_mode: 'HTML' })
    }
    return res.send(html('error'))
  }

  // Check for savings — cheaper registrar succeeded → credit difference to wallet
  const updatedInfo = await state.findOne({ _id: String(chatId) })
  const cheaperPrice = info?.cheaperPrice
  const fallbackOccurred = updatedInfo?.registrarFallback === true
  if (!fallbackOccurred && cheaperPrice && cheaperPrice < price) {
    const savingsUsd = price - cheaperPrice
    addFundsTo(walletOf, chatId, 'usd', savingsUsd, lang)
    sendMessage(chatId, translation('t.wh_15', lang, savingsUsd, domain, cheaperPrice, price, savingsUsd), { parse_mode: 'HTML' })
    sendMessage(TELEGRAM_ADMIN_CHAT_ID, `💰 <b>Domain savings (DynoPay Crypto)</b>\nUser: ${chatId}\nDomain: ${domain}\nShown: $${price} | Actual: $${cheaperPrice} | Saved: $${savingsUsd}\nRegistrar: ${updatedInfo?.actualRegistrar || 'unknown'}`, { parse_mode: 'HTML' })
  }

  // Clean up pricing state
  await set(state, chatId, 'actualPrice', null)
  await set(state, chatId, 'actualRegistrar', null)
  await set(state, chatId, 'registrarFallback', null)

  await auditCryptoTx(chatId, 'domain', updatedInfo?.actualPrice || cheaperPrice || price, { domain, registrar: updatedInfo?.actualRegistrar, coin, value, ref }, 'dynopay')

  notifyGroup(
    `🌐 <b>Domain Registered!</b>\nUser ${maskName(name)} just claimed <b>${maskDomain(domain)}</b> — your dream domain could be next.\nGrab yours before it's taken — /start`,
    `🌐 <b>Domain Registered (Crypto DynoPay)</b>\n👤 User: ${adminUserTag(name, chatId)}\n🌍 Domain: <b>${adminDomainTag(domain)}</b>\n💵 Charged: <b>$${price}</b> (${value} ${coin})\n💳 Payment: Crypto DynoPay`
  )
  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  sendDomainUpsell(chatId, lang, domain) // Post-purchase upsell (parity with wallet path)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  res.send(html())
})

// Dynopay Hosting
app.post('/dynopay/crypto-pay-hosting', authDyno, async (req, res) => {
  // Validate
  const { ref, chatId, price } = req.pay
  const { amount:value , currency:coin } = req.body

  log({ method: 'dynopay/crypto-pay-hosting', ref, chatId, price, coin, value })

  if (!ref || !chatId || !price || !coin || !value) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)
    // Logs
  del(chatIdOfDynopayPayment, ref)

  // Capture business context before hosting creation
  const txDomain = info?.domain || info?.website_name
  const txPlan = info?.plan || null
  const txHostingType = info?.hostingType || null
  const txCouponApplied = !!info?.couponApplied
  const txCouponDiscount = info?.couponDiscount || null
  const txExistingDomain = !!info?.existingDomain || !!info?.connectExternalDomain
  const txBase = { domain: txDomain, plan: txPlan, priceUsd: price, paymentMethod: 'dynopay', currency: coin || 'crypto', hostingType: txHostingType, couponApplied: txCouponApplied, couponDiscount: txCouponDiscount, existingDomain: txExistingDomain, gatewayData: req.body }

  // Update Wallet
  const ticker = tickerViewOfDyno[coin]
  // Use base_amount (confirmed USD) from DynoPay when fee_payer is company
  const baseAmount = req.body.base_amount
  const feePayer = req.body.fee_payer
  let usdIn
  if (baseAmount && feePayer === 'company') {
    usdIn = parseFloat(baseAmount)
    log('[crypto-pay-hosting] Using DynoPay base_amount:', baseAmount, 'USD')
  } else {
    usdIn = await convert(value, ticker , 'usd')
    log('[crypto-pay-hosting] Converted', value, ticker, '= $' + usdIn)
  }
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    recordHostingTransaction(chatId, { ...txBase, outcome: 'failed' })
    return res.send(html(translation('t.lowPrice')))
  }
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', usdIn - price, lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }

  const hostingResult = await registerDomainAndCreateCpanel(send, info, translation('o', lang), state)
  if (hostingResult?.duplicate) {
    log(`[Hosting] Duplicate provisioning blocked for crypto DynoPay path — chatId ${chatId} domain ${info?.website_name}. Skipping refund.`)
    return res.send(html('ok'))
  }
  if (!hostingResult?.success) {
    // If new domain was registered, refund only hosting portion (domain is consumed)
    if (!info?.existingDomain && !info?.connectExternalDomain && (info?.domainPrice || info?.price || 0) > 0) {
      const domainPrice = info?.domainPrice || info?.price || 0
      // FIX: Use hostingPrice directly instead of usdIn - domainPrice to avoid over-refund when overpaid
      const hostingRefund = info?.hostingPrice || (price - domainPrice)
      if (hostingRefund > 0) addFundsTo(walletOf, chatId, 'usd', hostingRefund, lang)
      sendMessage(chatId, translation('t.wh_16', lang, info?.website_name, domainPrice, hostingRefund.toFixed(2), process.env.APP_SUPPORT_LINK))
      recordHostingTransaction(chatId, { ...txBase, outcome: 'domain_only', refundAmount: hostingRefund, refundCurrency: 'USD' })
    } else {
      addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
      sendMessage(chatId, hostingResult?.error || 'Hosting creation failed. Full payment refunded to your USD wallet.')
      recordHostingTransaction(chatId, { ...txBase, outcome: 'full_refund', refundAmount: usdIn, refundCurrency: 'USD' })
    }
    return res.send(html(hostingResult?.error || 'Hosting creation failed'))
  }

  // Record successful hosting transaction
  recordHostingTransaction(chatId, { ...txBase, outcome: 'success' })
  await auditCryptoTx(chatId, 'hosting', price, { domain: txDomain, plan: txPlan, hostingType: txHostingType, coin, value, ref }, 'dynopay')


  // ── Hosting purchase group notification (was missing — Fix #1) ──
  try {
    const name = await get(nameOf, chatId)
    const domain = info?.domain || info?.website_name
    notifyGroup(
      `🏠 <b>Hosting Activated!</b>\nUser ${maskName(name)} just set up hosting for <b>${maskDomain(domain)}</b> — ready for launch.\nBuild yours — /start`,
      `🏠 <b>Hosting Purchase (Crypto DynoPay)</b>\n🆔 User: ${adminUserTag(name, chatId)}\n🌐 Domain: ${adminDomainTag(domain)}\n📋 Plan: ${info?.plan || 'N/A'}\n💵 Price: <b>$${price}</b>\n💳 Payment: Crypto DynoPay`
    )
  } catch (e) { log('[Hosting] notifyGroup error: ' + e.message) }

  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  set(state, chatId, 'processingPayment', false) // Clear hosting payment lock
  res.send(html())
})

// Dynopay Cloud IVR
app.post('/dynopay/crypto-pay-phone', authDyno, async (req, res) => {
  const { ref, chatId, price, cpData } = req.pay
  const { amount:value, currency:coin, payment_id:id } = req.body
  log({ method: 'dynopay/crypto-pay-phone', ref, chatId, price, coin, value })
  if (!ref || !chatId || !price || !coin || !value || !cpData) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const cpTxt = phoneConfig.getTxt(lang)
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)
  del(chatIdOfDynopayPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,CloudPhone,${cpData.selectedNumber},$${price},${chatId},${name},${new Date()},${value} ${coin},transaction,${id}`)
  const ticker = tickerViewOfDyno[coin]
  const baseAmount = req.body.base_amount
  const feePayer = req.body.fee_payer
  let usdIn
  if (baseAmount && feePayer === 'company') {
    usdIn = parseFloat(baseAmount)
  } else {
    usdIn = await convert(value, ticker, 'usd')
  }
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  // ━━━ FIX: Defer excess credit until AFTER purchase result is known (DynoPay) ━━━
  const excessUsd = usdIn > price ? (usdIn - price) : 0

  let selectedNumber = cpData.selectedNumber
  const planKey = cpData.planKey
  const plan = phoneConfig.plans[planKey]
  const provider = cpData.provider || 'telnyx'
  const countryCode = cpData.countryCode || info?.cpCountryCode || 'US'
  const countryName = cpData.countryName || info?.cpCountryName || 'US'

  if (provider === 'twilio') {
    try {
    if (needsTwilioAddress(countryCode, provider)) {
      // ── Tier 2+ doc upload check for DynoPay crypto path ──
      const numType_dp = cpData.numType || info?.cpNumberType || 'local'
      if (needsDocUpload(countryCode, numType_dp)) {
        const approvedBundle_dp = await pendingBundles.findOne({ chatId, countryCode, status: 'twilio-approved' })
        if (!approvedBundle_dp) {
          sendMessage(chatId, translation('t.wh_17', lang))
          const started = await regulatoryFlow.startDocCollection(chatId, {
            countryCode, numType: numType_dp, countryName, selectedNumber, planKey, price,
            priceUsd: price, priceNgn: 0, paymentMethod: 'crypto_dynopay',
          }, lang)
          if (started) return res.send(html())
        }
      }
      const cachedAddr = await getCachedTwilioAddress(chatId, countryCode)
      if (cachedAddr) {
        // ── Bundle-required countries (e.g. ZA) with cached address ──
        if (twilioService.needsBundle(countryCode)) {
          const approvedBundle = await pendingBundles.findOne({ chatId, countryCode, status: 'twilio-approved' })
          if (approvedBundle) {
            sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
            const result = await executeTwilioPurchase(chatId, selectedNumber, planKey, price, countryCode, countryName, info?.cpNumberType || 'local', 'crypto_dynopay_' + coin, cachedAddr, null, approvedBundle.bundleSid)
            if (result.error) { addFundsTo(walletOf, chatId, 'usd', Number(price), lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
            sendMessage(chatId, cpTxt.activated(selectedNumber, result.plan?.name || planKey, price, result.sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(result.expiresAt.toISOString())))
          postActivationNudge(chatId, selectedNumber, result.plan?.name || planKey)
            // notifyGroup + admin already sent inside executeTwilioPurchase()
            return res.send(html())
          } else {
            // No approved bundle — redirect to address/bundle flow
            await state.updateOne({ _id: String(chatId) }, { $set: {
              action: 'cpEnterAddress', cpPendingCoin: 'crypto_dynopay_' + coin, cpPendingPriceUsd: price, cpPendingPriceNgn: 0, cpPaymentMethod: 'crypto_dynopay_' + coin,
            }}, { upsert: true })
            sendMessage(chatId, translation('t.wh_18', lang, countryName), { parse_mode: 'HTML' })
            return res.send(html())
          }
        }
        // Non-bundle: proceed with cached address
        sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
        const result = await executeTwilioPurchase(chatId, selectedNumber, planKey, price, countryCode, countryName, info?.cpNumberType || 'local', 'crypto_dynopay_' + coin, cachedAddr)
        if (result.error) { addFundsTo(walletOf, chatId, 'usd', Number(price), lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
        sendMessage(chatId, cpTxt.activated(selectedNumber, result.plan?.name || planKey, price, result.sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(result.expiresAt.toISOString())))
          postActivationNudge(chatId, selectedNumber, result.plan?.name || planKey)
        // notifyGroup + admin already sent inside executeTwilioPurchase()
        return res.send(html())
      } else {
        await state.updateOne({ _id: String(chatId) }, { $set: {
          action: 'cpEnterAddress', cpPendingCoin: 'crypto_dynopay_' + coin, cpPendingPriceUsd: price, cpPendingPriceNgn: 0, cpPaymentMethod: 'crypto_dynopay_' + coin,
        }}, { upsert: true })
        const addrLoc = getAddressLocationText(countryCode)
        sendMessage(chatId, translation('t.wh_19', lang, countryName, addrLoc?.text || 'required'), { parse_mode: 'HTML' })
        return res.send(html())
      }
    }
    sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
    const result = await executeTwilioPurchase(chatId, selectedNumber, planKey, price, countryCode, countryName, info?.cpNumberType || 'local', 'crypto_dynopay_' + coin, null)
    if (result.error) { addFundsTo(walletOf, chatId, 'usd', Number(price), lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
    sendMessage(chatId, cpTxt.activated(selectedNumber, result.plan?.name || planKey, price, result.sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(result.expiresAt.toISOString())))
          postActivationNudge(chatId, selectedNumber, result.plan?.name || planKey)
    // notifyGroup + admin already sent inside executeTwilioPurchase()
    return res.send(html())
    } catch (purchaseErr) {
      log(`[CloudPhone] ❌ DynoPay/Twilio purchase crashed for ${chatId}: ${purchaseErr?.message || purchaseErr}`)
      try { addFundsTo(walletOf, chatId, 'usd', Number(price), lang) } catch (e) { log(`[CloudPhone] ❌ CRITICAL: DynoPay refund failed for ${chatId}: ${e?.message}`) }
      sendMessage(chatId, phoneConfig.getMsg(lang).purchaseFailed + '\n' + sanitizeProviderError(purchaseErr?.message || 'Unexpected error', 'voice'))
      return res.send(html(phoneConfig.getMsg(lang).purchaseFailed))
    }
  }

  // ── TELNYX ──
  sendMessage(chatId, phoneConfig.getMsg(lang).purchasingNumber)
  const orderResult = await telnyxApi.buyNumber(selectedNumber, telnyxResources.sipConnectionId, telnyxResources.messagingProfileId, { countryCode, numberType: info?.cpNumberType || 'local', areaCode: info?.cpAreaCode || null })
  if (orderResult?._retriedNumber) selectedNumber = orderResult._retriedNumber
  if (!orderResult) { addFundsTo(walletOf, chatId, 'usd', Number(price) + excessUsd, lang); return res.send(html(phoneConfig.getMsg(lang).purchaseFailed)) }
  // Credit excess to wallet only after successful purchase (DynoPay)
  if (excessUsd > 0) { addFundsTo(walletOf, chatId, 'usd', excessUsd, lang); sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`)) }
  // Assign to Call Control App for inbound webhook routing
  if (telnyxResources.callControlAppId) await telnyxApi.assignNumberToCallControlApp(selectedNumber, telnyxResources.callControlAppId)
  let sipUsername = phoneConfig.generateSipUsername()
  let sipPassword = phoneConfig.generateSipPassword()
  if (telnyxResources.sipConnectionId) { const tc = await telnyxApi.createSIPCredential(telnyxResources.sipConnectionId, sipUsername, sipPassword); if (tc?.sip_username) { sipUsername = tc.sip_username; sipPassword = tc.sip_password } }
  const expiresAt = new Date(); expiresAt.setMonth(expiresAt.getMonth() + 1)
  const numberDoc = {
    phoneNumber: selectedNumber, telnyxOrderId: orderResult.id, country: countryCode, countryName,
    type: info?.cpNumberType || 'local', plan: planKey, planPrice: price,
    purchaseDate: new Date().toISOString(), expiresAt: expiresAt.toISOString(),
    autoRenew: true, status: 'active', sipUsername, sipPassword,
    sipDomain: phoneConfig.SIP_DOMAIN, provider: 'telnyx',
    messagingProfileId: telnyxResources.messagingProfileId, connectionId: telnyxResources.sipConnectionId,
    smsUsed: 0, minutesUsed: 0,
    features: { sms: true, callForwarding: { enabled: false, mode: 'disabled', forwardTo: null, ringTimeout: 25 },
      voicemail: { enabled: false, greetingType: 'default', customGreetingUrl: null, forwardToTelegram: true, forwardToEmail: null, ringTimeout: 25 },
      smsForwarding: { toTelegram: true, toEmail: null, webhookUrl: null }, recording: false }
  }
  // Atomic $push — never rewrite the whole val (would race with concurrent feature edits)
  await phoneNumbersOf.updateOne(
    { _id: chatId },
    { $push: { 'val.numbers': numberDoc } },
    { upsert: true }
  )
  const existing = await get(phoneNumbersOf, chatId)
  await phoneTransactions.insertOne({ chatId, phoneNumber: selectedNumber, action: 'purchase', plan: planKey, amount: price, paymentMethod: 'crypto_dynopay_' + coin, timestamp: new Date().toISOString() })
  await auditCryptoTx(chatId, 'phone-number', price, { phoneNumber: selectedNumber, plan: planKey, countryCode, provider: 'telnyx', coin, value, ref }, 'dynopay')
  sendMessage(chatId, cpTxt.activated(selectedNumber, plan.name, price, sipUsername, phoneConfig.SIP_DOMAIN, phoneConfig.shortDate(expiresAt.toISOString())))
  postActivationNudge(chatId, selectedNumber, plan.name)
  notifyGroup(cpTxt.adminPurchase(maskName(name), selectedNumber, plan.name, price, 'Crypto DynoPay'), cpTxt.adminPurchasePrivate(adminUserTag(name, chatId), selectedNumber, plan.name, price, 'Crypto DynoPay'))
  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  res.send(html())
})

// ── DynoPay Crypto Callback for Phone Plan Upgrade ──
app.post('/dynopay/crypto-pay-phone-upgrade', authDyno, async (req, res) => {
  const { ref, chatId, price, upgradeData } = req.pay
  const { amount:value, currency:coin, payment_id:id } = req.body
  log({ method: 'dynopay/crypto-pay-phone-upgrade', ref, chatId, price, coin, value })
  if (!ref || !chatId || !price || !coin || !value || !upgradeData) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  del(chatIdOfDynopayPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,PhoneUpgrade,${upgradeData.phoneNumber},$${price},${chatId},${name},${new Date()},${value} ${coin},transaction,${id}`)
  const ticker = tickerViewOfDyno[coin]
  const baseAmount = req.body.base_amount
  const feePayer = req.body.fee_payer
  let usdIn
  if (baseAmount && feePayer === 'company') {
    usdIn = parseFloat(baseAmount)
  } else {
    usdIn = await convert(value, ticker, 'usd')
  }
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  const excessUsd = usdIn > price ? (usdIn - price) : 0
  if (excessUsd > 0) {
    await atomicIncrement(walletOf, chatId, 'usdIn', excessUsd)
    sendMessage(chatId, translation('t.wh_20', lang, excessUsd.toFixed(2)), { parse_mode: 'HTML' })
  }

  const userData = await get(phoneNumbersOf, chatId)
  const num = userData?.numbers?.find(n => n.phoneNumber === upgradeData.phoneNumber)
  if (!num) {
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html('Phone number not found'))
  }

  await applyPhonePlanUpgrade(chatId, num, upgradeData.newPlan, upgradeData.newPrice, lang, `🪙 Crypto (${coin})`, upgradeData)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  res.send(html())
})

// Dynopay Leads / Validation
app.post('/dynopay/crypto-pay-leads', authDyno, async (req, res) => {
  const { ref, chatId, price, lastStep, leadsData } = req.pay
  const { amount:value, currency:coin, payment_id:id } = req.body
  log({ method: 'dynopay/crypto-pay-leads', ref, chatId, price, coin, value })
  if (!ref || !chatId || !price || !coin || !value || !lastStep) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)
  del(chatIdOfDynopayPayment, ref)
  const name = await get(nameOf, chatId)
  const isValidator = lastStep === 'validatorSelectFormat'
  const label = isValidator ? 'Validation' : 'Leads'
  set(payments, ref, `Crypto,${label},$${price},${chatId},${name},${new Date()},${value} ${coin},transaction,${id}`)
  // Immediate payment notification — don't wait for lead generation to complete
  notifyGroup(
    `💰 <b>Crypto Payment Received!</b>\n👤 User: ${maskName(name)}\n💵 Paid: <b>$${price}</b> (${coin})\n📦 Product: ${leadsData?.amount?.toLocaleString() || '?'} ${leadsData?.targetName || label}\n⏳ Generation in progress...`,
    `💰 <b>Crypto Payment Received (DynoPay)</b>\n👤 User: ${adminUserTag(name, chatId)}\n💵 Paid: <b>$${price}</b> (${value} ${coin})\n📦 Product: ${leadsData?.amount?.toLocaleString() || '?'} ${leadsData?.targetName || label}\n⏳ Generation in progress...`
  )
  const ticker = tickerViewOfDyno[coin]
  const baseAmount = req.body.base_amount
  const feePayer = req.body.fee_payer
  let usdIn
  if (baseAmount && feePayer === 'company') {
    usdIn = parseFloat(baseAmount)
  } else {
    usdIn = await convert(value, ticker, 'usd')
  }
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', usdIn - price, lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }
  try {
    const ld = leadsData || {}
    let cc = countryCodeOf[ld.country]
    // For targeted leads: always enable CNAM for USA; for validator: respect user opt-in
    const cnam = ld.country === 'USA' ? (isValidator ? ld.cnamMode : (ld.targetName ? true : ld.cnamMode)) : false
    const format = ld.format
    const l = format === buyLeadsSelectFormat[0]
    if (isValidator) {
      sendMessage(chatId, translation('t.validatorBulkNumbersStart', lang))
      const phones = info?.phones?.slice(0, ld.amount)
      const result = await validatePhoneBulkFile(ld.carrier, phones, cc, cnam, bot, chatId)
      if (!result) return sendMessage(chatId, translation('t.validatorError', lang)) || res.send(html())
      sendMessage(chatId, translation('t.validatorSuccess', lang, ld.amount, result.length))
      cc = '+' + cc; const re = cc === '+1' ? '' : '0'
      if (result.length > 0) {
        fs.writeFile('leads.txt', result.map(a => (l ? a[0].replace(cc, re) : a[0])).join('\n'), () => bot?.sendDocument(chatId, 'leads.txt').catch(() => {}))
        if (cnam) { fs.writeFile('leads_with_cnam.txt', result.map(a => (l ? a[0].replace(cc, re) : a[0]) + ' ' + a[3]).join('\n'), () => { bot?.sendDocument(chatId, 'leads_with_cnam.txt').catch(() => {}); bot?.sendDocument(TELEGRAM_ADMIN_CHAT_ID, 'leads_with_cnam.txt').catch(() => {}) }) }
        else if (ld.country !== 'USA') { fs.writeFile('leads_with_carriers.txt', result.map(a => (l ? a[0].replace(cc, re) : a[0]) + ' ' + a[1]).join('\n'), () => { bot?.sendDocument(chatId, 'leads_with_carriers.txt').catch(() => {}); bot?.sendDocument(TELEGRAM_ADMIN_CHAT_ID, 'leads_with_carriers.txt').catch(() => {}) }) }
      } else {
        sendMessage(chatId, '⚠️ Validation completed but 0 valid phone numbers were found. No file to send.')
      }
    } else {
      const _startMsg = ld.targetName ? '🎯 Sourcing real data in progress. Please wait...' : translation('t.validatorBulkNumbersStart', lang)
      sendMessage(chatId, _startMsg)
      let areaCodes
      if (info?.targetAreaCodes) { areaCodes = ld.area === 'Mixed Area Codes' ? info.targetAreaCodes : [ld.area] }
      else if (['Australia'].includes(ld.country)) { areaCodes = ['4'] }
      else { areaCodes = ld.area === 'Mixed Area Codes' ? _buyLeadsSelectAreaCode(ld.country, ld.area) : [ld.area] }
      const result = await validateBulkNumbers(ld.carrier, ld.amount, cc, areaCodes, cnam, bot, chatId, lang, false, { target: ld.targetName, price: price, walletDeducted: true, paymentCoin: 'DYNOPAY' })
      if (!result || result.length === 0) {
        // Full refund to wallet — no leads generated
        await atomicIncrement(walletOf, chatId, 'usdIn', Number(price))
        log(`[Leads] DynoPay full refund $${price} for ${chatId} — 0 leads generated`)
        if (TELEGRAM_ADMIN_CHAT_ID) bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID, `💰 <b>Full Lead Refund (DynoPay)</b>\n👤 ${chatId}\n📊 0/${ld.amount} leads\n💵 $${Number(price).toFixed(2)} → wallet\n📝 Generation returned 0 results`, { parse_mode: 'HTML' }).catch(() => {})
        sendMessage(chatId, translation('t.buyLeadsError', lang))
        return res.send(html())
      }
      // ── Partial delivery refund for DynoPay crypto — credit wallet USD ──
      if (result._partialReason) {
        const requested = result._targetCount || ld.amount || 1
        const delivered = result._deliveredCount || result.length
        if (delivered < requested && price > 0) {
          const undeliveredRatio = (requested - delivered) / requested
          const refundAmount = Math.round(undeliveredRatio * price * 100) / 100
          if (refundAmount > 0) {
            await atomicIncrement(walletOf, chatId, 'usdIn', refundAmount)
            sendMessage(chatId, translation('t.wh_21', lang, delivered, requested, refundAmount.toFixed(2)))
            if (TELEGRAM_ADMIN_CHAT_ID) bot?.sendMessage(TELEGRAM_ADMIN_CHAT_ID, `💰 <b>Partial Lead Refund (DynoPay)</b>\n👤 ${chatId}\n📊 ${delivered}/${requested}\n💵 $${refundAmount.toFixed(2)} → wallet`, { parse_mode: 'HTML' }).catch(() => {})
          }
        }
      }
      const _successMsg = ld.targetName ? `🎯 Your ${ld.amount} targeted leads are ready — including phone owner names where matched.` : translation('t.buyLeadsSuccess', lang, ld.amount)
      sendMessage(chatId, _successMsg)
      cc = '+' + cc; const re = cc === '+1' ? '' : '0'
      const isTargetLeads = !!ld.targetName
      if (result.length > 0) {
        fs.writeFile('leads.txt', result.map(a => (l ? a[0].replace(cc, re) : a[0])).join('\n'), () => {
          bot?.sendDocument(chatId, 'leads.txt').catch(() => {})
          if (isTargetLeads) sendMessage(chatId, translation('t.leadsFileNumbersOnly', lang))
        })
        if (cnam) {
          const withNames = result.filter(a => a[3] && a[3].trim() && a[3].trim().toLowerCase() !== 'unknown')
          if (withNames.length > 0) {
            fs.writeFile('leads_with_names.txt', withNames.map(a => (l ? a[0].replace(cc, re) : a[0]) + ' ' + a[3]).join('\n'), () => {
              bot?.sendDocument(chatId, 'leads_with_names.txt').catch(() => {})
              if (isTargetLeads) sendMessage(chatId, translation('t.leadsFileWithNames', lang, withNames.length))
              bot?.sendDocument(TELEGRAM_ADMIN_CHAT_ID, 'leads_with_names.txt').catch(() => {})
            })
          }
        }
        else if (ld.country !== 'USA') { fs.writeFile('leads_with_carriers.txt', result.map(a => (l ? a[0].replace(cc, re) : a[0]) + ' ' + a[1]).join('\n'), () => { bot?.sendDocument(chatId, 'leads_with_carriers.txt').catch(() => {}); bot?.sendDocument(TELEGRAM_ADMIN_CHAT_ID, 'leads_with_carriers.txt').catch(() => {}) }) }
      } else {
        sendMessage(chatId, '⚠️ Validation completed but 0 valid phone numbers were found. No file to send.')
      }
    }
    set(payments, nanoid(), `Crypto,${label},${ld.amount} leads,$${price},${chatId},${name},${new Date()},DynoPay ${coin}`)
    await auditCryptoTx(chatId, isValidator ? 'validation' : 'leads', price, { amount: ld.amount, country: ld.country, carrier: ld.carrier, targetName: ld.targetName || null, coin, value, ref }, 'dynopay')
    notifyGroup(
      `🏦 <b>${ld.targetName || label} Acquired!</b>\nUser ${maskName(name)} just grabbed ${ld.amount?.toLocaleString()} verified ${ld.targetName ? ld.targetName + ' ' : ''}leads with phone owner names via crypto.\nGet yours — /start`,
      `🏦 <b>${ld.targetName || label} Acquired (Crypto DynoPay)</b>\n👤 User: ${adminUserTag(name, chatId)}\n📊 Leads: <b>${ld.amount?.toLocaleString()}</b> ${ld.targetName || ''}\n💵 Price: <b>$${price}</b> (${coin})\n💳 Payment: Crypto DynoPay`
    )
    webhookTierCheck(chatId, preSpend, lang)
  } catch (e) {
    log(`[dynopay-crypto-pay-leads] Error: ${e.message}`)
    sendMessage(chatId, translation('t.wh_22', lang, Number(price).toFixed(2), label.toLowerCase()))
    addFundsTo(walletOf, chatId, 'usd', Number(price), lang)
  }
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  res.send(html())
})

// Dynopay VPS
app.post('/dynopay/crypto-pay-vps', authDyno, async (req, res) => {
  // Validate
  const { ref, chatId, price, vpsDetails } = req.pay
  const { amount:value , currency:coin } = req.body

  log({ method: 'dynopay/crypto-pay-vps', ref, chatId, price, coin, value })

  if (!ref || !chatId || !price || !coin || !value) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))

  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const totalPrice = vpsDetails?.totalPrice
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)

  sendMessage(chatId, translation('vp.paymentRecieved', lang))
  // Logs
  del(chatIdOfDynopayPayment, ref)
  const name = await get(nameOf, chatId)
  let transaction = {
    type: 'new-plan',
    response: req.body
  }
  await insert(vpsTransactions, chatId, "dynopay", transaction)

  // Update Wallet
  const ticker = tickerViewOfDyno[coin]
  const baseAmount_v = req.body.base_amount
  const feePayer_v = req.body.fee_payer
  let usdIn
  if (baseAmount_v && feePayer_v === 'company') {
    usdIn = parseFloat(baseAmount_v)
  } else {
    usdIn = await convert(value, ticker , 'usd')
  }
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', Number(usdIn), lang)
    return res.send(html(translation('t.lowPrice')))
  }
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', Number(usdIn) - Number(price), lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }

  if (vpsDetails.plan === 'Hourly') {
    addFundsTo(walletOf, chatId, 'usd', Number(usdIn) - Number(totalPrice), lang)
    sendMessage(chatId, translation('vp.extraMoney', lang))
  }

  const isSuccess = await buyVPSPlanFullProcess(chatId, lang, vpsDetails)
  if (!isSuccess) {
    // ── Refund to wallet on VPS provisioning failure (crypto path) ──
    const refundAmt = Number(price) || Number(usdIn)
    if (refundAmt > 0) {
      addFundsTo(walletOf, chatId, 'usd', refundAmt, lang)
      const { usdIn: wIn = 0, usdOut: wOut = 0 } = (await get(walletOf, chatId)) || {}
      const usdBal = (wIn - wOut).toFixed(2)
      sendMessage(chatId, translation('t.wh_23', lang, refundAmt.toFixed(2), usdBal), { parse_mode: 'HTML' })
      log(`[crypto-pay-vps] Refunded $${refundAmt.toFixed(2)} to wallet for chatId=${chatId} after VPS provisioning failure`)
    }
    return res.send(html('error'))
  }
  await auditCryptoTx(chatId, 'vps', price, { plan: vpsDetails?.plan, region: vpsDetails?.region, type: 'new-plan', coin, value, ref }, 'dynopay')
  notifyGroup(
    `🖥️ <b>VPS Deployed!</b>\nUser ${maskName(name)} just deployed a new VPS server via crypto.\nDeploy yours in seconds — /start`,
    `🖥️ <b>New VPS (Crypto DynoPay)</b>\n👤 User: ${adminUserTag(name, chatId)}\n💰 Price: <b>$${Number(price).toFixed(2)}</b> (${value} ${coin})\n📦 Plan: ${vpsDetails?.plan || 'VPS'}\n💳 Payment: Crypto DynoPay`
  )
  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  res.send(html())
})

