app.post('/dynopay/crypto-pay-virtual-card', authDyno, async (req, res) => {
  const { ref, chatId, price, product, orderId } = req.pay
  const { amount: value, currency: coin, payment_id: id } = req.body
  log({ method: 'dynopay/crypto-pay-virtual-card', ref, chatId, product, price, coin, value })
  if (!ref || !chatId || !product || !price || !coin || !value) return log(translation('t.argsErr')) || res.send(html(translation('t.argsErr')))
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  const preSpend = await loyalty.getTotalSpend(walletOf, chatId)
  del(chatIdOfDynopayPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,VirtualCard,${product},$${price},${chatId},${name},${new Date()},${value} ${coin},transaction,${id}`)
  const ticker = tickerViewOfDyno[coin]
  const baseAmount = req.body.base_amount
  const feePayer = req.body.fee_payer
  let usdIn
  if (baseAmount && feePayer === 'company') {
    usdIn = parseFloat(baseAmount)
  } else {
    usdIn = await convert(value, ticker, 'usd')
  }
  if (usdIn < price) {
    sendMessage(chatId, translation('t.sentLessMoney', lang, `$${price}`, `$${usdIn}`))
    addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
    return res.send(html(translation('t.lowPrice')))
  }
  if (usdIn > price) {
    addFundsTo(walletOf, chatId, 'usd', usdIn - price, lang)
    sendMessage(chatId, translation('t.sentMoreMoney', lang, `$${price}`, `$${usdIn}`))
  }
  const vcAmount = info?.vcAmount || 0
  const vcAddress = info?.vcAddress || ''
  await digitalOrdersCol.updateOne({ orderId }, { $set: { status: 'pending', paymentConfirmedAt: new Date() } })
  await auditCryptoTx(chatId, 'virtual-card', price, { orderId, vcAmount, coin, value, ref }, 'dynopay')

  sendMessage(chatId, translation('t.vcOrderConfirmed', lang, vcAmount, price, orderId))
  notifyGroup(
    `💳 <b>Virtual Card Paid!</b>\n\n👤 User: ${maskName(name)}\n💵 Card: <b>$${vcAmount}</b> | Paid: <b>$${price}</b>\n\n✅ Payment confirmed.`,
    `💳 <b>Virtual Card Paid (Crypto DynoPay)</b>\n\n🆔 Order: <code>${orderId}</code>\n👤 User: ${adminUserTag(name, chatId)}\n💵 Card: <b>$${vcAmount}</b> | Paid: <b>$${price}</b> (${value} ${coin})\n📬 Address:\n<pre>${vcAddress}</pre>\n💳 Payment: Crypto DynoPay\n\n📩 Deliver with:\n<code>/deliver ${orderId} [card details]</code>`,
    buildAdminButtons({ chatId, orderId })
  )
  webhookTierCheck(chatId, preSpend, lang)
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto payment completes
  res.send(html())
})


// Dynopay wallet 
app.post('/dynopay/crypto-wallet', authDyno, async (req, res) => {
  log('=== DYNOPAY WALLET WEBHOOK PROCESSING START ===')
  
  // Validate
  const { ref, chatId } = req.pay
  const { amount:value , currency:coin, payment_id:id } = req.body
  
  log('Extracted data - ref:', ref, 'chatId:', chatId, 'coin:', coin, 'value:', value, 'transaction_id:', id)
  
  if (!ref || !chatId || !coin || !value) {
    log('ERROR: Missing required fields - ref:', ref, 'chatId:', chatId, 'coin:', coin, 'value:', value)
    return res.send(html(translation('t.argsErr')))
  }
  
  const info = await state.findOne({ _id: String(chatId) })
  const lang = info?.userLanguage ?? 'en'
  log('User language:', lang)

  // Update Wallet
  const ticker = tickerViewOfDyno[coin]
  log('Currency mapping - coin:', coin, '-> ticker:', ticker)
  
  if (!ticker) {
    log('ERROR: Unknown currency received from Dynopay:', coin)
    log('Supported currencies:', Object.keys(tickerViewOfDyno))
    return res.send(html('Currency not supported: ' + coin))
  }
  
  // Use base_amount (confirmed USD) from DynoPay when fee_payer is company
  // This prevents users losing money due to fee deduction + re-conversion variance
  const baseAmount = req.body.base_amount
  const feePayer = req.body.fee_payer
  let usdIn

  if (baseAmount && feePayer === 'company') {
    usdIn = parseFloat(baseAmount)
    log('Using DynoPay base_amount (fee_payer=company):', baseAmount, 'USD')
  } else {
    log('Converting', value, ticker, 'to USD (no base_amount or fee_payer != company)...')
    usdIn = await convert(value, ticker , 'usd')
    log('Conversion result:', value, ticker, '= $' + usdIn, 'USD')
  }
  
  log('Crediting wallet for chatId:', chatId, 'amount: $' + usdIn)
  await addFundsTo(walletOf, chatId, 'usd', usdIn, lang)
  log('Wallet credited successfully!')
  
  // Generate transaction ID for wallet top-up
  const txnId = generateTransactionId()
  try {
    await logTransaction(db, {
      transactionId: txnId,
      chatId,
      type: 'wallet-topup',
      amount: usdIn,
      currency: 'USD',
      status: 'completed',
      metadata: { coin, value, ref, psp: 'dynopay' }
    })
  } catch (txErr) {
    log('[Wallet] Failed to log transaction (non-blocking):', txErr.message)
  }

  log('Sending confirmation message to user...')
  const confirmMsg = translation('t.confirmationDepositMoney', lang, value + ' ' + coin, usdIn) + 
    `\n\n<b>Transaction ID:</b> <code>${txnId}</code>\n<i>Quote this ID when contacting support</i>`
  sendMessage(chatId, confirmMsg)
  log('Confirmation message sent')

  // Logs
  res.send(html())
  del(chatIdOfDynopayPayment, ref)
  const name = await get(nameOf, chatId)
  set(payments, ref, `Crypto,Wallet,wallet,$${usdIn},${chatId},${name},${new Date()},${value} ${coin},transaction,${id}`)
  notifyGroup(
    `💰 <b>Wallet Top-Up!</b>\nUser ${maskName(name)} just topped up via <b>💎 Crypto (DynoPay)</b>\nFund yours in seconds — /start`,
    `💰 <b>Wallet Top-Up (DynoPay)</b>\n👤 User: ${adminUserTag(name, chatId)}\n💵 Credited: <b>$${usdIn}</b> USD\n🪙 Received: <b>${value} ${coin}</b>\n🔖 Ref: <code>${ref}</code>\n🆔 Txn: <code>${txnId}</code>`,
    buildAdminButtons({ chatId })
  )
  // ── First-Purchase Deposit Bonus (Feature 2) ──
  if (userConversion) {
    try {
      const bonus = await userConversion.checkFirstDepositBonus(chatId, usdIn)
      if (bonus?.awarded) {
        await atomicIncrement(walletOf, chatId, 'usdIn', bonus.amount)
        sendMessage(chatId, userConversion.getFirstDepositBonusMessage(lang), { parse_mode: 'HTML' })
        log(`[Conversion] First deposit bonus $${bonus.amount} awarded to ${chatId}`)
      }
    } catch (e) { /* non-critical */ }
  }
  if (cartRecovery) cartRecovery.recordPaymentCompleted(String(chatId))
  if (userConversion) userConversion.markPurchased(chatId)
  await set(state, chatId, 'action', 'none') // Reset action after crypto wallet deposit
  
  log('=== DYNOPAY WALLET WEBHOOK PROCESSING COMPLETE ===')
})

