app.get('/:id', async (req, res) => {
  const id = req?.params?.id
  if (id === '') return res.json({ message: 'Salam', from: req.hostname })

  // ── Panel domain guard: NEVER run shortener on panel.hostbay.io ──
  const panelDom = (process.env.PANEL_DOMAIN || '').toLowerCase().trim()
  if (panelDom) {
    const host = (req.hostname || req.headers.host || '').toLowerCase().split(':')[0]
    if (host === panelDom) {
      // On panel domain — serve the React SPA so the panel renders (not the shortener)
      const buildIndex = require('path').join(__dirname, '..', 'frontend', 'build', 'index.html')
      if (require('fs').existsSync(buildIndex)) {
        return res.sendFile(buildIndex)
      }
      return res.status(404).json({ error: 'Panel page not found' })
    }
  }

  // Skip known frontend SPA routes — let them be handled by the React catch-all
  const spaRoutes = ['call', 'panel', 'phone', 'login', 'signup', 'dashboard', 'settings']
  if (spaRoutes.includes(id.toLowerCase())) {
    // Serve the React SPA index.html for these routes
    const buildPath = require('path').join(__dirname, '..', 'frontend', 'build', 'index.html')
    if (require('fs').existsSync(buildPath)) {
      return res.sendFile(buildPath)
    }
    // If no build (dev env), pass to next handler
    return res.status(404).json({ error: 'Page not found' })
  }

  // Build lookup key from SELF_URL (works on both Railway and Emergent)
  // On Railway: SELF_URL = "https://app.railway.app" → key = "app@railway@app/slug"
  // On Emergent: SELF_URL = "https://pod.emergentagent.com/api" → key = "pod@...@com/api/slug"
  const selfUrlPath = (process.env.SELF_URL || '').replace('https://', '').replace('http://', '')
  const selfKey = `${selfUrlPath}/${id}`.replaceAll('.', '@')
  let url = await get(fullUrlOf, selfKey)
  let lookupKey = selfKey

  // Fallback: try custom domain lookup (e.g., goog.link/abc → goog@link/abc)
  if (!url) {
    const customKey = `${req.hostname}/${id}`.replaceAll('.', '@')
    url = await get(fullUrlOf, customKey)
    lookupKey = customKey
  }

  if (!url) return res.status(404).send(html('Link not found'))
  if (!(await isValid(lookupKey))) return res.status(404).send(html(translation('t.linkExpired')))

  res.redirect(url)
  increment(clicksOf, 'total')
  increment(clicksOf, today())
  increment(clicksOf, week())
  increment(clicksOf, month())
  increment(clicksOf, year())
  increment(clicksOn, lookupKey)
})

