// TWILIO BULK CALL CAMPAIGN — TwiML Webhooks
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━


// ── Audio Proxy for Twilio — serves audio with correct Content-Type ──
// CloudFront/EdenAI returns binary/octet-stream which Twilio can't play.
// This proxy streams the audio back with audio/mpeg content type.
// Also handles local files served from /assets/user-audio/ to avoid self-referential requests.
app.get('/twilio/audio-proxy', async (req, res) => {
  const { url } = req.query
  if (!url) return res.status(400).send('Missing url parameter')
  try {
    // ── Validate URL protocol ──
    // Only allow http/https protocols; reject garbled/corrupted URLs
    if (!/^https?:\/\//i.test(url)) {
      log(`[AudioProxy] Rejected invalid URL protocol: ${url.substring(0, 80)}...`)
      return res.status(400).send('Invalid audio URL — only http/https allowed')
    }

    const selfUrl = process.env.SELF_URL_PROD || process.env.SELF_URL || ''

    // Detect local file — avoid HTTP self-request
    const isLocal = url.includes('/assets/user-audio/') || (selfUrl && url.startsWith(selfUrl + '/assets/'))
    if (isLocal) {
      // Extract filename from URL path
      const urlPath = new URL(url).pathname
      const localPath = require('path').join(__dirname, urlPath)
      if (require('fs').existsSync(localPath)) {
        res.set('Content-Type', 'audio/mpeg')
        res.set('Cache-Control', 'public, max-age=3600')
        return require('fs').createReadStream(localPath).pipe(res)
      }
      // ── File missing from disk — try restoring from MongoDB ──
      try {
        const filename = require('path').basename(localPath)
        const stored = await db.collection('ivrAudioStore').findOne({ filename })
        if (stored && stored.buffer) {
          const dir = require('path').dirname(localPath)
          if (!require('fs').existsSync(dir)) require('fs').mkdirSync(dir, { recursive: true })
          require('fs').writeFileSync(localPath, Buffer.from(stored.buffer, 'base64'))
          log(`[AudioProxy] Restored ${filename} from MongoDB to disk`)
          res.set('Content-Type', 'audio/mpeg')
          res.set('Cache-Control', 'public, max-age=3600')
          return require('fs').createReadStream(localPath).pipe(res)
        }
      } catch (restoreErr) {
        log(`[AudioProxy] MongoDB restore failed: ${restoreErr.message}`)
      }
      // File truly doesn't exist — fall through to external fetch (will likely 404)
    }

    // External URL — proxy with correct Content-Type
    const axios = require('axios')
    const audioRes = await axios.get(url, {
      responseType: 'stream',
      timeout: 15000,
      headers: { 'Accept': 'audio/mpeg, audio/*' },
    })
    res.set('Content-Type', 'audio/mpeg')
    res.set('Cache-Control', 'public, max-age=3600')
    audioRes.data.pipe(res)
  } catch (e) {
    log(`[AudioProxy] Error fetching audio: ${e.message} | url=${(url || '').substring(0, 120)}`)
    res.status(502).send('Audio fetch failed')
  }
})

// ── Twilio Regulatory Bundle Status Callback ──
// Registered by registerBundleStatusRoute() inside loadData() after
// pendingBundles collection is bound. Until then, Twilio gets a 404 and retries.
function registerBundleStatusRoute() {
app.post('/twilio/bundle-status', async (req, res) => {
  try {
    const { bundleSid, bundleStatus } = req.body || {}
    log(`[BundleWebhook] Received status update: bundle=${bundleSid}, status=${bundleStatus}`)
    if (bundleSid && bundleStatus && pendingBundles?.updateOne) {
      await pendingBundles.updateOne(
        { bundleSid },
        { $set: { status: bundleStatus, updatedAt: new Date() } }
      )
      // Trigger immediate check for this bundle
      setTimeout(() => checkPendingBundles(), 5000)
    }
    res.status(200).json({ received: true })
  } catch (e) {
    log(`[BundleWebhook] Error: ${e.message}`)
    res.status(200).json({ received: true })
  }
})
  log('[BundleWebhook] Twilio bundle-status route registered')
} // end registerBundleStatusRoute

// ── Bulk-call Twilio routes (/twilio/bulk-ivr, /twilio/bulk-ivr-gather, /twilio/bulk-status)
//    are now registered by bulkCallService.registerRoutes(app) inside initBulkCallService(),
