// Creates a bridge context in memory, then uses Twilio API to call through the SIP domain.
// This simulates exactly what happens when Telnyx transfers a call to the Twilio SIP domain.
app.post('/test/sip-bridge', async (req, res) => {
  try {
    const { destination, chatId } = req.body || {}
    if (!destination || !chatId) return res.status(400).json({ error: 'destination and chatId required' })

    const userData = await db.collection('phoneNumbersOf').findOne({ _id: chatId })
    const num = (userData?.val?.numbers || []).find(n => n.provider === 'twilio' && n.status === 'active')
    if (!num) return res.status(404).json({ error: 'No active Twilio number found for chatId' })

    const subSid = num.twilioSubAccountSid || userData?.val?.twilioSubAccountSid
    const subToken = num.twilioSubAccountToken || userData?.val?.twilioSubAccountToken
    if (!subSid || !subToken) return res.status(400).json({ error: 'No sub-account credentials' })

    const bridgeId = 'bridge_test_' + nanoid()
    pendingBridges[bridgeId] = {
      twilioNumber: num.phoneNumber,
      destination,
      chatId,
      num,
      selfUrl: SELF_URL,
      createdAt: Date.now(),
    }
    setTimeout(() => { delete pendingBridges[bridgeId] }, 60000)

    log(`[Test] SIP bridge test: ${num.phoneNumber} → ${destination} (bridge=${bridgeId})`)

    // Now call through the Twilio SIP domain — exactly like Telnyx transfer would
    const twilioClient = require('twilio')(subSid, subToken)
    const sipDomain = twilioResources?.sipDomainName
    if (!sipDomain) return res.status(500).json({ error: 'No Twilio SIP domain available' })

    const sipUri = `sip:${bridgeId}@${sipDomain}`
    log(`[Test] Calling SIP URI: ${sipUri}`)

    const call = await twilioClient.calls.create({
      to: sipUri,
      from: num.phoneNumber,
      url: `${SELF_URL}/twilio/sip-voice`,
      statusCallback: `${SELF_URL}/twilio/voice-dial-status?chatId=${chatId}&from=${encodeURIComponent(destination)}&to=${encodeURIComponent(num.phoneNumber)}&type=sip_bridge_test`,
      statusCallbackEvent: ['completed'],
    })

    log(`[Test] SIP bridge call created: ${call.sid}`)
    res.json({ success: true, callSid: call.sid, bridgeId, sipUri, from: num.phoneNumber, to: destination })
  } catch (e) {
    log(`[Test] SIP bridge error: ${e.message}`)
    res.status(500).json({ error: e.message })
  }
})


// ── Remaining Twilio routes (verify-callerid / sip-voice / voice-status / sms-webhook)
//    are deferred-registered by registerExtraTwilioRoutes() in loadData(),
//    AFTER initVoiceService() completes. They depend on voice-service exports
//    (pendingBridges, isSmsLimitReached) which are bound by initVoiceService. ──
function registerExtraTwilioRoutes() {
// ── Verification endpoint: Responds with DTMF digits for Twilio Caller ID verification ──
app.post('/twilio/verify-callerid', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  const code = req.query.code || '000000'
  log(`[Twilio] Caller ID verification: Playing code ${code}`)
  const response = new VoiceResponse()
  response.pause({ length: 3 })
  response.play({ digits: code.split('').join('w') }) // Play each digit with small pauses
  response.pause({ length: 5 })
  response.play({ digits: code.split('').join('w') }) // Repeat for safety
  res.type('text/xml').send(response.toString())
})


app.post('/twilio/sip-voice', async (req, res) => {
  const VoiceResponse = require('twilio').twiml.VoiceResponse
  try {
    const { To, From, CallSid } = req.body || {}
    log(`📞 [Twilio] SIP voice: ${From} → ${To} (${CallSid})`)

    const response = new VoiceResponse()

    // Parse SIP URI to get destination/bridge ID
    // SIP format: sip:+1234567890@domain or sip:bridge_xyz@domain
    let destinationOrBridgeId = To
    if (To?.startsWith('sip:')) {
      destinationOrBridgeId = To.replace('sip:', '').split('@')[0]
    }

    // ── FIX: Also check query param for bridgeId ──
    // When _attemptTwilioDirectCall creates calls.create({to: destination, url: /sip-voice?bridgeId=xxx}),
    // the To field is the destination phone number, not the bridge ID.
    // The bridgeId is passed in the URL query param instead.
    if (!destinationOrBridgeId?.startsWith('bridge_') && req.query?.bridgeId) {
      destinationOrBridgeId = req.query.bridgeId
      log(`[Twilio] SIP voice: Using bridgeId from query param: ${destinationOrBridgeId}`)
    }

    // ━━━ BRIDGE CALL: Routed from Telnyx SIP for Twilio number outbound ━━━
    if (destinationOrBridgeId?.startsWith('bridge_')) {
      const bridgeId = destinationOrBridgeId
      const bridge = pendingBridges[bridgeId]

      if (!bridge) {
        log(`[Twilio] Bridge ${bridgeId} not found or expired`)
        response.say('Call routing session expired. Please try again.')
        response.hangup()
        return res.type('text/xml').send(response.toString())
      }

      log(`[Twilio] Bridge found: ${bridge.twilioNumber} → ${bridge.destination}`)

      // Clean up the pending bridge
      delete pendingBridges[bridgeId]

      // Place the outbound PSTN call through Twilio with proper caller ID
      // ── Real-time billing: compute timeLimit for bridge (wallet-only) ──
      const isUSCA_bridge = (bridge.destination || '').replace(/[^+\d]/g, '').startsWith('+1')
      const bridgeRate = isUSCA_bridge ? parseFloat(process.env.OVERAGE_RATE_MIN || '0.04') : parseFloat(process.env.CALL_FORWARDING_RATE_MIN || '0.50')
      let bridgeTimeLimit = 14400
      try {
        const { usdBal: bridgeWallet } = await getBalance(walletOf, bridge.chatId)
        bridgeTimeLimit = computeDialTimeLimit('outbound', { walletBalance: bridgeWallet, ratePerMinute: bridgeRate })
        log(`[Twilio] Bridge dial timeLimit: ${bridgeTimeLimit}s (wallet=$${bridgeWallet.toFixed(2)}, rate=$${bridgeRate}/min)`)
      } catch (e) { log(`[Twilio] Bridge timeLimit calc error: ${e.message}`) }

      const recordingEnabled = bridge.num?.features?.recording === true
      const dialOpts = {
        callerId: bridge.twilioNumber,
        timeout: 30,
        timeLimit: bridgeTimeLimit,
        action: `${bridge.selfUrl}/twilio/voice-dial-status?chatId=${bridge.chatId}&from=${encodeURIComponent(bridge.destination)}&to=${encodeURIComponent(bridge.twilioNumber)}&type=sip_bridge`,
      }
      if (recordingEnabled) {
        dialOpts.record = 'record-from-answer-dual'
        dialOpts.recordingStatusCallback = `${bridge.selfUrl}/twilio/recording-status`
      }
      const dial = response.dial(dialOpts)
      dial.number(bridge.destination)

      log(`[Twilio] Bridge call: ${bridge.twilioNumber} → ${bridge.destination} (callerId=${bridge.twilioNumber})`)
      return res.type('text/xml').send(response.toString())
    }

    // ━━━ REGULAR SIP OUTBOUND: Direct Twilio SIP call (existing flow) ━━━
    let destinationNumber = destinationOrBridgeId

    // Find the SIP user by their From SIP URI
    let sipUsername = From
    if (From?.startsWith('sip:')) {
      sipUsername = From.replace('sip:', '').split('@')[0]
    }

    // Look up user by SIP username
    const allUsers = await db.collection('phoneNumbersOf').find({}).toArray()
    let owner = null, num = null
    for (const user of allUsers) {
      const numbers = user.val?.numbers || []
      const match = numbers.find(n => n.sipUsername === sipUsername && n.provider === 'twilio' && n.status === 'active')
      if (match) { owner = user._id; num = match; break }
    }

    if (!num || !owner) {
      response.say('SIP credentials not recognized.')
      response.hangup()
      return res.type('text/xml').send(response.toString())
    }

    // Outbound calls charge directly from wallet (plan minutes are for inbound only)
    const isUSCA = (destinationNumber || '').replace(/[^+\d]/g, '').startsWith('+1')
    const RATE = isUSCA ? parseFloat(process.env.OVERAGE_RATE_MIN || '0.04') : parseFloat(process.env.CALL_FORWARDING_RATE_MIN || '0.50')
    const chatId = owner

    const { usdBal } = await getBalance(walletOf, chatId)
    if (usdBal < RATE) {
      response.say('Your wallet balance is insufficient for outbound calls. Please top up.')
      response.hangup()
      bot?.sendMessage(chatId, `🚫 <b>SIP Call Blocked — Wallet Empty</b>\n📞 ${phoneConfig.formatPhone(num.phoneNumber)} → ${phoneConfig.formatPhone(destinationNumber)}\n\nWallet: $${usdBal.toFixed(2)} (need $${RATE}/min ${isUSCA ? 'US/CA' : 'Intl'})\nOutbound calls are billed from wallet.\n\nTop up via 👛 Wallet.`, { parse_mode: 'HTML' }).catch(() => {})
      return res.type('text/xml').send(response.toString())
    }
    log(`[Twilio] SIP outbound: wallet $${usdBal.toFixed(2)} — allowing at $${RATE}/min`)

    // Place outbound call
    // ── Real-time billing: compute timeLimit for SIP outbound (wallet-only) ──
    const outboundTimeLimit = computeDialTimeLimit('outbound', { walletBalance: usdBal, ratePerMinute: RATE })
    log(`[Twilio] SIP outbound timeLimit: ${outboundTimeLimit}s (wallet=$${usdBal.toFixed(2)}, rate=$${RATE}/min)`)
    const recordingEnabled = num.features?.recording === true
    const dialOpts = { callerId: num.phoneNumber, timeout: 30, timeLimit: outboundTimeLimit, action: `${SELF_URL}/twilio/voice-dial-status?chatId=${chatId}&from=${encodeURIComponent(destinationNumber)}&to=${encodeURIComponent(num.phoneNumber)}&type=sip_outbound` }
    if (recordingEnabled) {
      dialOpts.record = 'record-from-answer-dual'
      dialOpts.recordingStatusCallback = `${SELF_URL}/twilio/recording-status`
    }
    const dial = response.dial(dialOpts)
    dial.number(destinationNumber)

    const estMinutes = Math.floor(usdBal / RATE)
    bot?.sendMessage(chatId, `📞 <b>SIP Outbound Call</b>\nFrom: ${num.phoneNumber}\nTo: ${destinationNumber}\nRate: $${RATE}/min (~${estMinutes} min available)`, { parse_mode: 'HTML' }).catch(() => {})

    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[Twilio] SIP voice error:', error.message)
    const VR = new VoiceResponse()
    VR.say('An error occurred.')
    VR.hangup()
    res.type('text/xml').send(VR.toString())
  }
})

// Twilio Voice Status Callback (call duration billing + no-answer safety net)
app.post('/twilio/voice-status', async (req, res) => {
  const voiceService = require('./voice-service.js')
  try {
    const { CallSid, CallDuration, CallStatus, To, From } = req.body || {}
    const duration = parseInt(CallDuration || '0')

    log(`[Twilio] Voice status: ${CallSid} — ${CallStatus} (${duration}s)`)

    if (CallStatus === 'completed' && duration > 0) {
      // ── Dedup: Skip if this call was already billed in sip-ring-result or voice-dial-status ──
      if (CallSid && _twilioBilledCallSids.has(CallSid)) {
        log(`[Twilio] Voice status: ${CallSid} already billed in action handler — skipping`)
        _twilioBilledCallSids.delete(CallSid)
        return res.sendStatus(200)
      }

      const minutes = Math.ceil(duration / 60)

      // Find owner and bill using unified billing (plan minutes first, then wallet overage)
      const allUsers = await db.collection('phoneNumbersOf').find({}).toArray()
      for (const user of allUsers) {
        const numbers = user.val?.numbers || []
        const match = numbers.find(n => (n.phoneNumber === To || n.phoneNumber === From) && n.provider === 'twilio')
        if (match) {
          const chatId = String(user._id) // Ensure string for consistency
          const destination = match.phoneNumber === To ? From : To
          // Fix B: Detect direction — if our number is From, it's outbound (SIP bridge)
          const isOutboundCall = match.phoneNumber === From
          const callType = isOutboundCall ? 'Twilio_SIP_Outbound' : 'Twilio_Inbound'
          try {
            const billingInfo = await voiceService.billCallMinutesUnified(chatId, match.phoneNumber, minutes, destination, callType)
            const remaining = billingInfo.limit > 0 ? Math.max(0, billingInfo.limit - billingInfo.used) : null
            const planLine = remaining !== null
              ? `📊 ${minutes} min · <b>${remaining}/${billingInfo.limit}</b> min remaining`
              : `📊 ${minutes} min used`
            const overageLine = billingInfo.overageCharge > 0
              ? `\n💰 Overage: $${billingInfo.overageCharge.toFixed(2)} from wallet`
              : ''
            const outboundLine = billingInfo.rate > 0 && isOutboundCall
              ? `\n💰 Charged: $${(minutes * billingInfo.rate).toFixed(2)} (${minutes} min × $${billingInfo.rate})`
              : ''
            bot?.sendMessage(chatId, `📞 <b>Call Ended</b>\n${planLine}${overageLine}${outboundLine}`, { parse_mode: 'HTML' }).catch(() => {})
          } catch (e) {
            log(`[Twilio] Unified billing error: ${e.message}`)
          }
          break
        }
      }
    } else if (CallStatus === 'no-answer' || CallStatus === 'busy' || CallStatus === 'failed' || CallStatus === 'canceled') {
      // ALL outbound calls billed minimum 1 minute — answered or not
      const allUsers = await db.collection('phoneNumbersOf').find({}).toArray()
      for (const user of allUsers) {
        const numbers = user.val?.numbers || []
        const match = numbers.find(n => (n.phoneNumber === To || n.phoneNumber === From) && n.provider === 'twilio')
        if (match) {
          const chatId = String(user._id) // Ensure string for consistency
          const isOutboundCall = match.phoneNumber === From
          const destination = match.phoneNumber === To ? From : To
          const reason = CallStatus === 'no-answer' ? 'No answer'
            : CallStatus === 'busy' ? 'Line busy'
            : CallStatus === 'failed' ? 'Call failed'
            : 'Cancelled'

          if (isOutboundCall) {
            // Charge 1-minute minimum for ALL outbound unanswered calls
            try {
              const billingInfo = await voiceService.billCallMinutesUnified(chatId, match.phoneNumber, 1, destination, 'Twilio_SIP_Outbound')
              const chargeLine = billingInfo.rate > 0
                ? `\n💰 Charged: $${billingInfo.rate.toFixed(2)} (1 min minimum)`
                : ''
              bot?.sendMessage(chatId, `❌ <b>Call Not Connected</b>\n📞 ${destination} — ${reason}${chargeLine}`, { parse_mode: 'HTML' }).catch(() => {})
            } catch (e) {
              log(`[Twilio] Outbound unanswered billing error: ${e.message}`)
              bot?.sendMessage(chatId, `❌ <b>Call Not Connected</b>\n📞 ${destination} — ${reason}`, { parse_mode: 'HTML' }).catch(() => {})
            }
          } else {
            // Inbound missed call — no charge, just notify
            bot?.sendMessage(chatId, `❌ <b>Call Not Connected</b>\n📞 ${destination} — ${reason}`, { parse_mode: 'HTML' }).catch(() => {})
          }
          log(`[Twilio] Call not completed: ${CallSid} — ${reason} (${From} → ${To})${isOutboundCall ? ' [OUTBOUND — 1-min billed]' : ''}`)
          break
        }
      }
    }
    res.sendStatus(200)
  } catch (error) {
    log('[Twilio] Voice status error:', error.message)
    res.sendStatus(200)
  }
})

// Twilio SMS Webhook
app.post('/twilio/sms-webhook', async (req, res) => {
  const MessagingResponse = require('twilio').twiml.MessagingResponse
  try {
    const { To, From, Body } = req.body || {}
    log(`💬 [Twilio] SMS: ${From} → ${To}: ${(Body || '').substring(0, 50)}`)

    // Find owner
    const allUsers = await db.collection('phoneNumbersOf').find({}).toArray()
    for (const user of allUsers) {
      const numbers = user.val?.numbers || []
      const match = numbers.find(n => n.phoneNumber === To && n.provider === 'twilio' && n.status === 'active')
      if (match) {
        const chatId = String(user._id) // Ensure string for consistency
        const OVERAGE_SMS_RATE = parseFloat(process.env.OVERAGE_RATE_SMS || '0.02')

        // ── CHECK: SMS limit reached? → Try overage billing ──
        if (isSmsLimitReached(match)) {
          let overageAllowed = false
          try {
            const { usdBal } = await getBalance(walletOf, chatId)
            if (usdBal >= OVERAGE_SMS_RATE) {
              // Charge overage from wallet
              await atomicIncrement(walletOf, chatId, 'usdOut', OVERAGE_SMS_RATE)
              overageAllowed = true
              const ref = nanoid ? nanoid() : `ovsms_twilio_${Date.now()}`
              await set(payments, ref, `Overage,CloudPhoneSMS,$${OVERAGE_SMS_RATE},${chatId},${To},${new Date()}`)
              log(`[Twilio SMS] Overage charged: $${OVERAGE_SMS_RATE} for inbound SMS on ${To}`)
              bot?.sendMessage(chatId, `💰 <b>SMS Overage</b>: $${OVERAGE_SMS_RATE} charged from wallet (plan SMS exhausted).`, { parse_mode: 'HTML' }).catch(() => {})
            }
          } catch (e) { log(`[Twilio SMS] Overage check error: ${e.message}`) }

          if (!overageAllowed) {
            log(`[Twilio SMS] SMS limit reached for ${To} (${match.smsUsed || 0} used), no wallet — dropping`)
            bot?.sendMessage(chatId, `🚫 <b>Inbound SMS Dropped — No Credits</b>\n\n📞 ${phoneConfig.formatPhone(To)}\nFrom: ${phoneConfig.formatPhone(From)}\n\nPlan SMS exhausted and wallet insufficient for overage ($${OVERAGE_SMS_RATE}/SMS).\nTop up via 👛 Wallet or upgrade plan.`, { parse_mode: 'HTML' }).catch(() => {})
            const response = new MessagingResponse()
            return res.type('text/xml').send(response.toString())
          }
        }

        // Forward to Telegram
        const fwd = match.features?.smsForwarding
        if (fwd?.toTelegram !== false) {
          bot?.sendMessage(chatId, `💬 <b>SMS Received</b>\nFrom: ${From}\nTo: ${To}\n\n${Body || '(empty)'}`, { parse_mode: 'HTML' }).catch(() => {})
        }
        // Increment SMS usage — atomic $inc to prevent race conditions overwriting IVR/forwarding settings
        match.smsUsed = (match.smsUsed || 0) + 1
        await db.collection('phoneNumbersOf').updateOne(
          { _id: chatId, 'val.numbers.phoneNumber': To },
          { $inc: { 'val.numbers.$.smsUsed': 1 } }
        )
        break
      }
    }

    const response = new MessagingResponse()
    res.type('text/xml').send(response.toString())
  } catch (error) {
    log('[Twilio] SMS webhook error:', error.message)
    res.sendStatus(200)
  }
})

  log('[VoiceService] Extra Twilio routes registered (verify-callerid, sip-voice, voice-status, sms-webhook)')
} // end registerExtraTwilioRoutes

// ── Referral Tracking Redirect Route ──
// Handles /r/:referrerCode and tracks the referral in MongoDB before redirecting to Telegram
app.get('/r/:referrerCode', async (req, res) => {
  try {
    const { referrerCode } = req.params
    const botUsername = process.env.BOT_USERNAME || 'Nomadlybot'
    
    // Store the referral click in a temporary tracking collection
    // We can't create the referral relationship yet because we don't know the referee's chatId
    // But we can track that someone clicked this link
    const clickId = `click_${Date.now()}_${Math.random().toString(36).substring(7)}`
    const referrerChatId = parseInt(referrerCode)
    
    if (isNaN(referrerChatId)) {
      log(`[Referral] Invalid referrer code: ${referrerCode}`)
      return res.redirect(`https://t.me/${botUsername}`)
    }
    
    // Store the click with a 24-hour expiry (only if DB is ready)
    if (isDbHealthy() && typeof db !== 'undefined' && db && db.collection) {
      try {
        const referralClicks = db.collection('referralClicks')
        await referralClicks.insertOne({
          _id: clickId,
          referrerChatId,
          referrerCode,
          clickedAt: new Date(),
          expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000), // 24 hours
          converted: false
        })
        log(`[Referral] Tracked click: ${clickId} for referrer ${referrerChatId}`)
      } catch (e) {
        log(`[Referral] Error tracking click: ${e.message}`)
      }
    } else {
      log(`[Referral] DB not ready, skipping click tracking for ${referrerChatId}`)
    }
    
    // Redirect to Telegram bot with the deep link parameter
    // This will work for NEW users, and existing users will just open the bot
    res.redirect(`https://t.me/${botUsername}?start=ref_${referrerCode}`)
  } catch (error) {
    log(`[Referral] Redirect error: ${error.message}`)
    const botUsername = process.env.BOT_USERNAME || 'Nomadlybot'
    res.redirect(`https://t.me/${botUsername}`)
  }
})

